/* techniques q05 (145 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]=window.__LIBQ["pham-nhan-tu-tien"]["q05"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]["techniques"]={"updatedAt":"2026-07-14","count":145,"techniques":[{"id":"thai-bach-kiem-quyet","name":"Thái Bạch Kiếm Quyết","cn":"太白剑诀","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"Cổ Kiếm Môn","soHuu":["Cổ Kiếm Môn"],"blurb":"Tuyệt học trấn phái của Cổ Kiếm Môn, tại Khê Quốc bài danh đỉnh đỉnh, yêu cầu linh căn cực cao, đệ tử tu vi đại thành thì cùng cấp ít đối thủ.","detail":"Tuyệt học ngự kiếm thuật trấn phái Cổ Kiếm Môn. Tại Khê Quốc nổi danh hàng đầu. Yêu cầu tư chất linh căn cực cao mới có thể tu luyện. Đệ tử Cổ Kiếm Môn một khi tu vi đại thành, nhờ tính công kích siêu cường mà các tu sĩ cùng cấp thường không phải là đối thủ.","congNang":["Ngự kiếm thuật công kích siêu cường, cùng cấp ít đối thủ"],"tabs":{"tienTrinh":[{"chuong":"@c0596","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Hàn Lập nhắc khi cân nhắc ba môn phái","text":"Hàn Lập phân tích ba phái tại Vân Mộng Sơn, nhận định Thái Bạch Kiếm Quyết là tuyệt học trấn phái Cổ Kiếm Môn, bài danh đỉnh đỉnh tại Khê Quốc nhưng yêu cầu linh căn quá cao.","anchor":"tuyệt học trấn phái “Thái Bạch Kiếm Quyết” tại Khê Quốc càng bài danh đỉnh đỉnh"}]},"nguon":["@c0596"]},{"id":"van-tam-thuat","name":"Vấn Tâm Thuật","cn":"問心術","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lạc Vân Tông","soHuu":["Miêu sư huynh"],"blurb":"Vấn Tâm Thuật là thuật pháp phán đoán lời nói thật hay giả, được Lạc Vân Tông sử dụng trong quy trình kiểm tra tân đệ tử nhập môn, cần phối hợp cùng Vấn Tâm Phù để thi triển.","detail":"Vấn Tâm Thuật là phương pháp kiểm tra tâm ý, được nhấn mạnh không phải Mê hồn thuật. Khi thi triển, người sử dụng áp Vấn Tâm Phù lên vai phải đối tượng rồi đặt ra mười câu hỏi; nếu đối tượng trả lời sai từ ba câu trở lên sẽ bị loại. Độ chính xác của thuật này đạt khoảng 80–90%. Tại Lạc Vân Tông, Miêu sư huynh đã thi triển Vấn Tâm Thuật để kiểm tra bảy tán tu mới nhập môn, cả bảy đều vượt qua @c0598. Hàn Lập tự tin rằng thuật này không thể phán đoán được thật lòng của hắn.","congNang":["Phán đoán lời nói của đối tượng là thật hay giả, độ chính xác khoảng 80–90% @c0598"],"dacDiem":"Không phải Mê hồn thuật, chỉ có khả năng phán đoán thật-giả; cần phối hợp Vấn Tâm Phù áp lên vai phải đối tượng mới thi triển được; quy trình hỏi mười câu, sai ba câu thì bị loại","nguoiTu":[{"ten":"Miêu sư huynh","tuChuong":"@c0598","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0598","loai":"thi triển","importance":"major","giaiDoan":"Kiểm tra tân đệ tử Lạc Vân Tông","text":"Miêu sư huynh thi triển Vấn Tâm Thuật kiểm tra bảy tán tu mới nhập môn, hỏi mười câu mỗi người. Cả bảy đều qua, bao gồm Hàn Lập người tự tin thuật này không thể phát hiện thật lòng hắn.","anchor":"Mặc dù đây chỉ là thuật phán đoán, không thể nói là hoàn toàn chính xác, nhưng cũng đúng khoảng tám chín phần mười"}]},"nguon":["@c0598"]},{"id":"kim-luyen-quyet","name":"Kim Luyện quyết","cn":"金炼诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Kim thuộc tính","soHuu":["Lý sư bá"],"blurb":"Công pháp kim thuộc tính do Lý sư bá của Hỏa Vân Phong tu luyện, nổi danh ở Khê Quốc.","detail":"Công pháp kim thuộc tính, được trung niên đại diện Hỏa Vân Phong viện dẫn khi tranh đệ tử có Đoán kim chi thể, cho thấy Hỏa Vân Phong cũng có khả năng dạy công pháp kim thuộc tính dù chủ yếu tu hỏa thuộc tính.","thuocTinh":"Kim","nguonGoc":"Hỏa Vân Phong, Lạc Vân Tông","nguoiTu":[{"ten":"Lý sư bá","tuChuong":"@c0599","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0599","loai":"nhắc tới","importance":"normal","giaiDoan":"Được viện dẫn trong tranh chấp đệ tử","text":"Trung niên đại diện Hỏa Vân Phong nhắc đến Kim Luyện quyết của Lý sư bá nổi danh ở Khê Quốc để tranh đệ tử Đoán kim chi thể.","anchor":"Hỏa Vân Phong chúng ta cũng có Lý sư bá với Kim Luyện quyết ở Khê Quốc này cũng rất là nổi danh"}]},"nguon":["@c0599"]},{"id":"huyen-bang-quyet","name":"Huyền Băng Quyết","cn":"玄冰诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Thiên Tuyền Phong","soHuu":["Hàn Lập"],"blurb":"Công pháp thủy thuộc tính do Mộ Phái Linh giao cho Hàn Lập qua ngọc giản khi hắn nhận trông coi dược viên.","detail":"Công pháp tu luyện thủy thuộc tính, được ghi trên ngọc giản và lưu lại cho Hàn Lập bởi Mộ Phái Linh (Trúc Cơ trung kỳ, ngũ sư tỷ Thiên Tuyền Phong) khi nàng giao dược viên cho hắn quản lý. Hàn Lập nhận công pháp này dưới danh nghĩa ngoại môn đệ tử mới của Thiên Tuyền Phong.","nguon":["@c0600"]},{"id":"tat-phong-cuu-bien","name":"Tật Phong Cửu Biến","cn":"疾風九變","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Yêu tộc","soHuu":[],"blurb":"Tật Phong Cửu Biến là công pháp yêu tộc được ghi chép bằng cổ văn yêu tộc trên miếng sách da thú, chuyên dành cho yêu cầm tu luyện, bao gồm bộ pháp quyết, thân pháp và hai mật thuật kèm theo là Nặc Phong thuật cùng Huyết Ảnh Độn. Nhân loại không thể tu luyện phần pháp quyết và thân pháp, chỉ có thể sử dụng hai mật thuật đi kèm.","detail":"Tật Phong Cửu Biến được Hàn Lập phát hiện sau khi học cổ văn yêu tộc và dịch thành công nội dung ghi trên một miếng sách da thú (@c0602). Công pháp này vốn là bộ pháp quyết và thân pháp hoàn toàn dành riêng cho yêu cầm; nhân loại nếu cưỡng ép tu luyện phần pháp quyết và thân pháp sẽ bạo thể mà chết. Tuy nhiên, hai mật thuật kèm theo — Nặc Phong thuật và Huyết Ảnh Độn — có thể được nhân loại tham khảo hoặc tu luyện, là phần giá trị thực tế mà tu sĩ nhân tộc có thể khai thác từ bộ công pháp này.","thuocTinh":"Phong","nguonGoc":"Cổ văn yêu tộc ghi trên miếng sách da thú","dacDiem":"Công pháp yêu tộc ghi bằng cổ văn trên sách da thú, phần pháp quyết và thân pháp chỉ yêu cầm mới tu luyện được, nhân loại cưỡng luyện sẽ bạo thể mà chết; chỉ hai mật thuật đi kèm là nhân loại có thể sử dụng.","congNang":["Bộ pháp quyết và thân pháp chuyên dụng cho yêu cầm tu luyện (@c0602)","Kèm mật thuật Nặc Phong thuật, nhân loại có thể tu luyện (@c0602)","Kèm mật thuật Huyết Ảnh Độn, nhân loại có thể tu luyện (@c0602)"],"tabs":{"tienTrinh":[{"chuong":"@c0602","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập giải mã sách da thú","text":"Hàn Lập học cổ văn yêu tộc, dịch miếng sách da thú phát hiện công pháp Tật Phong Cửu Biến gồm pháp quyết, thân pháp và hai mật thuật.","anchor":"công pháp yêu tộc gọi là Tật Phong Cửu Biến"}]},"nguon":["@c0602"]},{"id":"huyet-anh-don","name":"Huyết Ảnh Độn","cn":"血影遁","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Yêu tộc","soHuu":["Hàn Lập"],"blurb":"Huyết Ảnh Độn là mật thuật thứ hai trong bộ công pháp yêu tộc Tật Phong Cửu Biến, cho phép mượn tinh huyết hóa huyết ảnh bắn ra ngoài trăm dặm trong nháy mắt, đạt tốc độ vượt xa lôi độn. Hàn Lập phát hiện thuật này khi giải mã sách da thú và nhận ra Phong Lôi Sí có thể đáp ứng điều kiện đôi cánh bắt buộc, song sau nửa năm kiêm tu vẫn chưa dám thực hành vì ba rủi ro chí mạng của thuật.","detail":"Huyết Ảnh Độn là mật thuật độn hành xếp thứ hai trong Tật Phong Cửu Biến — một bộ công pháp vốn thuộc yêu tộc. Thuật này vận dụng tinh huyết của người thi triển làm nhiên liệu, hóa toàn thân thành huyết ảnh lao đi tức thời, đạt tốc độ vượt xa cả lôi độn thuật. Tuy nhiên, thuật mang ba đặc điểm nguy hiểm khiến nó gần như liều mạng: thứ nhất, không thể khống chế khoảng cách — một khi kích phát sẽ lao thẳng ra ngoài trăm dặm không dừng được; thứ hai, tiêu hao tinh huyết cực lớn, nếu lượng máu không đủ thì da thịt nổ tung hóa huyết vụ mà chết; thứ ba, bắt buộc phải có đôi cánh để duy trì thăng bằng trong lúc di chuyển, nếu không có cánh thì hoặc đầu đập xuống đất, hoặc quay đảo tại chỗ. Hàn Lập khi giải mã sách da thú đã phát hiện thuật này và nhận ra thần thông Phong Lôi Sí của mình vừa đúng ","nguonGoc":"Mật thuật thứ hai trong Tật Phong Cửu Biến (công pháp yêu tộc)","dacDiem":"Ba rủi ro chí mạng: không khống chế được khoảng cách khi thi triển; tiêu hao tinh huyết cực lớn, máu không đủ thì da thịt nổ tung hóa huyết vụ; bắt buộc phải có đôi cánh duy trì thăng bằng, không có cánh sẽ đầu đập đất hoặc quay đảo tại chỗ. Vốn là mật thuật yêu tộc, cần thân thể có cánh mới đủ điều","uyLuc":"Tốc độ vượt xa lôi độn, tức thời bắn xa trăm dặm, thuộc hàng độn thuật nhanh nhất mà Hàn Lập từng tiếp xúc tại thời điểm phát hiện.","congNang":["Độn thuật tức thời bắn ra ngoài trăm dặm, tốc độ vượt xa lôi độn @c0602","Mượn tinh huyết bản thân hóa huyết ảnh để di chuyển @c0602"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0602","tangDatToi":"Kiêm tu nửa năm, nắm được lý thuyết","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0602","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện và kiêm tu","text":"Hàn Lập giải mã sách da thú phát hiện Huyết Ảnh Độn, nhận ra Phong Lôi Sí đáp ứng điều kiện cánh. Kiêm tu nửa năm, tự cảm nắm được nhưng chưa dám thực hành vì tốn hao máu huyết.","anchor":"Huyết Ảnh Độn này kỳ thật chính là một loại độn thuật quỷ dị mượn lực lượng máu huyết trong nháy mắt chạy trốn ngoài trăm dặm"}]},"nguon":["@c0602"]},{"id":"me-tung-tran","name":"Mê Tung trận","cn":"迷踪阵","aliases":["Ngũ Hành Mê Tung trận"],"loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp dùng trận kỳ bố trí mê trận vây bắt mục tiêu, nhóm Khuê Hoán mượn từ một nội môn sư huynh để bắt dị chủng Tuyết Vân Hồ.","detail":"Nhóm Khuê Hoán mượn được bộ Mê Tung trận pháp kỳ từ một vị nội môn sư huynh, dùng để bố trí trận nhỏ vây bắt dị chủng Tuyết Vân Hồ tại Lục Tung chiểu trạch. Cần đủ người mới vận hành được trận pháp.","congNang":["Bố trí mê trận vây bắt mục tiêu"],"tabs":{"tienTrinh":[{"chuong":"@c0603","loai":"xuất hiện","importance":"normal","giaiDoan":"Được mượn để bắt Tuyết Vân Hồ","text":"Nhóm Khuê Hoán mượn được bộ Mê Tung trận pháp kỳ từ một nội môn sư huynh để bố trí trận vây bắt dị chủng Tuyết Vân Hồ, nhưng thiếu người vận hành nên mời Hàn Lập tham gia.","anchor":"mượn được từ một vị nội môn sư huynh Mê Tung trận pháp kỳ"}]},"nguon":["@c0603"]},{"id":"chuong-nhan-phap","name":"Chướng Nhãn pháp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Tuyết Vân Hồ"],"blurb":"Thuật che mắt, Tuyết Vân Hồ sử dụng để che giấu hình dạng khi độn thổ, đánh lừa thị giác đám tu sĩ.","detail":"Tuyết Vân Hồ dùng để lén lút độn nhập vào đất trốn thoát khi bị nhóm Khuê Hoán bao vây. Che giấu hình dạng khi di chuyển trong lòng đất, khiến bốn đệ tử Ẩn Kiếm Phong không phát hiện được, chỉ có thần thức Hàn Lập mới nhận ra.","thuocTinh":"Không rõ","congNang":["Che giấu hình dạng khi độn thổ, đánh lừa thị giác người quan sát"],"nguoiTu":[{"ten":"Tuyết Vân Hồ","tuChuong":"@c0606","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0606","loai":"thi triển","importance":"normal","giaiDoan":"Tuyết Vân Hồ dùng để trốn thoát","text":"Tuyết Vân Hồ sử dụng Chướng Nhãn pháp che mắt đám tu sĩ Ẩn Kiếm Phong, lén lút độn nhập vào đất trốn thoát sau khi giả chết.","anchor":"yêu hồ kia dùng Chướng Nhãn pháp (thuật che mắt), lén lut độn nhập vào đất"}]},"nguon":["@c0606"]},{"id":"hap-linh-thach","name":"Hấp Linh thạch","cn":"吸灵石","aliases":["Thanh Kim thạch"],"loai":"khac","loaiLabel":"Tài liệu luyện khí","phamCap":"Trân quý, gần thất truyền","hePhai":"","soHuu":[],"blurb":"Loại đá đặc biệt miễn dịch linh lực, tự phục hồi vết thương, là tài liệu luyện khí trân quý cực hiếm ngoài tự nhiên.","detail":"Còn gọi là Thanh Kim thạch, là loại tài liệu luyện khí vô cùng trân quý. Kiếm mang công kích lên bề mặt không để lại vết tích, phi kiếm bắn vào chỉ tạo lỗ nhỏ sâu một tấc rồi tự liền lại. Ngoài dùng lực cực mạnh phá hỏng thì không gì tác động được, kể cả linh lực. Ngoài tự nhiên vô cùng hiếm, gần như không còn mấy người biết đến, gần thất truyền. Thạch thất nơi hắc y thiếu phụ ẩn tu được xây hoàn toàn bằng loại đá này, vách tường thô sơ lồi lõm.","nguon":["@c0607"]},{"id":"u-sat-quyet","name":"U Sát quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Hắc y thiếu phụ"],"blurb":"U Sát quyết là công pháp chủ tu của Hắc y thiếu phụ, nổi bật với tốc độ tu luyện cực nhanh và uy lực vượt trội công pháp thường. Tuy nhiên, công pháp này ẩn chứa khuyết điểm trí mạng: khi đại thành tiến vào Nguyên Anh kỳ, sát tính bùng phát không thể kiểm soát, khiến người tu thay đổi tâm tính hoàn toàn.","detail":"U Sát quyết là một công pháp khác biệt hoàn toàn với các công pháp tu luyện bình thường, sở hữu tốc độ tu luyện cực nhanh cùng uy lực thần kỳ. Đây là công pháp chủ tu của Hắc y thiếu phụ. Tuy nhiên, công pháp ẩn chứa khuyết điểm chí mạng ở ngưỡng đại thành: khi người tu đại thành và tiến vào Nguyên Anh kỳ, sát tính sẽ bùng phát không thể kiểm soát, tâm tính thay đổi hoàn toàn. Hắc y thiếu phụ khi tu đại thành U Sát quyết đã tạo ra mưa gió trong Tu Tiên giới, hậu quả là bị nhiều tu sĩ Nguyên Anh kỳ liên thủ vây đánh trọng thương, phế mất một cánh tay. Chính bà đã tự bạch về hệ quả này (@c0608).","thuocTinh":"","nguonGoc":"","yeuCau":"","uyLuc":"Uy lực thần kỳ, vượt trội công pháp thường; khi đại thành, người tu đủ sức tạo ra mưa gió trong Tu Tiên giới, khiến nhiều tu sĩ Nguyên Anh kỳ phải liên thủ mới có thể vây đánh trọng thương.","dacDiem":"Đại thành sẽ bùng phát sát tính không thể kiểm soát, thay đổi tâm tính hoàn toàn — đây là khuyết điểm chí mạng nằm trong bản chất của công pháp, không thể tránh khỏi khi tiến vào Nguyên Anh kỳ.","congNang":["Tu luyện tốc độ cực nhanh, vượt trội so với công pháp thường","Uy lực thần kỳ, mạnh hơn hẳn các công pháp tu luyện bình thường","Khi đại thành tiến Nguyên Anh kỳ, sát tính bùng phát không thể kiểm soát, tâm tính thay đổi hoàn toàn (@c0608)"],"nguoiTu":[{"ten":"Hắc y thiếu phụ","tuChuong":"@c0608","tangDatToi":"Nguyên Anh trung kỳ (đại thành)","trangThai":"sát tính bùng phát, tự giam"}],"tabs":{"tienTrinh":[{"chuong":"@c0608","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Hé lộ lai lịch và khuyết điểm trí mạng","text":"Hắc y thiếu phụ tự bạch tu U Sát quyết đại thành tiến Nguyên Anh kỳ, sát tính bùng phát không kiểm soát, gây mưa gió tu tiên giới bị vây đánh phế tay.","anchor":"công pháp chủ tu “U Sát quyết” của ta vô cùng khác với công pháp tu luyện bình thường"}]},"capNhatToi":"@c0608","nguon":["@c0608"]},{"id":"huyen-thuat-yeu-ho","name":"Huyễn thuật","cn":"幻术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Yêu hồ","soHuu":["Yêu hồ (Bạch hồ)"],"blurb":"Thần thông của yêu hồ, tạo phân thân ảo ảnh chịu đòn thay thân thật, kết hợp ám kích từ chỗ trống.","detail":"Yêu hồ tạo hình ảnh phân thân giả bị kiếm khí xuyên thủng để lừa đối phương, đồng thời bắn ngân ti ám kích từ vị trí khác. Hàn Lập nhận ra đó là huyễn thuật sau khi kiếm khí xuyên qua mà không có cảm giác trúng đích.","congNang":["Tạo ảo ảnh thân thể chịu đòn thay, kết hợp ám kích bất ngờ"],"nguon":["@c0611"]},{"id":"phan-sac-huong-vu","name":"Phấn sắc hương vụ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Yêu hồ","soHuu":["Yêu hồ (Bạch hồ)"],"blurb":"Yêu hồ phun phấn sắc hương vụ từ miệng, tràn ngập hơn nửa thạch thất, che khuất thân hình.","detail":"Thần thông phun từ miệng một mảng lớn phấn sắc hương vụ che khuất diện rộng. Yêu hồ dùng để che thân khi bị Ngân sắc cự lang uy hiếp.","congNang":["Phun vụ khí diện rộng che thân"],"nguon":["@c0611"]},{"id":"ma-dong","name":"Ma đồng","cn":"魔瞳","loai":"bi-thuat","loaiLabel":"Thiên phú","phamCap":"Không rõ","hePhai":"Tứ đồng linh hồ (Tuyết Vân Hồ đại thành)","soHuu":[],"blurb":"Thiên phú của Tứ đồng linh hồ, có thể vô hình giết chết kẻ địch trong lúc cười nói.","detail":"Khi Tuyết Vân Hồ tu vi đại thành sẽ biến thành Tứ đồng linh hồ, sở hữu thiên phú ma đồng. Bề ngoài giống Tuyết Vân Hồ bình thường nhưng khi thi triển công pháp sẽ bị Ngân Nguyệt lang tộc nhận ra. Bị Ngân Nguyệt lang tộc thiên sinh khắc chế.","thuocTinh":"Linh hồn","nguonGoc":"Thiên phú bẩm sinh của Tứ đồng linh hồ","dacDiem":"Vô hình giết địch trong lúc cười nói, bị Ngân Nguyệt lang tộc khắc chế","congNang":["Vô hình giết chết kẻ địch trong lúc cười nói"],"nguon":["@c0612"]},{"id":"mat-thuat-de-thang-tu-vi","name":"Mật thuật đề thăng tu vi tạm thời","cn":"","loai":"bi-thuat","loaiLabel":"Mật thuật","phamCap":"Không rõ","hePhai":"Ngân Nguyệt lang tộc","soHuu":["Ngân Nguyệt"],"blurb":"Mật thuật của Ngân Nguyệt lang tộc, tạm thời đề thăng tu vi lên thất-bát cấp yêu thú.","detail":"Ngân Nguyệt sử dụng mật thuật này để tạm thời đưa tu vi từ yêu thú cấp thấp lên thất cấp thậm chí bát cấp. Hiệu quả chỉ tạm thời, sau một thời gian tu vi hạ xuống, muốn biến hình người lại phải đợi ít nhất một tháng.","thuocTinh":"Không rõ","nguonGoc":"Mật thuật Ngân Nguyệt lang tộc","dacDiem":"Hiệu quả tạm thời, cần ít nhất 1 tháng hồi phục trước khi dùng lại","congNang":["Tạm thời đề thăng tu vi lên thất-bát cấp yêu thú"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0612","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0612","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Ngân Nguyệt tiết lộ","text":"Ngân Nguyệt cho biết có mật thuật tạm đưa tu vi lên thất-bát cấp yêu thú nhưng sau đó hạ xuống, muốn biến hình người lại cần ít nhất một tháng.","anchor":"có thể tạm thời đưa tu vi đề thăng lên trình độ yêu thú thất cấp thậm chí bát cấp"}]},"nguon":["@c0612"]},{"id":"thon-phe-linh-hon","name":"Thôn phệ linh hồn","cn":"","aliases":["Linh hồn cắn nuốt"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Ngân Nguyệt"],"blurb":"Bí thuật đoạt xá chiếm thân xác khác, đại giá là mất hơn phân nửa tu vi hồn khí bản thân.","detail":"Ngân Nguyệt từng thi triển thuật này để đoạt xá. Hậu quả: tu vi hồn khí sau đoạt xá mất hơn phân nửa.","congNang":["Đoạt xá chiếm thân xác khác"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0613","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0613","loai":"nhắc tới","importance":"normal","giaiDoan":"Ngân Nguyệt nhắc lại hậu quả","text":"Ngân Nguyệt xác nhận đã thi triển linh hồn cắn nuốt để đoạt xá, hậu quả mất hơn phân nửa tu vi hồn khí.","anchor":"sau khi thi triển linh hồn cắn nuốt, tu vi hồn khí bản thân sau khi đoạt xá đã mất hơn phân nửa"}]},"nguon":["@c0613"]},{"id":"thong-minh-linh-te","name":"Thông Minh Linh Tê","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lạc Vân Tông","soHuu":["Tống sư tổ"],"blurb":"Thông Minh Linh Tê là thần thông dò xét tâm thần độc đáo của Tống sư tổ, có uy lực cực mạnh khiến chỉ vài cao thủ Kết Đan Kỳ mới có thể chống lại. Thi triển qua ánh mắt trong suốt, thần thông này khiến đối tượng cảm giác toàn bộ thể xác và tinh thần bị nhìn thấu, phát hiện mọi bí mật giấu diếm.","detail":"Thông Minh Linh Tê là thần thông thuộc về Tống sư tổ, được thi triển thông qua ánh mắt trong suốt nhắm vào đối tượng, khiến người bị chiếu cảm giác toàn bộ thể xác lẫn tinh thần đều bị nhìn thấu. Uy lực của thần thông này cực kỳ đáng sợ, trừ hai vị sư thúc và bạch tu lão giả ở cảnh giới Kết Đan Kỳ ra, hầu như không ai có thể ngăn trở. Trong lần thi triển tại cuộc kiểm tra 24 đệ tử nổi danh (@c0623), Tống sư tổ sử dụng Thông Minh Linh Tê lên Hàn Lập và Đỗ Đông. Kết quả phát hiện Đỗ Đông có vấn đề giấu diếm, trong khi Hàn Lập nhờ có Đại Diễn Quyết bảo vệ tâm thần mà vượt qua được sự dò xét.","thuocTinh":"Dò xét tâm thần","uyLuc":"Cực mạnh, chỉ vài cao thủ Kết Đan Kỳ mới có thể chống lại; ngoài hai vị sư thúc và bạch tu lão giả Kết Đan Kỳ ra không ai ngăn trở được.","dacDiem":"Thi triển qua ánh mắt trong suốt, khiến đối tượng cảm giác bị nhìn thấu toàn bộ thể xác và tinh thần.","congNang":["Dò xét tâm thần đối tượng, phát hiện mọi bí mật giấu diếm (@c0623)"],"nguoiTu":[{"ten":"Tống sư tổ","tuChuong":"@c0623","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0623","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Tống sư tổ thi triển trên Hàn Lập và Đỗ Đông để kiểm tra 24 đệ tử nổi danh. Phát hiện Đỗ Đông có vấn đề, Hàn Lập vượt qua nhờ Đại Diễn Quyết.","anchor":"Thông Minh Linh Tê thần thông của Tống sư muội phát ra rất lợi hại"}]},"nguon":["@c0623"]},{"id":"quy-sat-quyet","name":"Quỷ Sát Quyết","cn":"鬼煞诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Tu sĩ áo vàng họ Việt"],"blurb":"Công pháp tu luyện của tu sĩ họ Việt, tiến bộ đáng kể nhờ tu luyện gần thánh thụ tại cấm địa năm sáu mươi năm, tạo sát khí kinh người trên mặt.","detail":"Tu sĩ Kết Đan họ Việt tu luyện Quỷ Sát Quyết trong thời gian trấn thủ Tam Phái Cấm Địa, nhờ gần thánh thụ mà công pháp tiến triển không ít, sát khí trên mặt kinh người.","congNang":["Tạo sát khí kinh người trên mặt người tu"],"nguoiTu":[{"ten":"Tu sĩ áo vàng họ Việt","tuChuong":"@c0626","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0626","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Tu sĩ họ Việt tu luyện gần thánh thụ","text":"Tu sĩ trung niên Bách Xảo Viện nhận xét Quỷ Sát Quyết của Việt sư huynh tiến triển không ít nhờ tu luyện gần thánh thụ cấm địa.","anchor":"Quỷ Sát Quyết của Việt sư huynh tựa hồ tiến triển không ít"}]},"nguon":["@c0626"]},{"id":"cuu-linh-kiem-the","name":"Cửu Linh Kiếm Thể","cn":"九灵剑体","loai":"khac","loaiLabel":"Linh thể đặc thù","phamCap":"Tam đại kiếm tu linh thể","hePhai":"Kiếm tu","soHuu":["Mạnh Địch"],"blurb":"Cửu Linh Kiếm Thể là một trong tam đại kiếm tu linh thể trong tu tiên giới, do Mạnh Địch sở hữu. Bằng linh thể này kết hợp phi kiếm đỉnh cấp pháp khí, Mạnh Địch tung hoành không đối thủ và đoạt quán quân tuyệt đối tại Thí Kiếm Đại Hội.","detail":"Cửu Linh Kiếm Thể được xưng tụng là một trong tam đại kiếm tu linh thể của tu tiên giới. Người sở hữu linh thể này có uy lực phi kiếm vượt trội hẳn so với kiếm tu thông thường. Mạnh Địch là người mang Cửu Linh Kiếm Thể, nhờ kết hợp linh thể cùng phi kiếm đỉnh cấp pháp khí mà tại Thí Kiếm Đại Hội đã tung hoành vô đối thủ, đoạt lấy ngôi quán quân tuyệt đối.","congNang":["Uy lực phi kiếm tuyệt đối, kết hợp cùng phi kiếm đỉnh cấp pháp khí cho phép tung hoành không đối thủ @c0626"],"nguoiTu":[{"ten":"Mạnh Địch","tuChuong":"@c0626","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0626","loai":"xuat-hien","importance":"major","giaiDoan":"Lộ diện tại Thí Kiếm Đại Hội","text":"Mạnh Địch dùng Cửu Linh Kiếm Thể cùng phi kiếm đỉnh cấp tung hoành vô đối thủ, đoạt quán quân tuyệt đối.","anchor":"\"Cửu Linh Kiếm Thể\" được xưng là một trong tam đại kiếm tu linh thể trong tu tiên giới"}]},"nguon":["@c0626"],"uyLuc":"Mạnh Địch dựa vào Cửu Linh Kiếm Thể cùng phi kiếm đỉnh cấp tung hoành vô đối thủ, đoạt quán quân tuyệt đối tại Thí Kiếm Đại Hội @c0626","dacDiem":"Được liệt vào hàng tam đại kiếm tu linh thể trong tu tiên giới"},{"id":"cam-che-cam-dia-ba-phai","name":"Cấm chế cấm địa ba phái","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp / Cấm chế","phamCap":"Do Nguyên Anh Kỳ tu sĩ thiết lập","hePhai":"","soHuu":[],"blurb":"Cấm chế nhiều tầng do mấy vị sư thúc Nguyên Anh Kỳ ba phái cùng thiết lập, bảo vệ Tam Phái Cấm Địa. Phong tỏa thần thức, chặn ở hơn mười trượng, cần lệnh bài vàng chuyên dụng mới mở được.","detail":"Cấm chế bao gồm nhiều tầng vách bao bọc cửa đá dày đặc chú văn. Ngăn thần thức người vào chỉ vươn hơn mười trượng. Chỉ mở được nhất thời bằng lệnh bài vàng chuyên dụng, tạo thông đạo vài trượng. Hàn Lập (Trúc Cơ hậu kỳ) nhận ra pháp trận cực kỳ lợi hại.","congNang":["Phong tỏa thần thức","Cấm chế đa tầng bảo vệ cửa đá","Chỉ mở nhất thời bằng lệnh bài vàng"],"tabs":{"tienTrinh":[{"chuong":"@c0626","loai":"xuat-hien","importance":"normal","giaiDoan":"Đoàn người vượt qua cấm chế vào cấm địa","text":"Thần thức Hàn Lập bị cấm chế chặn ở hơn mười trượng. Tu sĩ họ Việt dùng lệnh bài vàng mở cấm chế nhiều tầng do Nguyên Anh Kỳ thiết lập, tạo thông đạo cho mọi người bay vào.","anchor":"Cấm địa này là mấy vị sư thúc Nguyên Anh Kỳ ba phái cùng làm phép thiết lập"}]},"nguon":["@c0626"]},{"id":"kiem-khi-hoa-to","name":"Kiếm khí hóa tơ","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Cảnh giới kiếm tu","phamCap":"Cảnh giới kiếm tu tối cao","hePhai":"","soHuu":["Đồng tử họ Lam"],"blurb":"Kiếm khí hóa tơ là cảnh giới cực cao của kiếm tu, kiếm khí được luyện hóa thành tuyến tơ tằm bao bọc hàn khí, có thể tùy tâm hóa kiếm thành tơ, lấy một kiếm phá vạn pháp. Lần đầu xuất hiện khi Đồng tử Lam sư thúc (Nguyên Anh sơ kỳ) thi triển chế phục tu sĩ Kết Đan trong nháy mắt.","detail":"Kiếm khí hóa tơ là cảnh giới kiếm đạo mà kiếm khí được ngưng luyện đến mức cực tinh thuần, hóa thành hình dạng tuyến tơ tằm mảnh mai, bên ngoài bao bọc hàn khí lạnh lẽo. Tại chương @c0627, Đồng tử Lam sư thúc — tu sĩ Nguyên Anh sơ kỳ — bắn ra tuyến tơ tằm màu đỏ mang hàn khí, hạ gục một nho sinh tu vi Kết Đan trong nháy mắt. Đây là lần đầu tiên Hàn Lập tận mắt chứng kiến cảnh giới kiếm tu này; chỉ có Hàn Lập nhờ thần thức mới phát hiện được đòn tấn công, người thường hoàn toàn không thể nhận ra.","congNang":["Kiếm khí ngưng luyện thành tuyến tơ tằm mảnh mai bao bọc hàn khí, lấy một kiếm phá vạn pháp @c0627","Chế phục tu sĩ Kết Đan trong nháy mắt, tốc độ và uy lực vượt trội @c0627","Đòn tấn công cực kỳ ẩn giấu, người thường không thể phát hiện, chỉ thần thức mới nhận ra @c0627"],"nguoiTu":[{"ten":"Đồng tử họ Lam","tuChuong":"@c0627","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0627","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Đồng tử Lam sư thúc bắn tuyến tơ tằm đỏ bao bọc hàn khí hạ gục nho sinh Kết Đan trong nháy mắt. Hàn Lập là người duy nhất phát hiện bằng thần thức, lần đầu chứng kiến cảnh giới kiếm tu tối cao.","anchor":"có thể tùy tâm sở dục hóa kiếm thành tơ, có thể lấy một kiếm phá vạn pháp"}]},"nguon":["@c0627"],"uyLuc":"Tu sĩ Nguyên Anh sơ kỳ thi triển, hạ gục tu sĩ Kết Đan trong nháy mắt, đòn đánh tinh diệu đến mức chỉ có thần thức mới phát hiện được @c0627","dacDiem":"Kiếm khí hóa hình thành tuyến tơ tằm màu đỏ, bên ngoài bao bọc hàn khí lạnh lẽo; hình thái mảnh mai nhưng uy lực cực mạnh, đặc trưng của cảnh giới kiếm đạo cực cao"},{"id":"thai-bach-hoa-khi-thu","name":"Thái bạch hóa khí thủ","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Cổ Kiếm Môn","soHuu":["Nho sinh"],"blurb":"Công pháp của Cổ Kiếm Môn, hóa khí thành bàn tay lớn mịt mờ bắt người. Nho sinh họ Bạch tu luyện rất tốt, dùng quang thủ ép vỡ kiếm khí Luyện Khí Kỳ dễ dàng.","detail":"Bạch quang lóe trên người, tạo quang thủ mịt mờ nhắm bắt mục tiêu. Khi nho sinh bạo phát thi triển nhắm Mạnh Địch, kiếm khí Luyện Khí Kỳ của Mạnh Địch bị ép vỡ vụn. Đồng tử xác nhận đây là công pháp bổn môn, nho sinh tu luyện rất tốt. Quang thủ sau đó bị đồng tử hóa giải, tan thành điểm sáng biến mất.","congNang":["Hóa khí thành bàn tay lớn bắt người","Cấp Kết Đan, ép vỡ kiếm khí Luyện Khí Kỳ dễ dàng"],"nguoiTu":[{"ten":"Nho sinh","tuChuong":"@c0627","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0627","loai":"thi triển","importance":"normal","giaiDoan":"Nho sinh bạo phát","text":"Nho sinh họ Bạch thi triển khi bị lật tẩy, bạch quang lóe trên người tạo quang thủ nhắm bắt Mạnh Địch. Bị đồng tử hóa giải, quang thủ tan thành điểm sáng.","anchor":"Ngươi đem Thái bạch hóa khí thủ của bổn môn tu luyện quả thật rất tốt"}]},"nguon":["@c0627"]},{"id":"dai-la-thien-huyen-quyet","name":"Đại La Thiên Huyễn Quyết","cn":"大罗天幻诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Trấn phái pháp quyết","hePhai":"Thiên Huyễn Tông","soHuu":["Đỗ Đông"],"blurb":"Trấn phái pháp quyết của Thiên Huyễn Tông, được nhìn nhận là đệ nhất ẩn nặc công pháp tại Thiên Nam. Cho phép người tu luyện che giấu tu vi thật, biến đổi hình thể, khiến tu sĩ dưới Kết Đan Hậu Kỳ không thể nhìn thấu.","detail":"Đại La Thiên Huyễn Quyết là công pháp trấn phái của Thiên Huyễn Tông, nổi danh với khả năng ẩn nặc và biến hóa bậc nhất Thiên Nam. Khi Đỗ Đông thi triển pháp quyết này, thân hình biến hóa thành cự hán cao hai trượng, mặt hiện phù văn đen, đôi mắt xanh biếc, tu vi biểu hiện bên ngoài từ Trúc Cơ kỳ được nâng trực tiếp lên Kết Đan Trung Kỳ. Hàn Lập từng nhận xét rằng nếu nói về ẩn nặc công pháp thì Thiên Huyễn Tông tại Thiên Nam đáng xưng đệ nhất. Muốn nhìn thấu qua lớp ngụy trang của pháp quyết này, tu sĩ cần đạt ít nhất cảnh giới Kết Đan Hậu Kỳ.","thuocTinh":"Ẩn nặc, biến hóa hình thể","nguonGoc":"Trấn phái Thiên Huyễn Tông","uyLuc":"Tu sĩ dưới Kết Đan Hậu Kỳ không thể nhìn thấu, đủ sức ngụy trang tu vi Trúc Cơ thành Kết Đan Trung Kỳ, được công nhận là đệ nhất ẩn nặc công pháp Thiên Nam.","dacDiem":"Ẩn nặc tàng hình kết hợp biến đổi hình thể, vừa thay đổi ngoại hình vừa nâng tu vi biểu hiện, ngưỡng nhìn thấu nằm ở Kết Đan Hậu Kỳ trở lên.","nguoiTu":[{"ten":"Đỗ Đông","tuChuong":"@c0630","tangDatToi":"","trangThai":"dang-tu"}],"congNang":["Ẩn nặc tàng hình, che giấu tu vi thật sự của người thi triển @c0630","Biến đổi hình thể — hóa cự hán cao hai trượng, mặt hiện phù văn đen, mắt xanh biếc @c0630","Nâng tu vi biểu hiện bên ngoài, từ Trúc Cơ kỳ tăng lên Kết Đan Trung Kỳ @c0630"],"tabs":{"tienTrinh":[{"chuong":"@c0630","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Đỗ Đông thi triển, hóa cự hán hai trượng mắt xanh biếc, tu vi tăng lên Kết Đan Trung Kỳ. Hàn Lập nhận xét là thiên hạ đệ nhất ẩn nặc công pháp.","anchor":"Đại La Thiên Huyễn Quyết chính xác là danh bất hư truyền, không hổ là trấn phái pháp quyết của quý tông"}]},"nguon":["@c0630"]},{"id":"thien-ho-me-linh-dai-phap","name":"Thiên Hồ Mê Linh Đại Pháp","cn":"天狐迷灵大法","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Hồ tộc","soHuu":["Ngân Nguyệt"],"blurb":"Thiên Hồ Mê Linh Đại Pháp là công pháp của Hồ tộc, cho phép tạo phân thân giả có tim có máu, đủ sức lừa tu sĩ Kết Đan Trung Kỳ tin rằng đã giết được mục tiêu. Hoá thân thuật chỉ có thể ứng phó nhất thời, không thể duy trì kéo dài, và đối mặt tu sĩ Kết Đan Hậu Kỳ sẽ bị nhìn thấu.","detail":"Thiên Hồ Mê Linh Đại Pháp vốn là công pháp truyền thừa của Hồ tộc, được Ngân Nguyệt — vốn tiền thân là Ngân Lang tộc chứ không phải Hồ tộc thuần chính — luyện thành và thi triển. Tại cuộc đối đầu với Đỗ Đông (tu sĩ Kết Đan Trung Kỳ), Ngân Nguyệt sử dụng đại pháp này tạo ra phân thân giả mang hình Hàn Lập, có tim có máu như thật, khiến Đỗ Đông tin rằng đã hạ sát được Hàn Lập. Hàn Lập sau đó nhận xét rằng thuật này còn cao hơn dự kiến, song nếu đối phương là tu sĩ Kết Đan Hậu Kỳ thì phân thân giả sẽ bị nhìn thấu, không thể lừa được. Ngoài ra, hoá thân thuật của công pháp không thể duy trì kéo dài, chỉ dùng ứng phó trong tình huống nhất thời. Việc một yêu tu thuộc Ngân Lang tộc lại luyện được Hồ tộc công pháp này là điều rất kỳ lạ.","thuocTinh":"Ảo thuật, phân thân","nguonGoc":"Hồ tộc công pháp","uyLuc":"Phân thân giả có tim có máu đủ chân thực để lừa Đỗ Đông — tu sĩ Kết Đan Trung Kỳ — tin rằng đã giết được Hàn Lập, song đối mặt Kết Đan Hậu Kỳ thì sẽ bị nhìn thấu.","dacDiem":"Hoá thân thuật không thể kéo dài, chỉ dùng ứng phó nhất thời; bản thân là Hồ tộc công pháp nhưng Ngân Nguyệt vốn thuộc Ngân Lang tộc lại luyện được, điều này được xem là rất kỳ lạ.","nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0630","tangDatToi":"","trangThai":"dang-tu"}],"congNang":["Tạo phân thân giả mang hình dạng người khác, có tim có máu như thật, đủ sức chịu chết thay cho chủ nhân @c0630","Lừa được tu sĩ Kết Đan Trung Kỳ tin rằng phân thân giả là bản thể thật @c0630"],"tabs":{"tienTrinh":[{"chuong":"@c0630","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Ngân Nguyệt tạo phân thân giả hình Hàn Lập, lừa Đỗ Đông tưởng đã giết được Hàn Lập. Hàn Lập nhận xét còn cao hơn Đại La Thiên Huyễn Quyết.","anchor":"Thiên Hồ Mê Linh Đại Pháp của ta có phải còn cao hơn cả Đại La Thiên Huyễn Quyết kia không"}]},"nguon":["@c0630"]},{"id":"dai-tran-tran-phai","name":"Đại trận trấn phái","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Lạc Vân Tông","soHuu":["Lạc Vân Tông"],"blurb":"Trận pháp trấn phái của Lạc Vân Tông, từng được mở ra khi các Nguyên Anh của tông kết anh năm xưa để bảo vệ.","detail":"Lữ sư đệ nhắc lại khi hai vị Nguyên Anh kết anh năm xưa, tông môn đã phong tỏa cả ngọn núi và mở đại trận trấn phái để bảo hộ quá trình kết anh.","congNang":["Bảo hộ quá trình kết anh, phong tỏa ngọn núi"],"tabs":{"tienTrinh":[{"chuong":"@c0635","loai":"nhắc tới","importance":"bridge","giaiDoan":"Được nhắc lại","text":"Lữ sư đệ nhắc lại khi hai vị Nguyên Anh kết anh năm xưa, tông môn đã mở đại trận trấn phái.","anchor":"ngay cả đại trận trấn phái cũng mở ra"}]},"nguon":["@c0635"]},{"id":"tam-ma-can-tra","name":"Tâm ma cắn trả","cn":"","loai":"khac","loaiLabel":"Hiện tượng tu luyện","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Bước cuối cùng trong quá trình kết Nguyên Anh, người kết anh phải đối mặt với tâm ma huyễn hóa ra nỗi sợ lớn nhất của mình.","detail":"Thử thách tâm thần ở giai đoạn cuối kết Nguyên Anh. Người kết anh cảm nhận như trải qua mấy tháng đến mấy năm, nhưng thực tế bên ngoài chỉ một chút thời gian. Càng sợ cái gì tâm ma càng huyễn hóa ra cái đó. Lữ sư đệ (Nguyên Anh Lạc Vân Tông) phải dùng Định Linh Đan mới sống sót qua.","congNang":["Thử thách tâm thần, huyễn hóa nỗi sợ hãi lớn nhất của người kết anh"],"dacDiem":"Thời gian chủ quan kéo dài mấy tháng đến mấy năm, thời gian thực rất ngắn","tabs":{"tienTrinh":[{"chuong":"@c0635","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lộ cơ chế","text":"Trình sư huynh và Lữ sư đệ giải thích cơ chế tâm ma cắn trả khi kết anh: càng sợ cái gì càng huyễn hóa ra cái đó, Lữ sư đệ phải dùng Định Linh Đan mới vượt qua.","anchor":"Tâm ma cắn trả, cơ hồ là ngươi càng sợ hãi cái gì, trong lòng ngươi lại càng huyễn hóa ra cái đó"}]},"nguon":["@c0635"]},{"id":"cong-phap-giu-nguyen-am","name":"Công pháp giữ nguyên âm của Mộ Phái Linh","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Mộ Phái Linh"],"blurb":"Công pháp Mộ Phái Linh đang tu luyện đến thời kỳ mấu chốt, yêu cầu giữ thân xử nữ, là lý do nàng xin ước hẹn ba mươi năm.","detail":"Mộ Phái Linh cho biết công pháp nàng đang tu luyện cần thân thể xử nữ, vô cùng trọng yếu cho bước đột phá sắp tới. Nàng lấy đó làm điều kiện xin Hàn Lập ba mươi năm không chiếm nguyên âm.","yeuCau":"Thân thể xử nữ","congNang":["Yêu cầu giữ thân xử nữ trong quá trình tu luyện đến thời kỳ mấu chốt"],"nguoiTu":[{"ten":"Mộ Phái Linh","tuChuong":"@c0641","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0641","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Mộ Phái Linh tiết lộ công pháp cần thân xử nữ","text":"Mộ Phái Linh nói công pháp nàng đang tu luyện đến thời kỳ mấu chốt, thân thể xử nữ vô cùng trọng yếu, xin ba mươi năm giữ nguyên âm.","anchor":"Mà công pháp này, thân thể xử nữ vô cùng trọng yếu"}]},"nguon":["@c0641"]},{"id":"dan-long-quyet","name":"Dẫn Long quyết","cn":"引龙诀","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Lục đạo cực thánh","Lục đạo thiếu chủ"],"blurb":"Bí thuật song tu ma đạo do Lục đạo cực thánh sáng tạo, thích hợp tu sĩ Kết Đan, cho nam tu hấp thu âm nguyên tinh của nữ nhân để tăng tu vi nhanh nhưng tổn hại nguyên khí nữ nhân.","detail":"Dẫn Long quyết là một trong hai môn song tu bí thuật ghi trong ngọc giản màu hồng mà Hàn Lập lấy được từ túi trữ vật của Lục đạo thiếu chủ. Dành cho tu sĩ Kết Đan Kỳ, cho phép nam tu hấp thu âm nguyên tinh của nữ nhân để tăng tu vi rất nhanh, nhưng đổi lại gây tổn hại lớn cho nguyên khí nữ nhân. Hàn Lập suy đoán Lục đạo thiếu chủ đạt Kết Đan Hậu Kỳ khi còn trẻ và có nhiều nữ tu Trúc Cơ bên cạnh là nhờ tu luyện bí thuật này.","nguonGoc":"Do Lục đạo cực thánh sáng tạo","congNang":["Cho nam tu Kết Đan hấp thu âm nguyên tinh của nữ nhân để tăng tu vi"],"dacDiem":"Tổn hại lớn nguyên khí nữ nhân bị hấp thu","nguoiTu":[{"ten":"Lục đạo thiếu chủ","tuChuong":"@c0642","tangDatToi":"","trangThai":"da-tu-huyen"}],"tabs":{"tienTrinh":[{"chuong":"@c0642","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Được Hàn Lập phát hiện trong ngọc giản","text":"Hàn Lập lấy ngọc giản màu hồng từ túi trữ vật Lục đạo thiếu chủ, bên trong ghi Dẫn Long quyết thích hợp tu sĩ Kết Đan, suy đoán Lục đạo thiếu chủ đã dùng bí thuật này.","anchor":"một loại là Dẫn Long quyết thích hợp với tu sĩ Kết Đan Kỳ"}]},"nguon":["@c0642"]},{"id":"dien-phuong-boi-nguyen-cong","name":"Điên Phượng Bồi Nguyên công","cn":"颠凤培元功","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Điên Phượng Bồi Nguyên công là bí thuật song tu ma đạo do Lục đạo cực thánh sáng tạo, dành cho nam tu cảnh giới Nguyên Anh đoạt nguyên âm từ nữ tu Kết Đan kiêm tu nhằm hỗ trợ đột phá tu vi. Hàn Lập phát hiện công pháp này trong ngọc giản và coi đây là phương pháp dài hạn, lấy đó làm lý do chính thu Mộ Phái Linh làm thiếp để chờ nàng kết đan rồi kiêm tu.","detail":"Điên Phượng Bồi Nguyên công là bí thuật song tu thuộc hệ ma đạo, được ghi chép trong ngọc giản màu hồng, do Lục đạo cực thánh sáng tạo. Công pháp này có tính chất trái ngược với Dẫn Long quyết, yêu cầu quy trình nghiêm ngặt: nữ tu trước tiên phải tự thân đạt tới cảnh giới Kết Đan, sau đó mới kiêm tu bí thuật này; khi nữ tu đã kiêm tu xong, nam tu ở cảnh giới Nguyên Anh sẽ đoạt nguyên âm của nữ tu để mạnh mẽ đột phá tu vi. Hàn Lập tìm thấy công pháp trong ngọc giản @c0642, nhận định đây là con đường hỗ trợ đột phá sau Nguyên Anh đáng thử, và quyết định thu Mộ Phái Linh làm thiếp chính vì mục đích này, dự tính chờ nàng kết đan xong mới cho kiêm tu Điên Phượng Bồi Nguyên công.","nguonGoc":"Do Lục đạo cực thánh sáng tạo","congNang":["Hỗ trợ nam tu cảnh giới Nguyên Anh đoạt nguyên âm từ nữ tu Kết Đan đã kiêm tu công pháp này, nhằm đột phá tu vi @c0642"],"dacDiem":"Yêu cầu nữ tu phải tự thân đạt cảnh giới Kết Đan rồi kiêm tu bí thuật này trước, sau đó nam tu Nguyên Anh mới đoạt nguyên âm; quy trình dài hạn, trái ngược với Dẫn Long quyết, thuộc hệ song tu ma đạo.","nguoiTu":[],"tabs":{"tienTrinh":[{"chuong":"@c0642","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Hàn Lập phát hiện và lên kế hoạch dài hạn","text":"Hàn Lập tìm thấy trong ngọc giản và quyết định đây là lý do chính thu Mộ Phái Linh làm thiếp, chờ nàng kết đan rồi kiêm tu nhằm thử phương pháp đột phá sau Nguyên Anh.","anchor":"Mà bí thuật còn lại chính là Điên Phượng Bồi Nguyên công"}]},"nguon":["@c0642"]},{"id":"ngoc-gian-mau-hong","name":"Ngọc giản màu hồng","cn":"","loai":"khac","loaiLabel":"Ngọc giản công pháp","phamCap":"","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Ngọc giản lấy từ túi trữ vật Lục đạo thiếu chủ, ghi nhiều loại công pháp song tu ma đạo, nổi bật là Dẫn Long quyết và Điên Phượng Bồi Nguyên công.","detail":"Hàn Lập lấy ra từ túi trữ vật của Lục đạo thiếu chủ, bên trong ghi lại nhiều loại công pháp song tu ma đạo. Hai bí thuật quan trọng nhất là Dẫn Long quyết dành cho tu sĩ Kết Đan và Điên Phượng Bồi Nguyên công dành cho tu sĩ Nguyên Anh.","nguon":["@c0642"]},{"id":"dai-canh-kiem-tran","name":"Đại Canh Kiếm Trận","cn":"大庚剑阵","loai":"than-thong","loaiLabel":"Kiếm trận / Trận pháp","phamCap":"Cực phẩm (tầng 13 cuối cùng của Thanh Nguyên Kiếm Quyết)","hePhai":"Kiếm tu","soHuu":["Hàn Lập"],"blurb":"Đại Canh Kiếm Trận là thần thông tối cường ẩn ở tầng thứ 13 — tầng cuối cùng của Thanh Nguyên Kiếm Quyết, bị cấm chế theo cảnh giới và chỉ giải mở được khi đạt Nguyên Anh Kỳ. Tu luyện đến đỉnh, chỉ cần phát huy 1/3 uy lực cũng đủ tung hoành Thiên Nam, với 72 phi kiếm huyễn hóa thành 362 đạo kiếm quang đủ sức giết tu sĩ Nguyên Anh Trung Kỳ thậm chí Hậu Kỳ.","detail":"Đại Canh Kiếm Trận là kiếm trận liên quan trận pháp, được ghi chép ẩn trong giấy vàng chứa Thanh Nguyên Kiếm Quyết. Người luyện chế giấy vàng đã khóa khẩu quyết tầng này bằng cấm chế theo cảnh giới; Hàn Lập sau khi đột phá Nguyên Anh Kỳ mới phun thanh quang giải mở được cấm chế, khai mở tầng 13 này (@c0643). Điều kiện bày trận đòi hỏi ít nhất hàng trăm đạo kiếm quang, buộc phải luyện chế Thanh Trúc Phong Vân kiếm và trộn thêm tài liệu Canh Tinh vào mỗi phi kiếm. Canh Tinh cần số lượng lớn, Hàn Lập đã yêu cầu Thiên Đạo Minh giúp thu thập nguyên liệu này và kiên quyết không đổi điều kiện (@c0748). Phương án cụ thể mà Hàn Lập tính toán là dùng 72 phi kiếm, mỗi thanh huyễn hóa 4 kiếm quang nhờ Kiếm Ảnh Phân Quang thuật — một chiêu thức vốn được sáng tạo để phục vụ kiếm trận này — tạo thành 362","thuocTinh":"Kiếm","nguonGoc":"Ẩn trong giấy vàng ghi Thanh Nguyên Kiếm Quyết, bị cấm chế theo cảnh giới","yeuCau":"Nguyên Anh Kỳ trở lên mới giải cấm chế; cần ≥72 phi kiếm Thanh Trúc Phong Vân + Canh Tinh","uyLuc":"Tu đến đỉnh phong chỉ cần phát huy 1/3 uy lực đã đủ tung hoành Thiên Nam; với 72 phi kiếm huyễn hóa thành 362 đạo kiếm quang, đủ sức giết tu sĩ Nguyên Anh Trung Kỳ thậm chí Hậu Kỳ.","dacDiem":"Bản chất là trận pháp chứ không phải chiêu thức đơn lẻ, cần bày trận bằng phi kiếm với nguyên liệu Canh Tinh; khẩu quyết bị cấm chế theo cảnh giới, phải đạt Nguyên Anh Kỳ mới giải mở; Kiếm Ảnh Phân Quang thuật vốn được sáng tạo chuyên để phục vụ kiếm trận này.","congNang":["Bày kiếm trận bằng phi kiếm, triển khai hàng trăm đạo kiếm quang sát địch (@c0643)","Cần Canh Tinh số lượng lớn làm nguyên liệu trộn vào mỗi phi kiếm để đáp ứng điều kiện bày trận (@c0748)","Phối hợp Kiếm Ảnh Phân Quang thuật để mỗi phi kiếm huyễn hóa nhiều kiếm quang, nhân số lượng kiếm quang trong trận"],"cacTang":[{"ten":"Đại Canh Kiếm Trận","moTa":"Tầng 13, tầng cuối cùng, kiếm trận liên quan trận pháp","chuong":"@c0643"}],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0643","tangDatToi":"Vừa lĩnh ngộ, chưa thi triển","trangThai":"đang luyện chế"}],"trangThai":"Đã lĩnh ngộ, chưa thể thi triển (thiếu Canh Tinh)","capNhatToi":"@c0643","tabs":{"tienTrinh":[{"chuong":"@c0643","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Khai mở và lĩnh ngộ","text":"Hàn Lập đạt Nguyên Anh Kỳ, phun thanh quang giải cấm chế trên giấy vàng, khai mở tầng 13 Thanh Nguyên Kiếm Quyết. Ngồi lĩnh ngộ 3 ngày 3 đêm, nắm được toàn bộ kiếm trận nhưng chưa thể thi triển vì thiếu 72 phần Canh Tinh.","anchor":"Tu luyện đến đỉnh thì dù chỉ là một phần ba uy lực cũng có thể tung hoành Thiên Nam"},{"chuong":"@c0748","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập đặt điều kiện thu thập nguyên liệu","text":"Hàn Lập yêu cầu Thiên Đạo Minh giúp thu thập Canh Tinh để luyện chế trận pháp này, kiên quyết không đổi điều kiện.","anchor":"Tại hạ muốn một chút Canh Tinh để luyện chế pháp bảo"}]},"nguon":["@c0643","@c0748"]},{"id":"kinh-hon-thuat","name":"Kinh hồn thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật Hàn Lập tu luyện, cho phép qua tiếp xúc hoặc thi triển lên người khác mà nhận ra đối phương có linh căn hay không cùng tư chất tu luyện.","detail":"Hàn Lập thi triển lên tiểu nhị A Nhị, chỉ qua tiếp xúc đã nhận ra A Nhị có linh căn tư chất đủ tu tới luyện khí kỳ tầng ba bốn. Hàn tự nhận đây là một loại bí thuật, khiến hai tu sĩ đồng hành kinh ngạc gọi là thần thông kinh người.","congNang":["Thăm dò linh căn và tư chất tu luyện của đối phương qua tiếp xúc"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0645","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0645","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Hàn Lập dùng Kinh hồn thuật lên tiểu nhị A Nhị tại khách điếm Vĩnh Khúc, phát hiện A Nhị có linh căn tư chất đủ tu tới luyện khí kỳ tầng ba bốn.","anchor":"vì sao với con người lại dùng Kinh hồn thuật"}]},"nguon":["@c0645"]},{"id":"tran-phap-vay-dich-tieu-coc","name":"Trận pháp vây địch trong tiểu cốc","loai":"bi-thuat","loaiLabel":"Trận pháp","soHuu":["Tu sĩ ục ịch họ La","Đại hán đầu hói"],"blurb":"Trận pháp đơn giản do Bành Dịch Song Hung bố trí sẵn trong tiểu cốc, dùng làm bẫy vây địch để phục kích tu sĩ Trúc Cơ.","detail":"Một trận pháp vây địch đơn giản được bố trí trong tiểu cốc phía sau tiểu sơn vắng người. Dùng để lừa mục tiêu vào rồi đánh lén, nhưng Hàn Lập dễ dàng phát hiện bằng thần thức do dao động linh khí cấm chế quá yếu ớt.","congNang":["Vây khốn mục tiêu trong tiểu cốc để phục kích"],"nguon":["@c0646"],"tabs":{"tienTrinh":[{"chuong":"@c0646","loai":"xuat-hien","importance":"normal","giaiDoan":"Bố trí tại tiểu cốc","text":"Bành Dịch Song Hung bố trí sẵn trận pháp vây địch trong tiểu cốc để phục kích Hàn Lập, nhưng bị hắn phát hiện bằng thần thức trước khi vào.","anchor":"không ngờ còn bố trí trong cốc một trận pháp vây địch đơn giản"}]}},{"id":"huyen-quang-hoa-vat-quyet","name":"Huyễn quang hóa vật quyết","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Lục sắc tiểu nhân"],"blurb":"Pháp quyết ẩn nặc hóa thân thành vật thể (cây nhỏ), khiến thần thức tu sĩ Nguyên Anh kỳ không phát hiện được.","detail":"Lục sắc tiểu nhân dùng pháp quyết này hóa thành một cây nhỏ để tránh thần thức dò xét. Chính nó tuyên bố pháp quyết này không có khả năng bị tu sĩ Nguyên Anh kỳ hiểu được, nhưng bị Minh Thanh Linh Nhãn của Hàn Lập phát hiện sai biệt.","congNang":["Ẩn nặc hóa thân thành vật thể (cây nhỏ), tránh thần thức dò xét"],"nguoiTu":[{"ten":"Lục sắc tiểu nhân","tuChuong":"@c0647","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0647","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị phá giải","text":"Lục sắc tiểu nhân ẩn thân bằng pháp quyết này hóa thành cây nhỏ, nhưng bị Hàn Lập dùng Minh Thanh Linh Nhãn phát hiện sai biệt, buộc phải hiện hình.","anchor":"Huyễn quang hóa vật quyết này của ta không có khả năng bị tu sĩ Nguyên Anh Kỳ hiểu được"}]},"nguon":["@c0647"]},{"id":"minh-thanh-linh-nhan","name":"Minh Thanh Linh Nhãn","cn":"明清灵眼","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Thần thông linh nhãn giúp nhìn thấu ngụy trang ẩn nặc mà thần thức thông thường không phát hiện được.","detail":"Hàn Lập trong lúc cấp bách dùng thử Minh Thanh Linh Nhãn, nhờ lam quang phát ra mà phát hiện một cây nhỏ có sai biệt với xung quanh, từ đó ép lục sắc tiểu nhân đang dùng Huyễn quang hóa vật quyết phải hiện hình.","congNang":["Nhìn ra ngụy trang hóa vật mà thần thức không phát hiện được","Quan sát linh hồn, linh thức tinh tế, phát hiện biến hóa vi tế"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0647","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0647","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu sử dụng thực chiến","text":"Hàn Lập vô ý dùng thử, nhờ lam quang phát hiện cây nhỏ khác thường, ép lục sắc tiểu nhân hiện hình.","anchor":"trong lúc vô ý dùng thần thông Minh Thanh Linh Nhãn thử một lần"},{"chuong":"@c0759","loai":"thi triển","importance":"normal","giaiDoan":"Quan sát giao hồn Độc Giao","text":"Hàn Lập dùng Minh Thanh Linh Nhãn quan sát giao hồn Độc Giao, phát hiện linh thức đang biến mất, ba phần si ngốc.","anchor":"Dưới sự trợ giúp của Minh Thanh Linh Nhãn, Hàn Lập lại rõ ràng nhìn thấy sự khác biệt"}]},"nguon":["@c0647","@c0759"]},{"id":"kim-ho-dien-vong","name":"Kim hồ điện võng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kim hồ điện võng là thần thông do Hàn Lập tự sáng chế, vận dụng Ích Tà Thần Lôi từ mười hai phi kiếm Kim Lôi Trúc ngưng kết thành lưới điện vàng, co rút bao chụp mục tiêu thành kim cầu và phong tỏa ngũ hành linh khí khiến đối phương không thể thoát thân.","detail":"Hàn Lập ngưng hóa Ích Tà Thần Lôi phát ra từ mười hai phi kiếm Kim Lôi Trúc thành một tấm điện võng màu vàng kim bao chụp xuống mục tiêu, sau đó co rút siết chặt nhốt đối tượng thành một quả kim cầu, đồng thời phong tỏa ngũ hành linh khí bên trong khiến mục tiêu mất khả năng vận chuyển pháp lực để phá vây. Thần thông này đòi hỏi hơn mười đoạn Kim Lôi Trúc chứa đủ Ích Tà Thần Lôi mới có thể ngưng hóa thành công. Sau khi Hàn Lập luyện thành Đại Diễn Quyết tầng thứ tư, thần thức mở rộng đáng kể, ông mới có thể thi triển Kim hồ điện võng trong đấu pháp thực chiến với ít cố kỵ hơn trước. Tại chương @c0648, Hàn Lập đã dùng điện hồ từ mười hai phi kiếm kết thành lưới vàng chụp xuống Mộc Linh Anh, co rút nhốt thành kim cầu.","congNang":["Ngưng kết Ích Tà Thần Lôi từ mười hai phi kiếm Kim Lôi Trúc thành lưới điện vàng bao chụp mục tiêu, co rút siết chặt nhốt thành kim cầu @c0648","Phong tỏa ngũ hành linh khí bên trong kim cầu khiến mục tiêu không thể vận chuyển pháp lực để thoát thân"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0648","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0648","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng trong thực chiến","text":"Hàn Lập dùng điện hồ từ mười hai phi kiếm kết thành lưới vàng chụp xuống Mộc Linh Anh, co rút nhốt thành kim cầu, lần đầu thi triển thần thông tự sáng chế trong đấu pháp thực tế.","anchor":"Ngưng hóa Ích Tà Thần Lôi thành lưới, loại thần thông này"}]},"nguon":["@c0648"],"uyLuc":"Co rút lưới điện vàng nhốt trọn Mộc Linh Anh thành kim cầu, phong tỏa hoàn toàn ngũ hành linh khí khiến đối phương bất lực không thoát @c0648","dacDiem":"Cần hơn mười đoạn Kim Lôi Trúc chứa Ích Tà Thần Lôi để ngưng hóa; sau khi luyện Đại Diễn Quyết tầng thứ tư mở rộng thần thức mới thi triển trong thực chiến với ít cố kỵ hơn"},{"id":"khoi-huong-phan-hong","name":"Khói hương phấn hồng","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Ngân Nguyệt"],"blurb":"Ngân Nguyệt phun khói hương phấn hồng từ môi, làm đối phương hôn mê bất tỉnh dù có quang hoa hộ thể, hiệu quả tức thì xuyên qua phòng hộ.","detail":"Khói hương phấn hồng phun ra từ môi Ngân Nguyệt, xộc vào miệng mũi đối phương gây hôn mê tức thì. Quang hoa hộ thể của tu sĩ Kết Đan Kỳ hoàn toàn vô dụng trước chiêu này. Được sử dụng để hạ gục Phó Gia lão tổ trước khi chặt đầu.","thuocTinh":"Mị/Độc","nguonGoc":"","uyLuc":"Xuyên qua quang hoa hộ thể Kết Đan Kỳ, gây hôn mê tức thì","dacDiem":"Dạng khói hương phấn hồng phun từ môi","congNang":["Xộc vào miệng mũi gây hôn mê bất tỉnh","Vô hiệu hóa quang hoa hộ thể"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0651","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0651","loai":"thi triển","importance":"normal","giaiDoan":"Phục kích Phó Gia lão tổ","text":"Ngân Nguyệt phun khói hương phấn hồng từ môi làm Phó Gia lão tổ hôn mê bất tỉnh, quang hoa hộ thể hoàn toàn vô dụng.","anchor":"một mảnh khói hương phấn hồng trong nháy mắt phun ra, bao Phó Gia lão tổ đang không kịp đề phòng lại"}]},"nguon":["@c0651"]},{"id":"huyen-mau-hoa-anh-dai-phap","name":"Huyền Mẫu Hóa Anh Đại Pháp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Cấp bậc gần ngang Nhất Khí Hóa Tam Thanh","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Huyền Mẫu Hóa Anh Đại Pháp là bí công ma đạo ghi trong ngọc giản trận pháp thượng cổ thời hồng hoang, có thể bồi dưỡng nguyên thần thứ hai và thúc đẩy nguyên anh thứ hai đi ra. Thần thông này được đánh giá cấp bậc gần ngang Nhất Khí Hóa Tam Thanh — đạo môn đệ nhất huyền công.","detail":"Huyền Mẫu Hóa Anh Đại Pháp được ghi chép trong ngọc giản trận pháp thượng cổ thời hồng hoang, vốn là di vật của Tân Như Âm. Đây là bí công thuộc ma đạo, sở hữu năng lực bồi dưỡng nguyên thần thứ hai hàng thật giá thật, thậm chí có thể thúc đẩy nguyên anh thứ hai đi ra — trình độ gần sánh ngang với Nhất Khí Hóa Tam Thanh, đạo môn đệ nhất huyền công. Hàn Lập tiết lộ bí công này cho Ngân Nguyệt biết; Ngân Nguyệt cảnh báo rằng bí công ma đạo thường mang tính chất tà môn, cần kiểm tra và nghiên cứu cẩn thận trước khi tu luyện.","nguonGoc":"Ghi trong ngọc giản trận pháp thượng cổ thời hồng hoang","thuocTinh":"Ma đạo","dacDiem":"Có thể có tính chất tà môn, cần nghiên cứu cẩn thận trước khi tu luyện.","congNang":["Bồi dưỡng nguyên thần thứ hai @c0654","Thúc đẩy nguyên anh thứ hai đi ra @c0654"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0654","tangDatToi":"Chưa bắt đầu tu luyện","trangThai":"nghien-cuu"}],"tabs":{"tienTrinh":[{"chuong":"@c0654","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện trong ngọc giản","text":"Hàn Lập tiết lộ cho Ngân Nguyệt bí công ma đạo ghi trong ngọc giản trận pháp thượng cổ, có thể bồi dưỡng nguyên thần thứ hai và thúc đẩy nguyên anh thứ hai đi ra, cấp bậc gần ngang Nhất Khí Hóa Tam Thanh. Quyết định nghiên cứu cẩn thận khi về Lạc Vân Tông.","anchor":"bí thuật bồi dưỡng nguyên thần thứ hai hàng thật giá thật, thậm chí có thể thúc dục nguyên anh thứ hai đi ra"}]},"capNhatToi":"@c0654","nguon":["@c0654"],"uyLuc":"Cấp bậc gần ngang Nhất Khí Hóa Tam Thanh — đạo môn đệ nhất huyền công."},{"id":"dan-mong-thuat","name":"Dẫn Mộng Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Huyền Âm Kinh","soHuu":["Hàn Lập"],"blurb":"Bí công thuộc Huyền Âm Kinh, có thể phong ấn và cải biến trí nhớ người khác. Vượt xa Khống Thần Thuật và Vong Trần Đan.","detail":"Bí công nằm trong Huyền Âm Kinh, cho phép phong ấn trí nhớ liên quan và cải biến thành ký ức giả. Vượt xa Khống Thần Thuật và Vong Trần Đan. Chỉ người tu vi cao hơn xa mới có thể giải, nhưng chỉ dùng được khi chênh lệch tu vi rất lớn giữa người dùng và đối tượng, nếu không sẽ hao tổn thần thức người chịu thuật.","congNang":["Phong ấn trí nhớ liên quan","Cải biến trí nhớ thành ký ức giả"],"dacDiem":"Cần chênh lệch tu vi rất lớn, nếu không hao tổn thần thức người chịu thuật","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0654","tangDatToi":"Đã thi triển thành công","trangThai":"thanh-thuc"}],"tabs":{"tienTrinh":[{"chuong":"@c0654","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Hàn Lập thi triển Dẫn Mộng Thuật phong ấn trí nhớ phụ nhân Tề Vân Tiêu liên quan đến mình, cải biến thành ký ức gặp cao nhân ban đan dược.","anchor":"bắt đầu thi triển một loại bí công Dẫn mộng thuật Huyền Âm Kinh, phong ấn một ít trí nhớ liên quan lại"}]},"capNhatToi":"@c0654","nguon":["@c0654"]},{"id":"nhat-khi-hoa-tam-thanh","name":"Nhất Khí Hóa Tam Thanh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đạo môn đệ nhất huyền công","hePhai":"Đạo môn","soHuu":[],"blurb":"Đạo môn đệ nhất huyền công, bí thuật nghịch thiên không dễ ngoại lưu. Được Hàn Lập nhắc đến như mốc so sánh cho Huyền Mẫu Hóa Anh Đại Pháp.","detail":"Đạo môn đệ nhất huyền công, bí thuật nghịch thiên. Được Hàn Lập nhắc đến khi tiết lộ về Huyền Mẫu Hóa Anh Đại Pháp, đánh giá bí công ma đạo kia có cấp bậc gần ngang với thần thông này.","nguon":["@c0654"]},{"id":"phap-thuat-thu-linh-tuyen","name":"Pháp thuật thu linh tuyền","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp thuật kết hợp dấu tay cổ quái và chú ngữ, thu gọn toàn bộ linh tuyền thành viên châu.","detail":"Hàn Lập thi triển dấu tay cổ quái kết hợp chú ngữ, hoàng quang bao phủ, khiến mặt nước bay lên, suối xoay tròn tạo hắc động, rồi thu gọn toàn bộ Linh Nhãn Chi Tuyền thành viên châu cỡ nắm tay.","congNang":["Thu gọn linh tuyền thành viên châu nhỏ gọn để mang đi"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0655","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0655","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Hàn Lập dùng pháp thuật thu gọn toàn bộ Linh Nhãn Chi Tuyền trong động phủ cũ tại Thái Nhạc Sơn Mạch thành viên châu cỡ nắm tay.","anchor":"hai tay kết xuất một cái dấu tay cổ quái, hai mắt nhìn chằm chằm linh tuyền, miệng lầm rầm đọc chú ngữ"}]},"nguon":["@c0655"]},{"id":"kiem-thuat-hop-kiem","name":"Kiếm thuật hợp kiếm (Thanh trúc phong vân kiếm)","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kỹ thuật hợp nhất nhiều thanh kiếm quang thành cự kiếm xanh hơn mười trượng, tốc độ cực nhanh, uy lực mạnh mẽ.","detail":"Hàn Lập phóng hơn mười thanh kiếm quang biến thành ba bốn mươi đạo chém giết nhóm tu sĩ, sau đó hợp thành cự kiếm xanh hơn mười trượng phóng đuổi theo tu sĩ áo xám, đánh tan mọi phòng thủ của đối phương.","congNang":["Kiếm quang nhân lên gấp nhiều lần, hợp thành cự kiếm tốc độ cực nhanh"],"tabs":{"tienTrinh":[{"chuong":"@c0656","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập dùng diệt nhóm Quỷ Linh Môn","text":"Hàn Lập hợp hơn một trăm đạo kiếm quang thành cự kiếm xanh hơn mười trượng, tiêu diệt tu sĩ Kết Đan Kỳ Vu Hồng đang bỏ chạy cùng toàn bộ phòng thủ.","anchor":"hơn một trăm đạo kiếm quang liền tụ tập lại, trong nháy mắt tạo thành một thanh cự kiếm màu xanh thật lớn"}]},"nguon":["@c0656"]},{"id":"bi-cong-cam-ung-moc-linh-anh","name":"Bí công cảm ứng Mộc Linh Anh","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Hạm Vân Chi","Liễu sư muội"],"blurb":"Công pháp do sư tổ Ngự Linh Tông tự mình truyền, cho phép đơn phương cảm ứng vị trí Mộc Linh Anh từ xa mấy trăm dặm mà đối phương dưới Nguyên Anh Hậu Kỳ không thể phát hiện.","detail":"Do sư tổ Ngự Linh Tông truyền cho Hạm Vân Chi và nữ tử họ Liễu. Chỉ cảm ứng đơn phương, không bị phát hiện trừ khi đối phương đạt Nguyên Anh Hậu Kỳ trở lên. Hàn Lập nhờ thần thức Đại Diễn Quyết tầng 4 cường đại hơn hẳn tu sĩ Nguyên Anh bình thường nên đã cảm nhận được.","thuocTinh":"Cảm ứng","nguonGoc":"Sư tổ Ngự Linh Tông truyền","congNang":["Đơn phương cảm ứng vị trí Mộc Linh Anh từ xa mấy trăm dặm"],"nguoiTu":[{"ten":"Hạm Vân Chi","tuChuong":"@c0661","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Liễu sư muội","tuChuong":"@c0661","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0661","loai":"thi triển","importance":"normal","giaiDoan":"Nhóm Ngự Linh Tông dùng để truy tung Hàn Lập","text":"Hạm Vân Chi và nữ tử họ Liễu thi triển bí công cảm ứng vị trí Mộc Linh Anh trên người Hàn Lập từ xa mấy trăm dặm, nhưng bị Hàn Lập phát hiện nhờ thần thức vượt trội.","anchor":"Công pháp của chúng ta là do sư tổ các ngươi tự mình truyền cho"}]},"nguon":["@c0661"]},{"id":"linh-hop-quyet","name":"Linh Hợp Quyết","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":[],"blurb":"Bí thuật liên kết pháp lực nhiều người thành một thể, đề cao tốc độ phi độn gần nửa.","detail":"Sáu người Ngự Linh Tông thi triển, liên kết pháp lực sáu người thành toàn thể tạo hoàng quang phi độn, tăng tốc độ gần nửa để chạy trốn khỏi Hàn Lập.","nguon":["@c0661"]},{"id":"phong-hoa-chi-don","name":"Phong hỏa chi độn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Phụ nhân họ Lâm"],"blurb":"Độn thuật cổ quái cực hiếm phối hợp phong và hỏa, biến cả người thành hỏa cầu to lớn kèm thanh quang, tốc độ ngang Nguyên Anh Sơ Kỳ dù người tu chỉ Kết Đan Sơ Kỳ. Đối địch yếu nhưng chạy cực nhanh.","detail":"Công pháp cổ quái mà phụ nhân họ Lâm (đệ tử Toái Hồn Chân Nhân) tu luyện. Khi thi triển, biến cả người thành hỏa cầu to lớn kèm thanh quang di chuyển cực nhanh. Khi phối hợp với pháp bảo phong thuộc tính Phiêu Linh Đái, tốc độ như hổ thêm cánh, đạt ngang Nguyên Anh Sơ Kỳ. Tuy nhiên khi đối địch thì so với công pháp đỉnh cấp khác thua kém không ít.","thuocTinh":"Phong, Hỏa","nguonGoc":"","dacDiem":"Chiến đấu yếu nhưng độn thuật cực mạnh, cực hiếm thấy","congNang":["Độn thuật phong+hỏa, tốc độ ngang Nguyên Anh Sơ Kỳ dù Kết Đan Sơ Kỳ"],"nguoiTu":[{"ten":"Phụ nhân họ Lâm","tuChuong":"@c0662","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0662","loai":"thi triển","importance":"normal","giaiDoan":"Phụ nhân họ Lâm thi triển đào tẩu","text":"Phụ nhân họ Lâm thi triển Phong hỏa chi độn kết hợp Phiêu Linh Đái, hóa hồng quang bỏ chạy xa nhất bốn năm mươi dặm, tốc độ ngang Nguyên Anh Sơ Kỳ.","anchor":"tại độn thuật lại là Phong hỏa chi độn cực hiếm thấy"}]},"nguon":["@c0662"]},{"id":"bi-thuat-tang-toc-linh-cam","name":"Bí thuật tăng tốc linh cầm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Hạm Vân Chi"],"blurb":"Bí thuật phun quang châu cố định lên đầu linh cầm kết hợp pháp quyết, tăng tốc độ gấp rưỡi nhưng cực hao nguyên khí.","detail":"Hạm Vân Chi phun ra viên quang châu trong suốt, cố định lên đầu linh cầm bạch điểu rồi kết pháp quyết. Tốc độ độn thuật tăng gấp rưỡi nhưng rất hao tổn nguyên khí, khiến sắc mặt trắng bệch.","congNang":["Tăng tốc linh cầm gấp rưỡi"],"dacDiem":"Cực hao nguyên khí","nguoiTu":[{"ten":"Hạm Vân Chi","tuChuong":"@c0664","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0664","loai":"thi triển","importance":"normal","giaiDoan":"Hạm Vân Chi thi triển khi chạy trốn","text":"Hạm Vân Chi phun quang châu cố định lên đầu linh cầm, thi triển bí thuật tăng tốc gấp rưỡi nhưng cực hao nguyên khí, sắc mặt trắng bệch.","anchor":"một công pháp rất hao tổn nguyên khí"}]},"nguon":["@c0664"]},{"id":"cam-che-nhan-chu-tu-bao","name":"Cấm chế nhận chủ và cấm chế tự bạo","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Hai loại cấm chế mà tu sĩ sử dụng linh trùng hạ lên: cấm chế nhận chủ ràng buộc linh trùng với chủ nhân, cấm chế tự bạo khiến linh trùng tự hủy khi chủ chết.","detail":"Tu sĩ sử dụng linh trùng đều hạ hai cấm chế — nhận chủ (ràng buộc linh trùng) và tự bạo (linh trùng tự hủy khi chủ chết, nguyên thần tiêu tan). Chỉ khi chủ nhân tự giác loại bỏ cấm chế mới có thể truyền linh trùng cho người khác. Phệ Kim Trùng của Hàn Lập cũng đã được chủ cũ gỡ bỏ cấm chế này.","congNang":["Ràng buộc linh trùng với chủ nhân","Linh trùng tự hủy khi chủ chết, ngăn kẻ thù chiếm đoạt"],"tabs":{"tienTrinh":[{"chuong":"@c0664","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Giải thích cơ chế cấm chế linh trùng","text":"Giải thích cơ chế cấm chế nhận chủ và tự bạo trên linh trùng, lý do Hàn Lập không thể giết nữ tu để chiếm Lục Dực Sương Công.","anchor":"hễ là tu sĩ sử dụng linh trùng, vì sợ sau khi bị bỏ mình ngoài ý muốn, linh vật liền bị cừu gia lấy được"}]},"nguon":["@c0664"]},{"id":"ngu-hanh-linh-anh","name":"Ngũ Hành Linh Anh","cn":"五行灵婴","aliases":["Dung hợp Linh Anh đại pháp"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Đại bí thuật thần thông cổ","hePhai":"Ngự Linh Tông","soHuu":["Ngự Linh Tông"],"blurb":"Ngũ Hành Linh Anh là đại bí thuật thần thông cổ của Ngự Linh Tông, thất truyền nhiều năm và được khôi phục khi lão giả vô ý luyện ra Thổ Linh Anh. Bí pháp dung hợp năm Linh Anh (Kim, Mộc, Thủy, Hỏa, Thổ) vào đệ tử bổn môn, tạo tu sĩ có thần thông ngang Nguyên Anh Kỳ nhưng không có thọ mệnh Nguyên Anh.","detail":"Ngũ Hành Linh Anh là bí pháp cổ của Ngự Linh Tông, thất truyền đã lâu, được khôi phục một cách tình cờ khi lão giả vô ý luyện thành Thổ Linh Anh. Theo kế hoạch của Ngự Linh Tông, khi chuẩn bị đủ năm Linh Anh tương ứng ngũ hành — Kim, Mộc, Thủy, Hỏa, Thổ — sẽ lần lượt dung hợp vào năm đệ tử bổn môn, biến mỗi người thành tu sĩ sở hữu thần thông ngang Nguyên Anh Kỳ. Với năm tu sĩ cấp Nguyên Anh, Ngự Linh Tông đủ thực lực tranh đua vị trí đứng đầu ma đạo với Hợp Hoan Tông. Tuy nhiên, bí pháp này có hạn chế rõ rệt: đệ tử sau khi hợp thể tuy đạt thần thông Nguyên Anh nhưng không có thọ mệnh Nguyên Anh. Ngoài ra, trước khi tiến hành dung hợp, bắt buộc phải làm suy yếu tu vi của Linh Anh nhằm bảo vệ nguyên thần đệ tử. Trong năm Linh Anh, Mộc Linh Anh được ghi nhận là nếu dung hợp thành công, đệ tử","thuocTinh":"Ngũ Hành","nguonGoc":"Bí thuật cổ thất truyền của Ngự Linh Tông","yeuCau":"Phải có đủ năm Linh Anh, suy yếu tu vi Linh Anh trước khi dung hợp","uyLuc":"Tạo tu sĩ có thần thông ngang Nguyên Anh Kỳ; riêng Mộc Linh Anh có thể cho thần thông đạt Nguyên Anh Trung Kỳ.","dacDiem":"Đệ tử hợp thể có thần thông Nguyên Anh nhưng không có thọ mệnh Nguyên Anh; bắt buộc làm suy yếu tu vi Linh Anh trước khi dung hợp để bảo toàn nguyên thần đệ tử.","congNang":["Dung hợp Linh Anh vào thân thể đệ tử, khiến đệ tử sở hữu thần thông ngang Nguyên Anh Kỳ (@c0665)","Mộc Linh Anh dung hợp thành công có thể cho đệ tử thần thông đạt Nguyên Anh Trung Kỳ","Trước khi dung hợp cần làm suy yếu tu vi Linh Anh để bảo vệ nguyên thần đệ tử"],"trangThai":"Đang khôi phục, mất Mộc Linh Anh","capNhatToi":"@c0665","nguoiTu":[{"ten":"Ngự Linh Tông (toàn tông)","tuChuong":"@c0665","tangDatToi":"Chưa dung hợp","trangThai":"chuẩn bị"}],"tabs":{"tienTrinh":[{"chuong":"@c0665","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lộ bí mật toàn bộ kế hoạch","text":"Lão giả và trung niên nam tử tiết lộ bí pháp Ngũ Hành Linh Anh: đại bí thuật thất truyền, khôi phục nhờ luyện ra Thổ Linh Anh. Kế hoạch dung hợp năm Linh Anh vào đệ tử tạo năm tu sĩ thần thông Nguyên Anh Kỳ. Mộc Linh Anh đã bị mất, còn hai Linh Anh và một dự bị.","anchor":"Bí pháp Ngũ Hành Linh Anh này nguyên vốn là một đại bí thuật thần thông thất truyền nhiều năm"}]},"nguon":["@c0665"]},{"id":"suu-hon-thuat","name":"Sưu hồn thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Lão giả thạch thất Kỳ Linh Sơn","Bạch sam lão giả"],"blurb":"Thủ pháp thương tổn thần thức độc địa, dùng để tra hỏi đối tượng bằng cách tổn thương thần thức.","detail":"Bí thuật tra hỏi bằng cách tổn thương thần thức đối tượng. Lão giả thạch thất nhắc đến khi cân nhắc tra hỏi Hạm Vân Chi nhưng không dùng vì nể mặt Hạm sư đệ.","congNang":["Tra hỏi đối tượng bằng cách tổn thương thần thức","Tìm kiếm, trích xuất ký ức trong thần hồn đối phương"],"nguon":["@c0665","@c0702"],"tabs":{"tienTrinh":[{"chuong":"@c0702","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến lần đầu","text":"Lão giả họ Vân đề xuất dùng Sưu hồn thuật lên Nam Lũng Hầu để trích xuất tin tức về Trụy Ma Cốc.","anchor":"để ta dùng Sưu hồn thuật, xem một chút coi có lấy được tin tức gì hữu dụng hay không"}]},"nguoiTu":[{"ten":"Bạch sam lão giả","tuChuong":"@c0702","tangDatToi":"","trangThai":"dang-co"}]},{"id":"bi-thuat-cam-ung-trai-tim","name":"Bí thuật cảm ứng trái tim","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Trung niên nam tử mắt to mày rậm"],"blurb":"Bí thuật cảm ứng trạng thái tâm lý đối tượng, có thể phát hiện dối trá.","detail":"Trung niên nam tử dùng để kiểm tra Hạm Vân Chi khi nàng báo cáo, xác nhận nàng đại bộ phận nói thật nhưng đoạn chạy thoát có chút hỗn loạn, phỏng chừng giấu diếm.","congNang":["Cảm ứng trạng thái tâm lý đối tượng, phát hiện dối trá"],"nguon":["@c0665"]},{"id":"dung-hop-linh-anh-dai-phap","name":"Dung hợp Linh Anh đại pháp","cn":"","aliases":["Ngũ Hành Linh Anh"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Ngự Linh Tông"],"blurb":"Dung hợp Linh Anh đại pháp là bí thuật cổ truyền cốt lõi của Ngự Linh Tông, cho phép tu sĩ Kết Đan dung hợp năm loại Linh Anh thuộc tính khác nhau để thay thế Nguyên Anh, từ đó trực tiếp đạt tu vi và thần thông của Nguyên Anh Kỳ. Tuy nhiên, người dung hợp phải chịu khuyết điểm nghiêm trọng: thọ mệnh vẫn chỉ ở mức Kết Đan Kỳ, vĩnh viễn mất cơ hội ngưng kết Nguyên Anh thật sự, và tu vi đình trệ không thể tiến thêm.","detail":"Dung hợp Linh Anh đại pháp là bí thuật cổ xưa của Ngự Linh Tông, đóng vai trò then chốt trong chiến lược duy trì thực lực cấp Nguyên Anh Kỳ cho tông môn. Pháp thuật này cho phép tu sĩ Kết Đan dung hợp năm loại Linh Anh thuộc tính bất đồng (Kim, Mộc, Thủy, Hỏa, Thổ) để thay thế Nguyên Anh, nhờ đó có được tu vi cùng thần thông ngang hàng Nguyên Anh Kỳ tu sĩ mà không cần tự mình ngưng kết Nguyên Anh. Điều kiện luyện chế Linh Anh cực kỳ khắt khe: nguyên liệu vô cùng hiếm có, bắt buộc phải có trưởng lão sắp tọa hóa phối hợp — nguyên anh của vị trưởng lão ấy tán đi chính là điều kiện tiên quyết — và xác suất thành công cực thấp, mười mấy lần luyện mới may ra thành một. Tính đến thời điểm Liễu Ngọc tiết lộ bí mật này, Ngự Linh Tông trải bao đời tích lũy chỉ sở hữu sáu bảy viên Linh Anh, và đã tuy","thuocTinh":"Ngũ hành (cần đủ 5 thuộc tính)","nguonGoc":"Bí thuật cổ truyền của Ngự Linh Tông","yeuCau":"Tu sĩ Kết Đan tu luyện công pháp tương ứng thuộc tính; cần đủ 5 loại Linh Anh","uyLuc":"Trực tiếp đưa tu sĩ Kết Đan đạt tu vi và thần thông ngang hàng Nguyên Anh Kỳ mà không cần tự ngưng kết Nguyên Anh.","dacDiem":"Thọ mệnh sau dung hợp vẫn chỉ ở mức Kết Đan Kỳ, vĩnh viễn mất cơ hội kết Nguyên Anh thật sự, tu vi đình trệ không thể tiến thêm; điều kiện luyện chế Linh Anh cực khắt khe với xác suất thành công rất thấp.","congNang":["Dùng năm loại Linh Anh thuộc tính khác nhau (Kim, Mộc, Thủy, Hỏa, Thổ) thay thế Nguyên Anh, giúp tu sĩ Kết Đan trực tiếp đạt tu vi và thần thông Nguyên Anh Kỳ @c0666"],"nguoiTu":[],"trangThai":"Ngự Linh Tông đang chuẩn bị tuyển ứng viên dung hợp","capNhatToi":"@c0666","tabs":{"tienTrinh":[{"chuong":"@c0666","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Bí mật bị tiết lộ cho Hàn Lập","text":"Liễu Ngọc dưới áp lực thẩm vấn của Hàn Lập tiết lộ toàn bộ bí mật: Dung hợp Linh Anh đại pháp dùng 5 Linh Anh thay Nguyên Anh, giúp tu sĩ Kết Đan đạt tu vi Nguyên Anh Kỳ. Khuyết điểm: thọ mệnh vẫn Kết Đan, mất cơ hội kết Nguyên Anh thật.","anchor":"Không cần tự mình ngưng kết Nguyên Anh, liền có thể trực tiếp lấy Linh Anh thay thế Nguyên Anh, từ đó có được tu vi cùng thần thông của Nguyên Anh Kỳ"}]},"nguon":["@c0666"]},{"id":"bi-thuat-cam-ung-phuong-vi-moc-linh-anh","name":"Bí thuật cảm ứng phương vị Mộc Linh Anh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Liễu Ngọc"],"blurb":"Bí thuật đặc thù của Ngự Linh Tông, cần hai người cùng tu luyện, có thể cảm ứng phương vị Mộc Linh Anh từ xa, giới hạn ngoài mười mấy vạn dặm thì vô hiệu.","detail":"Bí thuật cảm ứng do Ngự Linh Tông truyền dạy, yêu cầu hai tu sĩ cùng tu luyện phối hợp mới có thể đại khái cảm ứng phương vị của Mộc Linh Anh từ cự ly xa. Khoảng cách hữu hiệu giới hạn trong mười mấy vạn dặm, vượt quá thì không thể cảm ứng. Liễu Ngọc và đồng môn sư tỷ là hai người đã tu luyện bí thuật này.","thuocTinh":"Cảm ứng","nguonGoc":"Ngự Linh Tông","yeuCau":"Hai người cùng tu luyện phối hợp","dacDiem":"Giới hạn mười mấy vạn dặm","congNang":["Cảm ứng phương vị Mộc Linh Anh từ cự ly xa, cần 2 người phối hợp @c0666"],"nguoiTu":[{"ten":"Liễu Ngọc","tuChuong":"@c0666","tangDatToi":"","trangThai":"dang-tu"}],"trangThai":"Đang sử dụng","capNhatToi":"@c0666","tabs":{"tienTrinh":[{"chuong":"@c0666","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Liễu Ngọc tiết lộ cho Hàn Lập","text":"Liễu Ngọc khai báo phương thức truy tìm: nàng cùng đồng môn sư tỷ tu luyện bí thuật cảm ứng phương vị Mộc Linh Anh từ xa, giới hạn mười mấy vạn dặm.","anchor":"cùng với một vị đồng môn sư tỷ khác tu luyện một loại bí thuật đặc thù, có thể đại khái cảm ứng được phương vị của Mộc Linh Anh từ cự ly xa"}]},"nguon":["@c0666"]},{"id":"trung-giap-thuat","name":"Trùng Giáp Thuật","cn":"虫甲术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Trùng Giáp Thuật là bí thuật phòng ngự phái sinh từ Khu Trùng Thuật của Ngự Linh Tông, sử dụng Phệ Kim Trùng ngưng tụ thành bảo giáp chiến giáp hoa văn ba màu trên thân người, cực kỳ chắc chắn. Hàn Lập luyện thành công sau khi nghiên cứu kết hợp Khu Trùng Thuật và Huyền Mẫu Hóa Anh Đại Pháp.","detail":"Trùng Giáp Thuật bắt nguồn từ phương pháp mà Ngự Linh Tông đã sớm nghiên cứu ra, nằm trong ngọc giản Khu Trùng Thuật do Liễu Mi cung cấp cho Hàn Lập. Hàn Lập kết hợp nghiên cứu Khu Trùng Thuật cùng Huyền Mẫu Hóa Anh Đại Pháp để luyện thành công thuật này. Khi thi triển, người dùng triệu hồi mấy ngàn con tam sắc Phệ Kim Trùng, phóng khói xanh bao trùm, sau đó dùng pháp ấn điều khiển đám trùng tụ lại trên thân, ngưng tụ thành bảo giáp chiến giáp có hoa văn ba màu. Bảo giáp thành hình thanh quang lóng lánh, bóng loáng, nhìn bề ngoài không ra dị thường, là lớp phòng ngự vật lý cực kỳ chắc chắn.","thuocTinh":"Không rõ","nguonGoc":"Khu Trùng Thuật của Ngự Linh Tông","congNang":["Ngưng tụ Phệ Kim Trùng thành bảo giáp phòng ngự trên thân, hoa văn ba màu, cực kỳ chắc chắn @c0668"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0668","tangDatToi":"Thành công lần đầu","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0668","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập luyện thành công lần đầu","text":"Hàn Lập nghiên cứu Khu Trùng Thuật cùng Huyền Mẫu Hóa Anh Đại Pháp, triệu hồi mấy ngàn con tam sắc Phệ Kim Trùng, dùng pháp ấn ngưng tụ thành bảo giáp chiến giáp ba màu trên thân, thanh quang lóng lánh cực kỳ chắc chắn.","anchor":"Trước kia tại Hư Thiên Điện thật không nghĩ tới dùng Phệ Kim Trùng ngưng tụ thành một bảo giáp"}]},"nguon":["@c0668"]},{"id":"quy-nhat-quyet","name":"Quy Nhất Quyết","cn":"归一诀","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Ma đạo","soHuu":[],"blurb":"Bí thuật phụ trong Huyền Mẫu Hóa Anh Đại Pháp, dùng đánh tan tâm ma, đồng hóa hai nguyên thần, ngăn hóa thân phản khách vi chủ.","detail":"Bí thuật nằm trong Huyền Mẫu Hóa Anh Đại Pháp. Tác dụng: đánh tan tâm ma, đồng hóa hai nguyên thần (chủ thể và hóa thân), tăng mạnh khống chế của chủ thể đối với hóa thân. Cần sử dụng định kỳ để ngăn hóa thân dần khác biệt trí nhớ, tình cảm dẫn tới hóa ma và cắn trả.","congNang":["Đánh tan tâm ma, đồng hóa hai nguyên thần","Tăng mạnh khống chế chủ thể đối với hóa thân","Ngăn hóa thân phản khách vi chủ"],"tabs":{"tienTrinh":[{"chuong":"@c0669","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hàn Lập phát hiện trong công pháp","text":"Hàn Lập phát hiện bí thuật Quy Nhất Quyết trong Huyền Mẫu Hóa Anh Đại Pháp, dùng định kỳ để đồng hóa hai nguyên thần chống hóa ma.","anchor":"Cách một đoạn thời gian sẽ dùng bí thuật “Quy Nhất Quyết” trong Huyền Mẫu Hóa Anh Đại Pháp đánh tan tâm ma"}]},"nguon":["@c0669"]},{"id":"thuong-nguyen-diet-quang-tran","name":"Thượng Nguyên Diệt Quang trận","cn":"上元灭光阵","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Liên minh chín nước","soHuu":["Liên minh chín nước"],"blurb":"Địa trận do liên minh chín nước mở ra trước khi khai đàn Giao dịch hội, đại bộ phận cấm chế đã triệu hồi, dùng bảo vệ khu vực tổ chức.","detail":"Liên minh chín nước mở địa trận này một hai tháng trước khi Giao dịch hội khai đàn. Đại bộ phận cấm chế trong trận đã được triệu hồi, có tác dụng bảo vệ toàn bộ khu vực thành tu sĩ nơi tổ chức Giao dịch hội.","congNang":["Bảo vệ khu vực Giao dịch hội tại tổng đàn liên minh chín nước","Phòng thủ thành trì, tạo linh quang bao phủ bầu trời ngăn chặn xâm nhập"],"tabs":{"tienTrinh":[{"chuong":"@c0670","loai":"xuất hiện","importance":"normal","giaiDoan":"Được kích hoạt trước Giao dịch hội","text":"Liên minh chín nước mở Thượng Nguyên Diệt Quang trận trước khi khai đàn, đại bộ phận cấm chế đã triệu hồi.","anchor":"liên minh chín nước đã mở ra một địa trận, là “Thượng Nguyên Diệt Quang trận”"},{"chuong":"@c0718","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt phòng thủ","text":"Điền Thiên Thành triệt hồi cấm chế trên không trung nhưng mở đại bộ phận Thượng Nguyên Diệt Quang Trận, bầu trời tràn ngập linh quang quỷ dị, đánh dấu trạng thái chiến tranh.","anchor":"mở ra đại bộ phận “Thượng Nguyên Diệt Quang Trận”"}]},"nguon":["@c0670","@c0718"]},{"id":"ngan-lang-quyet","name":"Ngân Lăng Quyết","cn":"银棱诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Thủy","soHuu":["Lữ Lạc"],"blurb":"Công pháp hệ thủy của Lữ Lạc, khắc chế Kết Đan Kỳ dễ dàng nhưng đấu đồng cấp Nguyên Anh bại nhiều hơn thắng. Có hai loại bảo hộ tính mạng, nhiều lần cứu mạng chủ nhân.","detail":"Ngân Lăng Quyết là công pháp hệ thủy, Lữ Lạc khiêm tốn gọi là bình thường. Đối phó Kết Đan Kỳ thì dễ dàng, nhưng đấu với đồng cấp Nguyên Anh Kỳ thì bại nhiều hơn thắng. Đặc biệt có hai loại bảo hộ tính mạng, nhiều lần cứu Lữ Lạc thoát chết — từng bị chính tà vây khốn mà chạy về Vân Mộng Sơn không chút tổn hại.","thuocTinh":"Thủy","uyLuc":"Khắc chế Kết Đan Kỳ, yếu thế trước đồng cấp Nguyên Anh Kỳ","dacDiem":"Có hai loại bảo hộ tính mạng đặc biệt","congNang":["Chiến đấu hệ thủy","Bảo hộ tính mạng (hai loại, chi tiết chưa rõ)"],"nguoiTu":[{"ten":"Lữ Lạc","tuChuong":"@c0671","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0671","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lữ Lạc tiết lộ đặc tính","text":"Lữ Lạc khiêm tốn nói Ngân Lăng Quyết chỉ là công pháp hệ thủy bình thường, tiết lộ có hai loại bảo hộ tính mạng cứu mạng nhiều lần.","anchor":"Ngân Lăng Quyết này chỉ là công pháp hệ thủy bình thường mà thôi"}]},"capNhatToi":"@c0671","nguon":["@c0671"]},{"id":"than-thuc-hoa-hinh","name":"Thần thức hóa hình","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Yêu cầu lý thuyết Nguyên Anh Trung Kỳ","hePhai":"","soHuu":["Hàn Lập","Nam Lũng Hầu"],"blurb":"Thần thông cô đọng thần thức thành hình thể hữu hình để tỷ đấu, theo lý thuyết chỉ tu sĩ Nguyên Anh Trung Kỳ với thần thức cường đại mới nắm giữ được. Hàn Lập ở Nguyên Anh Sơ Kỳ đã thi triển thần thông này trong trận tỷ thí với Nam Lũng Hầu, hai luồng thần thức va chạm tạo cuồng phong dữ dội quét bốn phương.","detail":"Thần thức hóa hình cho phép tu sĩ cô đọng thần thức thành bóng đen hữu hình, nhìn thấy được, dùng để tỷ đấu thần thức trực tiếp. Theo lý thuyết, chỉ tu sĩ Nguyên Anh Trung Kỳ trở lên với thần thức cường đại mới có thể nắm giữ thần thông này. Hàn Lập khi còn ở Nguyên Anh Sơ Kỳ đã thi triển được, khiến Lữ Lạc kinh ngạc và suy đoán công pháp chủ tu của Hàn Lập thiên về hướng thần thức. Trong trận tỷ thí với Nam Lũng Hầu, cả hai bên đều thi triển thần thức hóa hình, hai luồng thần thức cô đọng thành hình va chạm nhau tạo cuồng phong và sét đánh dữ dội (@c0673).","thuocTinh":"Thần thức","nguonGoc":"","yeuCau":"Thần thức cường đại, lý thuyết Nguyên Anh Trung Kỳ","uyLuc":"Cô đọng thần thức thành hình bóng hữu hình, hai luồng va chạm tạo cuồng phong dữ dội và sét đánh quét bốn phương.","dacDiem":"Bóng đen hữu hình do thần thức cô đọng tạo thành; hai luồng thần thức va chạm sinh gió lốc và sét đánh; lý thuyết yêu cầu tu sĩ Nguyên Anh Trung Kỳ trở lên mới thi triển được.","congNang":["Cô đọng thần thức thành hình thể hữu hình để tỷ đấu thần thức (@c0673)","Hai luồng thần thức hóa hình va chạm tạo cuồng phong dữ dội và sét đánh quét bốn phương (@c0673)"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0673","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Nam Lũng Hầu","tuChuong":"@c0673","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0673","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Hàn Lập và Nam Lũng Hầu thi triển thần thức hóa hình trong trận tỷ thí, hai luồng thần thức cô đọng thành hình va chạm tạo cuồng phong dữ dội. Lữ Lạc xác nhận đây là thần thông Nguyên Anh Trung Kỳ, Hàn Lập Sơ Kỳ thi triển được là dị thường.","anchor":"Thần thức hóa hình là thần thông do tu sĩ Nguyên Anh Trung Kỳ bằng vào thần thức cường đại mới có thể nắm giữ"}]},"capNhatToi":"@c0673","dinhDanh":"goc","nguon":["@c0673"]},{"id":"song-tu-bi-thuat-hop-hoan-tong","name":"Song tu bí thuật (Hợp Hoan Tông)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ma Môn Hợp Hoan Tông","soHuu":["Tu sĩ mập mạp (Phì Xá song ma — nam)","Nữ tu phong mãn (Phì Xá song ma — nữ)"],"blurb":"Bí thuật song tu của Phì Xá song ma thuộc Hợp Hoan Tông, cho phép hai người liên thủ chống lại tu sĩ Nguyên Anh Trung Kỳ dù bản thân chỉ ở Nguyên Anh Sơ Kỳ.","detail":"Bí thuật song tu đặc thù của Ma Môn Hợp Hoan Tông. Phì Xá song ma thông qua bí thuật này liên thủ, chiến lực vượt cấp, thậm chí có thể cùng chống lại tu sĩ Nguyên Anh Trung Kỳ.","congNang":["Liên thủ hai người tăng chiến lực vượt cấp, đối kháng Nguyên Anh Trung Kỳ"],"nguoiTu":[{"ten":"Tu sĩ mập mạp (Phì Xá song ma — nam)","tuChuong":"@c0675","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Nữ tu phong mãn (Phì Xá song ma — nữ)","tuChuong":"@c0675","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0675","loai":"nhắc tới","importance":"normal","giaiDoan":"Lữ Lạc cảnh báo Hàn Lập","text":"Lữ Lạc truyền âm cảnh báo Hàn Lập về Phì Xá song ma, cho biết hai người thông qua song tu bí thuật liên thủ có thể chống lại tu sĩ Nguyên Anh Trung Kỳ.","anchor":"Phì Xá song ma. Hai người này thông qua song tu bí thuật liên thủ, thậm chí có thể cùng chống lại tu sĩ Nguyên Anh Trung Kỳ"}]},"nguon":["@c0675"]},{"id":"tinh-quang-cong","name":"Tinh quang công","cn":"星光功","loai":"cong-phap","loaiLabel":"Công pháp","soHuu":["Thiên Tinh Chân Nhân"],"blurb":"Công pháp chính mà Thiên Tinh Chân Nhân tu luyện, được Lão Cúc Hợp Hoan Tông nhắc đến khi hỏi đùa về chuyện cải tu Khôi Lỗi Thuật.","detail":"Công pháp tu luyện của Thiên Tinh Chân Nhân. Lão Cúc hỏi đùa liệu Thiên Tinh Chân Nhân có buông bỏ Tinh quang công để cải tu Khôi Lỗi Thuật không, cho thấy đây là công pháp gốc mà lão tu luyện từ đầu.","nguoiTu":[{"ten":"Thiên Tinh Chân Nhân","tuChuong":"@c0677","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0677","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc tại trao đổi hội","text":"Lão Cúc Hợp Hoan Tông hỏi đùa Thiên Tinh Chân Nhân có buông bỏ Tinh quang công để cải tu Khôi Lỗi Thuật không, xác nhận đây là công pháp chính của lão.","anchor":"Chẳng lẽ Tinh quang công mà lúc đầu tu luyện định buông tha sao"}]},"nguon":["@c0677"]},{"id":"che-phu-thuat","name":"Chế phù thuật","cn":"制符术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không cố định (tùy cấp bậc chế phù sư)","hePhai":"Không giới hạn","soHuu":[],"blurb":"Kỹ năng luyện chế phù lục, cần bút chế phù chuyên dụng và nguyên liệu tương ứng; chế phù sư Kết Đan kỳ cực hiếm, Nguyên Anh kỳ chuyên chế phù thì không có.","detail":"Hệ thống kỹ năng luyện chế phù lục trong tu tiên giới. Chế phù sư phần lớn chỉ ở Trúc Cơ kỳ; tại Thiên Nam, chế phù sư đạt Kết Đan kỳ cả tu tiên giới cũng chỉ có mấy người, còn Nguyên Anh kỳ chuyên chế phù thì hoàn toàn không tồn tại. Tu sĩ Nguyên Anh chỉ kiêm tu một hai loại phù hữu dụng cho bản thân. Chế phù cần bút chế phù chuyên dụng chứa linh khí đặc thù; nếu pháp lực không đủ mà dùng bút cao cấp sẽ tăng tỷ lệ thất bại. Phù lục cao cấp do Kết Đan kỳ chế tạo, so với đỉnh cấp pháp khí tại tu tiên giới có khi còn quý hơn ba phần.","nguon":["@c0678"]},{"id":"ngu-hanh-phap-thuat-cao-cap","name":"Ngũ hành pháp thuật cao cấp","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"Cao cấp (trên pháp thuật thường)","hePhai":"Ngũ hành","soHuu":["Hàn Lập"],"blurb":"Nhóm pháp thuật ngũ hành cao cấp, uy lực cường đại đến mức tu sĩ Nguyên Anh Kỳ cũng kiêng dè, nhưng tu luyện và thi triển vô cùng phiền phức.","detail":"Tu sĩ Kết Đan trở lên hầu hết bỏ tu vì uy lực không bằng pháp bảo khi thi triển, thời gian quá lâu. Hàn Lập sau khi ngưng tụ Nguyên Anh đã lĩnh ngộ ba bốn loại nhưng tốc độ thi triển quá chậm, không dùng được trong đấu pháp. Nếu phối hợp phù lục cao cấp (ném hai ba mươi cùng lúc) thì tương đương mười mấy Nguyên Anh tấn công, nhưng mỗi lần hao mấy vạn linh thạch.","congNang":["Công kích ngũ hành cao cấp, một số đủ khiến tu sĩ Nguyên Anh Kỳ kiêng dè"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0679","tangDatToi":"Đã lĩnh ngộ 3-4 loại, thi triển quá chậm","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0679","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Hàn Lập suy tư về hạn chế","text":"Hàn Lập sau khi ngưng tụ Nguyên Anh lĩnh ngộ ba bốn loại pháp thuật cao cấp nhưng tốc độ thi triển quá chậm, không thể dùng trong đấu pháp. Nhận định đại bộ phận tu sĩ Kết Đan bỏ tu pháp thuật vì uy lực không bằng pháp bảo.","anchor":"uy lực của đại bộ phận pháp thuật cao cấp, còn không bằng uy lực cường đại của việc sử dụng pháp bảo"}]},"nguon":["@c0679"]},{"id":"phap-thuat-tuc-thi-mac-lan","name":"Pháp thuật tức thì của pháp sĩ Mạc Lan","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật đặc thù","phamCap":"Cực cao","hePhai":"","soHuu":["Mạc Lan"],"blurb":"Thành quả nghiên cứu đột phá của pháp sĩ Mạc Lan, cho phép thi triển pháp thuật nháy mắt với đại uy lực, khiến liên minh các thế lực Thiên Nam cũng chỉ tự bảo vệ.","detail":"Mạc Lan đột phá cực hạn pháp thuật, nghiên cứu ra cách thi triển tức thì đại uy lực. Pháp sĩ cấp thấp không cần pháp khí cũng đánh ngang tu sĩ thường, pháp sĩ cao cấp phối hợp pháp bảo như hổ thêm cánh.","congNang":["Thi triển pháp thuật nháy mắt với đại uy lực","Pháp sĩ cấp thấp không cần pháp khí đánh ngang tu sĩ thường"],"nguoiTu":[{"ten":"Mạc Lan","tuChuong":"@c0679","tangDatToi":"Đột phá cực hạn","trangThai":"thanh-cong"}],"tabs":{"tienTrinh":[{"chuong":"@c0679","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Hàn Lập nhớ lại thành tựu Mạc Lan","text":"Hàn Lập nhớ lại rằng pháp sĩ Mạc Lan đã đột phá cực hạn thi triển pháp thuật, nghiên cứu ra cách trong nháy mắt thi triển đại uy lực, khiến các thế lực lớn Thiên Nam liên thủ cũng chỉ tự bảo vệ.","anchor":"Nghiên cứu ra không ít thứ có thể trong nháy mắt thi triển ra đại uy lực"}]},"nguon":["@c0679"]},{"id":"tho-don-phap","name":"Thổ Độn pháp","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông độn thuật hệ thổ, cho phép hai người biến mất trên mặt đất với tốc độ cực nhanh khiến tu sĩ xung quanh kinh hãi.","detail":"Hàn Lập thi triển thổ độn thuật đưa Tôn Hỏa biến mất tại chỗ, hoàng quang chớp động rồi cả hai biến mất trên mặt đất. Tu sĩ xung quanh chưa từng thấy thổ độn thần diệu đến vậy.","congNang":["Cho phép di chuyển dưới lòng đất, hai người biến mất trên mặt đất với tốc độ cực nhanh"],"tabs":{"tienTrinh":[{"chuong":"@c0680","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập dùng tại Điền Thiên Thành","text":"Hàn Lập dùng thổ độn thuật đưa Tôn Hỏa biến mất tại chỗ, tu sĩ xung quanh kinh hãi vì chưa từng thấy thổ độn thần diệu đến vậy.","anchor":"hoàng quang chớp động, thân hình hai người trên mặt đất bỗng biến mất không thấy"}]},"nguon":["@c0680"]},{"id":"thuong-co-khoi-loi-thuat","name":"Thượng cổ khôi lỗi thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật luyện chế","phamCap":"Thượng cổ","hePhai":"","soHuu":["Thiên Tinh Chân Nhân"],"blurb":"Thượng cổ khôi lỗi thuật là thuật luyện chế khôi lỗi thú có nguồn gốc từ thời thượng cổ, được Thiên Tinh Chân Nhân cùng bằng hữu phát hiện trong di vật của cổ tu sĩ. Khôi lỗi thú được tạo ra bằng thuật này sở hữu uy lực vô cùng lợi hại, song đòi hỏi tài liệu trân quý và hồn thạch — loại nguyên liệu cốt lõi cực kỳ khó kiếm.","detail":"Thượng cổ khôi lỗi thuật là một bí thuật luyện chế khôi lỗi thú lưu truyền từ thời thượng cổ. Thiên Tinh Chân Nhân cùng vài vị bằng hữu đã phát hiện thuật này từ di vật của một thượng cổ tu sĩ. Khôi lỗi thú được luyện thành theo thuật này có uy lực vô cùng lợi hại, tuy nhiên quá trình luyện chế yêu cầu tài liệu vô cùng trân quý, trong đó nguyên liệu cốt lõi là hồn thạch — thứ rất khó tìm kiếm. Hàn Lập đã dùng hồn thạch làm điều kiện đàm phán để được xem nội dung thuật này.","thuocTinh":"Luyện chế khôi lỗi","nguonGoc":"Di vật thượng cổ tu sĩ, Thiên Tinh Chân Nhân cùng bằng hữu phát hiện","yeuCau":"Hồn thạch + tài liệu trân quý","uyLuc":"Khôi lỗi thú được tạo ra bằng thuật này có uy lực vô cùng lợi hại.","dacDiem":"Thuật có từ thời thượng cổ, tài liệu luyện chế vô cùng trân quý, nguyên liệu cốt lõi là hồn thạch — thứ cực kỳ khó kiếm.","congNang":["Luyện chế khôi lỗi thú có uy lực vô cùng lợi hại @c0681"],"nguoiTu":[{"ten":"Thiên Tinh Chân Nhân","tuChuong":"@c0681","tangDatToi":"","trangThai":"dang-nghien-cuu"}],"tabs":{"tienTrinh":[{"chuong":"@c0681","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện qua đàm phán Hàn Lập – Thiên Tinh Chân Nhân","text":"Thiên Tinh Chân Nhân xác nhận cùng bằng hữu phát hiện thuật luyện chế khôi lỗi thượng cổ từ di vật cổ tu sĩ. Hàn Lập hé lộ từng tìm hài cốt khôi lỗi thú trong động phủ, đàm phán bằng hồn thạch để xem thuật.","anchor":"phát hiện ra một ít thuật luyện chế khôi lỗi thời thượng cổ"}]},"dinhDanh":"goc","nguon":["@c0681"]},{"id":"bi-thuat-lien-thu-hop-nhat-than-thuc","name":"Bí thuật liên thủ hợp nhất thần thức","loai":"bi-thuat","loaiLabel":"Bí thuật","soHuu":["Vương Thiền","Yến Như Yên"],"blurb":"Bí thuật cho phép hai người liên thủ hợp nhất thần thức, trong khoảng thời gian ngắn đạt sức mạnh thần thức ngang Nguyên Anh Kỳ dù bản thân chỉ ở Kết Đan Hậu Kỳ.","detail":"Vương Thiền và Yến Như Yên tinh thông bí thuật này. Khi liên thủ, hai thần thức Kết Đan Hậu Kỳ được hợp nhất, sức mạnh thần thức trong khoảng thời gian ngắn không kém Nguyên Anh Kỳ. Đây là lý do Nam Lũng Hầu mời hai vãn bối này tham gia mật hội dù chỉ ở Kết Đan.","congNang":["Hợp nhất thần thức hai người, đạt sức mạnh thần thức ngang Nguyên Anh Kỳ trong thời gian ngắn"],"nguoiTu":[{"ten":"Vương Thiền","tuChuong":"@c0683","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Yến Như Yên","tuChuong":"@c0683","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0683","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến tại mật hội","text":"Nam Lũng Hầu giải thích hai vãn bối Quỷ Linh Môn (Vương Thiền và Yến Như Yên) tinh thông bí thuật liên thủ hợp nhất thần thức, khi liên thủ sức mạnh thần thức không kém Nguyên Anh Kỳ.","anchor":"một khi liên thủ thì có thể hợp nhất hai thần thức lại với nhau trong khoảng thời gian cũng không kém gì với ta đâu"}]},"nguon":["@c0683"]},{"id":"thai-dieu-than-cam","name":"Thái Diệu Thần Cấm","cn":"","loai":"bi-thuat","loaiLabel":"Thượng cổ cấm chế / Pháp trận","phamCap":"Thượng cổ thất truyền (thập đại thượng cổ cấm chế)","hePhai":"","soHuu":["Thương Khôn Thượng Nhân"],"blurb":"Thái Diệu Thần Cấm là một trong thập đại thượng cổ cấm chế đã thất truyền, được bố trí bảo vệ bên ngoài động phủ Thương Khôn Thượng Nhân tại vòng ngoài Mộ Lan thảo nguyên. Nam Lũng Hầu và Bạch sam lão giả công kích liên tục mấy tháng liền vẫn không thể phá vỡ, cho thấy sức phòng ngự vượt xa tầm thần thông thông thường.","detail":"Thái Diệu Thần Cấm là pháp trận thượng cổ thuộc hàng thập đại cấm chế đã thất truyền, được dùng làm lớp phòng hộ bên ngoài động phủ Thương Khôn Thượng Nhân nằm ở vòng ngoài Mộ Lan thảo nguyên. Khi Nam Lũng Hầu và Bạch sam lão giả phát hiện động phủ này, hai người đã dốc sức công kích cấm chế suốt mấy tháng liền nhưng hoàn toàn bất lực. Sau quá trình nghiên cứu, họ nhận ra Thái Diệu Thần Cấm miễn nhiễm trước các công kích thần thông thông thường; muốn giải trừ nó cần phải có tám vị tu sĩ sở hữu thần thức cường đại đồng thời vận dụng thần thức biến hoá thần thông, ước tính trong điều kiện đó khoảng một ngày mới có thể phá được.","congNang":["Tạo cấm chế phòng hộ cực kỳ kiên cố bảo vệ bên ngoài động phủ @c0684","Miễn nhiễm trước các công kích thần thông thông thường; chỉ có thể phá giải bằng tám vị tu sĩ thần thức cường đại đồng thời vận dụng thần thức biến hoá thần thông @c0684"],"tabs":{"tienTrinh":[{"chuong":"@c0684","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện và nghiên cứu","text":"Nam Lũng Hầu và Bạch sam lão giả tìm được động phủ Thương Khôn Thượng Nhân ở vòng ngoài Mộ Lan thảo nguyên nhưng bên ngoài có Thái Diệu Thần Cấm — thượng cổ pháp trận thất truyền. Hai người công kích mấy tháng không phá nổi. Sau nghiên cứu xác định cần tám tu sĩ thần thức cường đại phá giải. Vương Thiên Cổ nhận ra đây thuộc thập đại thượng cổ cấm chế.","anchor":"phát hiện ra pháp trận này tạo ra cấm chế đúng là một loại thượng cổ pháp trận đã bị thất truyền"}]},"capNhatToi":"@c0684","nguon":["@c0684"],"uyLuc":"Nam Lũng Hầu và Bạch sam lão giả liên tục công kích suốt mấy tháng liền vẫn không thể phá vỡ cấm chế.","dacDiem":"Thuộc hàng thập đại thượng cổ cấm chế đã thất truyền; hoàn toàn bất khả xâm phạm bởi thần thông thông thường, yêu cầu điều kiện phá giải đặc thù là tám thần thức cường đại đồng thời biến hoá thần thông."},{"id":"huyet-linh","name":"Huyết Linh","cn":"血灵","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Vương Thiền","Yến Như Yên"],"blurb":"Công pháp tà thuật do vợ chồng Vương Thiền tu luyện, uy lực cao thâm. Khi đột phá tầng thứ bảy, người tu sẽ tương đương kết thành Nguyên Anh.","detail":"Vương Thiên Cổ đánh giá uy lực Huyết Linh cao thâm, tiết lộ khi đột phá tới tầng thứ bảy thì vợ chồng Vương Thiền tương đương như người kết thành Nguyên Anh. Vợ chồng Vương Thiền hiện chưa đạt tầng 7.","congNang":["Khi đột phá tầng 7, người tu tương đương kết thành Nguyên Anh"],"cacTang":[{"ten":"Tầng 7","moTa":"Tương đương Nguyên Anh, vợ chồng Vương Thiền sắp đột phá","chuong":"@c0685"}],"nguoiTu":[{"ten":"Vương Thiền","tuChuong":"@c0685","tangDatToi":"Dưới tầng 7","trangThai":"dang-tu"},{"ten":"Yến Như Yên","tuChuong":"@c0685","tangDatToi":"Dưới tầng 7","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0685","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hé lộ tầng 7 tương đương Nguyên Anh","text":"Vương Thiên Cổ tiết lộ Huyết Linh khi đột phá tầng thứ bảy sẽ khiến người tu tương đương kết thành Nguyên Anh, vợ chồng Vương Thiền sắp đạt mốc này.","anchor":"Huyết Linh sau khi đột phá tới tầng thứ bảy thì hai người các ngươi cũng tương đương như người kết thành nguyên anh"}]},"dinhDanh":"goc","nguon":["@c0685"]},{"id":"phong-linh-thuat-hong-tran-van-truong","name":"Phong Linh Thuật — Hồng Trần Vạn Trượng","cn":"風靈術 — 紅塵萬丈","loai":"linh-thuat","loaiLabel":"Linh thuật","phamCap":"Không rõ","hePhai":"Người Mộ Lan","soHuu":["Người Mộ Lan"],"blurb":"Phong Linh Thuật — Hồng Trần Vạn Trượng là linh thuật bản địa đặc trưng của pháp sĩ Người Mộ Lan, tạo bão cát vàng quy mô cực lớn ngăn cản thần thức tu sĩ dò xét, đồng thời dùng cuồng phong cát vàng hộ thân và vây khốn địch nhân. Tại trận chiến ghi nhận, đội tiên phong Người Mộ Lan đã thi triển linh thuật này với quy mô gấp trăm ngàn lần bình thường, khiến Nam Lũng Hầu nhận ra đây chính là chiêu thức từng được sử dụng khi đấu pháp với hắn trước đây.","detail":"Phong Linh Thuật — Hồng Trần Vạn Trượng là linh thuật bản địa của Người Mộ Lan, tạo ra hoàng phong (bão cát vàng) bao phủ diện tích cực lớn. Khi thần thức tu sĩ xâm nhập vào vùng bão cát, chỉ có thể cảm ứng được hơn mười trượng trước mặt rồi bị sương mù che phủ hoàn toàn, mất khả năng thăm dò. Cuồng phong cát vàng vừa có tác dụng hộ thân cho caster vừa vây khốn đối phương. Bên trong bão cát ẩn tàng nhiều phong trụ, cho phép pháp sĩ Người Mộ Lan di chuyển mà không bị phát hiện. Trong trận giao chiến được ghi nhận (@c0686), đội tiên phong Người Mộ Lan thi triển linh thuật này với quy mô mở rộng gấp trăm ngàn lần so với bình thường, bao hàm khu vực chiến trường rộng lớn. Nam Lũng Hầu nhận ra đây là chiêu thức Hồng Trần Vạn Trượng mà Người Mộ Lan từng dùng khi đấu pháp với hắn trước đây.","thuocTinh":"Phong","nguonGoc":"Linh thuật bản địa của Người Mộ Lan","congNang":["Tạo bão cát vàng (hoàng phong) bao phủ diện tích cực lớn, ngăn cản thần thức tu sĩ dò xét — thần thức xâm nhập chỉ cảm ứng được hơn mười trượng trước khi bị sương mù che phủ (@c0686)","Cuồng phong cát vàng hộ thân cho pháp sĩ, đồng thời vây khốn địch nhân (@c0686)","Bên trong bão cát ẩn tàng nhiều phong trụ, cho phép pháp sĩ di chuyển ẩn mình mà không bị phát hiện (@c0686)"],"tabs":{"tienTrinh":[{"chuong":"@c0686","loai":"thi triển","importance":"major","giaiDoan":"Đội tiên phong Mộ Lan thi triển quy mô cực lớn","text":"Đội tiên phong Người Mộ Lan thi triển Phong Linh Thuật Hồng Trần Vạn Trượng với quy mô gấp trăm ngàn lần bình thường, tạo bão cát cao hơn trăm trượng bao phủ diện tích cực lớn, bên trong ẩn tàng nhiều pháp sĩ.","anchor":"Phong Linh Thuật của người Mộ Lan! Trước kia khi cùng ta đấu pháp đã thi triển loại linh thuật “Hồng Trần Vạn Trượng” này"}]},"nguon":["@c0686"],"uyLuc":"Khi đội tiên phong Người Mộ Lan thi triển với quy mô gấp trăm ngàn lần bình thường, bão cát bao phủ vùng chiến trường rộng lớn, hoàn toàn phong tỏa thần thức dò xét của đối phương (@c0686).","dacDiem":"Linh thuật mang đặc tính phong-sa kết hợp, vừa phòng ngự (chặn thần thức, hộ thân) vừa tấn công (vây khốn); có thể mở rộng quy mô cấp số nhân khi nhiều pháp sĩ Người Mộ Lan đồng thời thi triển."},{"id":"ao-tran-cat-vang","name":"Ảo trận cát vàng","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Mộ Lan — Hoàng Sa Bộ","soHuu":["Hoàng Sa Bộ"],"blurb":"Cấm chế ảo trận do pháp sĩ Mộ Lan Hoàng Sa Bộ bố trí vội vã để vây khốn nhóm tu sĩ. Uy lực yếu, bị nhóm Nguyên Anh xé rách dễ dàng như bạc chỉ bàn.","detail":"Trận pháp vây khốn, cấm chế khu vực bão cát. Do bố trí vội nên uy lực cực yếu so với nhóm tu sĩ Nguyên Anh, bị phá hủy dễ dàng.","congNang":["Vây khốn, cấm chế khu vực bão cát"],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"thi triển","importance":"normal","giaiDoan":"Bị phá hủy","text":"Hoàng Sa Bộ bố trí vội vã vây nhóm tu sĩ Hàn Lập. Nhóm Nguyên Anh hợp lực tấn công, cấm chế bị xé rách dễ dàng như bạc chỉ bàn.","anchor":"cấm chế này giống như bạc chỉ bàn bị mọi người công kích dễ dàng bị xé rách nát bấy"}]},"nguon":["@c0687"]},{"id":"minh-thanh-linh-muc","name":"Minh Thanh Linh Mục","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông mắt nhờ rửa bằng Minh Thanh Linh Thủy nhiều lần, truyền linh lực vào mắt để nhìn xuyên bão cát, kết giới che mắt, phát hiện kẻ ẩn thân.","detail":"Hàn Lập truyền linh lực vào mắt thi triển thần thông, nhìn xuyên bão cát trong Hoàng Sa Phong Trận, phát hiện vòng tròn bóng đen đường kính hơn mười trượng chứa mấy người ẩn thân giám sát. Rót thêm linh lực thì bóng đen chia rõ ra nhưng đó là cực hạn, không thấy hoàn toàn rõ chi tiết bên trong. Mắt thường không thấy gì.","congNang":["Nhìn xuyên bão cát, kết giới che mắt, phát hiện kẻ ẩn thân"],"dacDiem":"Có cực hạn — rót thêm linh lực vẫn không thấy hoàn toàn rõ chi tiết bên trong","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0688","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0688","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển thực chiến","text":"Hàn Lập truyền linh lực vào mắt thi triển Minh Thanh Linh Mục trong Hoàng Sa Phong Trận, nhìn xuyên bão cát phát hiện vòng tròn bóng đen chứa mấy người ẩn thân giám sát có pháp lực vượt Nguyên Anh.","anchor":"Minh Thanh Linh Mục kia thần thông ra sao"}]},"nguon":["@c0688"]},{"id":"don-tho-thuat","name":"Độn thổ thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Hán tử da ngăm đen"],"blurb":"Bí thuật trốn chạy bằng cách chui vào lòng đất biến mất.","detail":"Hán tử da ngăm đen toàn thân toát hoàng linh hỏa, thi triển độn thổ thuật chui vào lòng đất không còn bóng dáng để chạy trốn khi bị Ngự Phong Xa truy đuổi.","nguon":["@c0688"]},{"id":"trung-giap-phe-kim-trung","name":"Trùng giáp Phệ Kim Trùng","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trùng giáp Phệ Kim Trùng là cách thức vận dụng Tam Sắc Phệ Kim Trùng kết thành giáp trùng bọc toàn thân để phòng hộ, lần đầu được Hàn Lập thi triển khi nghênh chiến Mục lão quái. Giáp trùng trong suốt, phát ra thanh quang nhàn nhạt.","detail":"Khi đối đầu Mục lão quái, Hàn Lập thả Tam Sắc Phệ Kim Trùng từ túi linh thú, dùng pháp quyết khiến trùng vân hạ xuống bọc lấy toàn thân, kết thành một lớp giáp trùng trong suốt phát thanh quang nhàn nhạt. Đây là phương thức phòng hộ hoàn toàn mới mà Hàn Lập lần đầu sử dụng, tận dụng đặc tính của Phệ Kim Trùng để hình thành lớp phòng ngự bao phủ toàn thân. @c0689","congNang":["Kết giáp trùng bọc toàn thân, hình thành lớp phòng hộ trong suốt phát thanh quang nhàn nhạt @c0689"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0689","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0689","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Hàn Lập lần đầu dùng Tam Sắc Phệ Kim Trùng kết thành giáp trùng bọc toàn thân phòng hộ khi nghênh chiến Mục lão giả trên Mộ Lan thảo nguyên.","anchor":"tam sắc trùng hiện thành giáp trùng trên người Hàn Lập, trong suốt cổ phát, thanh quang lóe lên nhàn nhạt"}]},"nguon":["@c0689"],"dacDiem":"Giáp trùng trong suốt, phát thanh quang nhàn nhạt, được kết từ Tam Sắc Phệ Kim Trùng bọc toàn thân."},{"id":"bang-tinh-thuat","name":"Băng Tinh Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Pháp sĩ","soHuu":["Mục lão giả"],"blurb":"Băng Tinh Thuật là linh thuật riêng của hệ thống pháp sĩ, kết thủ ấn phóng pháp quyết biến linh quang lam sắc thành vô số băng tinh huyền tinh hàn khí cỡ nắm tay bao phủ phạm vi hơn mười trượng bắn tới đối thủ. Thuật này sắc bén và kỳ hàn hơn hẳn Băng Vũ Thuật của tu sĩ ngũ hành thông thường, có thể đóng băng và nghiền nát cả hộ thân pháp bảo.","detail":"Băng Tinh Thuật thuộc hệ thống linh thuật của pháp sĩ, khác biệt với thuật pháp của tu sĩ thông thường. Thay vì vận dụng linh lực ngũ hành, thuật này dựa trên huyền tinh hàn khí do tự thân tu luyện mà thành. Khi thi triển, pháp sĩ kết thủ ấn phóng pháp quyết, linh quang lam sắc co rút rồi bạo liệt vỡ ra thành vô số băng tinh sắc bén bao phủ phạm vi rộng lớn. Tuy hình thức tương tự Băng Vũ Thuật của tu sĩ ngũ hành, bản chất huyền tinh hàn khí khiến uy lực vượt trội hơn nhiều. Trong truyện, Mạc lão giả đã thi triển thuật này nhưng bị hoa lam cổ bảo và trùng tráo Phệ Kim Trùng của Hàn Lập hóa giải hoàn toàn (@c0690).","thuocTinh":"Băng","nguonGoc":"Linh thuật riêng của hệ thống pháp sĩ, khác thuật pháp tu sĩ thông thường","uyLuc":"Sắc bén và kỳ hàn hơn Băng Vũ Thuật của tu sĩ ngũ hành, có thể đóng băng và nghiền nát cả hộ thân pháp bảo.","dacDiem":"Dùng huyền tinh hàn khí tự thân tu luyện thay vì linh lực ngũ hành thông thường; linh quang lam sắc co rút rồi bạo liệt vỡ ra thành vô số băng tinh cỡ nắm tay.","congNang":["Phóng vô số băng tinh huyền tinh hàn khí sắc bén bao phủ phạm vi hơn mười trượng, bắn tới đối thủ (@c0690)","Đóng băng và nghiền nát hộ thân pháp bảo của đối phương (@c0690)"],"nguoiTu":[{"ten":"Mục lão giả","tuChuong":"@c0690","tangDatToi":"Thuần thục","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0690","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển trong trận đấu với Hàn Lập","text":"Mạc lão giả kết thủ ấn phóng pháp quyết, linh quang lam sắc co rút rồi bạo liệt vỡ ra thành vô số băng tinh cỡ nắm tay trải rộng hơn mười trượng, bắn tới Hàn Lập. Bị hoa lam cổ bảo hút thu và trùng tráo Phệ Kim Trùng cản lại hoàn toàn.","anchor":"chính là bị đạo hữu dùng vật ấy phá vỡ"}]},"nguon":["@c0690"]},{"id":"loi-don-chi-thuat","name":"Lôi Độn Chi Thuật","cn":"雷遁之术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi thuộc tính","soHuu":["Mục lão giả"],"blurb":"Thuật lôi độn thuần túy, tốc độ truy đuổi tầm xa vượt trội hơn Phong Lôi Sí.","detail":"Mục lão giả dùng Lôi Độn Chi Thuật (hóa lam mang) để Nguyên Anh thoát thân sau khi thân xác bị hủy. Hàn Lập thừa nhận Phong Lôi Sí không bằng Lôi Độn Chi Thuật thuần túy trong việc truy đuổi tầm xa.","congNang":["Lôi độn di chuyển tốc độ cực cao, ưu thế truy đuổi tầm xa"],"nguon":["@c0691"],"tabs":{"tienTrinh":[{"chuong":"@c0691","loai":"thi triển","importance":"normal","giaiDoan":"Nguyên Anh Mục lão giả thoát thân","text":"Nguyên Anh Mục lão giả hóa lam mang dùng Lôi Độn Chi Thuật chạy trốn cực nhanh sau khi thân xác bị đóng băng hủy diệt. Hàn Lập thừa nhận Phong Lôi Sí không bằng thuật này về truy đuổi.","anchor":"Dù hắn có thần thông của Phong Lôi Sí, cũng không thể bằng Lôi Độn Chi Thuật"}]}},{"id":"tinh-bang-thuan","name":"Tinh Băng Thuẫn","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Băng thuộc tính","soHuu":["Mục lão giả"],"blurb":"Băng thuẫn hộ thể thông linh tự động, có thể đóng băng vật thể tiếp xúc.","detail":"Linh quang lam ly thể hóa thành băng thuẫn bay khắp tứ phía bao bọc, thông linh tự động hộ chủ. Đóng băng được Thanh Minh Châm khi tiếp xúc biến thành băng châm rơi xuống, nhưng không chống nổi Kiền Lam Băng Diễm.","congNang":["Tự động hộ thể","Đóng băng vật thể tiếp xúc"],"nguon":["@c0691"],"tabs":{"tienTrinh":[{"chuong":"@c0691","loai":"thi triển","importance":"normal","giaiDoan":"Mục lão giả hộ thể chống Hàn Lập","text":"Băng thuẫn lơ lửng quanh thân Mục lão giả, thông linh tự động hộ chủ, đóng băng được Thanh Minh Châm nhưng không chống nổi Kiền Lam Băng Diễm.","anchor":"băng thuẫn lơ lửng quang thân, thông linh tự động hộ chủ, bạch quang tự động che trước mặt lão già"}]}},{"id":"bi-phap-don-thuat-quy-linh-mon","name":"Bí pháp độn thuật Quỷ Linh Môn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Quỷ Linh Môn","soHuu":["Vương Thiên Cổ","Vương Thiền"],"blurb":"Bí pháp độn thuật của Quỷ Linh Môn, cần liên thủ nhiều người thi triển để tăng tốc độ thoát thân vượt trội.","detail":"Vương Thiên Cổ cùng hai vãn bối liên thủ thi triển bí pháp này để bỏ xa pháp sĩ Mộ Lan truy đuổi. Yêu cầu ba người phối hợp, tốc độ độn thuật vượt xa bình thường.","nguoiTu":[{"ten":"Vương Thiên Cổ","tuChuong":"@c0692","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0692","loai":"thi triển","importance":"normal","giaiDoan":"Liên thủ ba người thoát truy đuổi","text":"Vương Thiên Cổ cùng hai vãn bối liên thủ thi triển bí pháp độn thuật môn phái để bỏ xa pháp sĩ Mộ Lan đuổi theo.","anchor":"Ta cùng hai vị vãn bối liên thủ thi triển bí pháp độn thuật của môn phái"}]},"nguon":["@c0692"]},{"id":"thanh-truc-bach-luyen-hoa","name":"Thanh Trúc Bách Luyện Hỏa","cn":"青竹百炼火","aliases":["Sợi tơ lửa xanh"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hỏa","soHuu":["Hàn Lập"],"blurb":"Thanh Trúc Bách Luyện Hỏa là một thần thông hỏa hệ, phun ra từ miệng dưới dạng sợi tơ lửa màu xanh cực nhỏ, sở hữu xuyên phá lực vượt trội có thể xuyên thủng hộ thể quang tráo của đối phương.","detail":"Thanh Trúc Bách Luyện Hỏa được Hàn Lập thi triển trong chiến đấu, há miệng phun ra sợi tơ lửa màu xanh nhỏ như sợi tơ. Dù hình thái cực nhỏ, ngọn lửa này có xuyên phá lực rất mạnh, xuyên thủng bạch quang tráo hộ thân của tu sĩ họ Vưu mà không gặp trở ngại, bắn thẳng trúng người đối phương. Thuộc loại thần thông hỏa hệ, đặc trưng ở dạng tơ lửa tinh tế nhưng uy lực tập trung, chuyên khắc chế phòng ngự hộ thể.","congNang":["Phun từ miệng dạng sợi tơ lửa xanh, xuyên thủng hộ thể quang tráo của đối phương @c0699"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0699","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0699","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Hàn Lập há miệng phun sợi tơ lửa xanh xuyên thủng bạch quang tráo hộ thân tu sĩ họ Vưu, bắn trúng người đối phương.","anchor":"sợi tơ không hề trở ngại xuyên thùng bạch quang tráo bắn thẳng đến trên người tên tu sĩ họ Vưu"}]},"nguon":["@c0699"],"uyLuc":"Sợi tơ lửa xanh xuyên thủng bạch quang tráo hộ thân của tu sĩ họ Vưu mà không hề gặp trở ngại, bắn trúng trực tiếp vào người đối phương @c0699","dacDiem":"Hình thái cực nhỏ như sợi tơ, màu xanh, phun ra từ miệng; tuy nhỏ nhưng xuyên phá lực tập trung cực mạnh, chuyên phá hộ thể phòng ngự"},{"id":"van-xich-nhat-tuyen","name":"Vạn Xích Nhất Tuyến","cn":"万尺一线","loai":"bi-thuat","loaiLabel":"Bí thuật / Độn thuật","phamCap":"","hePhai":"","soHuu":["Thương Khôn Thượng Nhân","Nam Lũng Hầu"],"blurb":"Vạn Xích Nhất Tuyến là bí thuật tự tạo của Thương Khôn Thượng Nhân, có khả năng biến độn quang thành tuyến tơ tằm cực nhỏ và thu liễm hoàn toàn khí tức khiến thần thức không thể truy tung. Đại giá thi triển cực lớn, tiêu hao phần lớn nguyên khí cùng lượng lớn tinh huyết, khiến người dùng có thể mất cảnh giới vĩnh viễn.","detail":"Vạn Xích Nhất Tuyến là bí thuật do Thương Khôn Thượng Nhân tự sáng tạo, chuyên dùng cho tình huống đào thoát tuyệt cảnh. Khi thi triển, thuật này trong nháy mắt biến độn quang thành một tuyến tơ tằm cực nhỏ, đồng thời thu liễm hoàn toàn khí tức của người dùng, khiến đối phương không thể nào cảm ứng hay truy tung bằng thần thức. Nam Lũng Hầu đã thi triển bí thuật này tại Hư Thiên điện khi đào thoát, biến kim hồng độn quang thành sợi tơ tằm cực nhỏ để thoát thân. Tuy nhiên đại giá phải trả vô cùng khốc liệt: tiêu hao phần lớn nguyên khí và lượng lớn tinh huyết, không thể duy trì được lâu, và sau khi thi triển, Nam Lũng Hầu bị đánh giá là dù trăm năm cũng không giữ nổi cảnh giới Nguyên Anh Trung Kỳ.","nguon":["@c0701"],"nguonGoc":"Bí thuật tự tạo của Thương Khôn Thượng Nhân","thuocTinh":"","uyLuc":"Thu liễm hoàn toàn khí tức, vô pháp truy tung bằng thần thức, ngay cả trong tình huống bị bao vây tại Hư Thiên điện vẫn có thể đào thoát thành công.","dacDiem":"Đại giá cực lớn: tốn phần lớn nguyên khí và lượng lớn tinh huyết, không duy trì được lâu; sau khi thi triển, người dùng có thể suy thoái cảnh giới nghiêm trọng, dù trăm năm cũng không phục hồi nổi.","congNang":["Biến độn quang thành tuyến tơ tằm cực nhỏ, tốc độ đào thoát cực nhanh @c0701","Thu liễm hoàn toàn khí tức, khiến thần thức không thể cảm ứng hay truy tung @c0701"],"nguoiTu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0701","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0701","loai":"thi triển","importance":"major","giaiDoan":"Nam Lũng Hầu thi triển đào thoát","text":"Nam Lũng Hầu thi triển Vạn Xích Nhất Tuyến khi đào thoát khỏi Hư Thiên điện, biến kim hồng thành tơ tằm cực nhỏ thu liễm khí tức biến mất, trả giá bằng phần lớn nguyên khí và tinh huyết.","anchor":"Đem độn quang hóa thành tuyến tơ tằm cực nhỏ khí tức thu liễm hoàn toàn, làm cho người ta không thể nào truy tung"}]}},{"id":"don-thuat-ngan-nguyet-lang-toc","name":"Độn thuật Ngân Nguyệt Lang Tộc","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngân Nguyệt Lang Tộc","soHuu":["Ngân Nguyệt"],"blurb":"Độn thuật ẩn thân đặc hữu của Ngân Nguyệt Lang Tộc, thần diệu nhưng cần vật che dấu linh khí hỗ trợ mới qua mắt được thần thức tu sĩ Nguyên Anh.","detail":"Ngân Nguyệt sử dụng độn thuật này để ẩn thân lấy hộp ngọc ở Cổ Bảo tầng hai. Bản thân độn thuật rất thần diệu trong việc che dấu hình thể, nhưng không che dấu được linh khí — cần kết hợp với hộp ngọc có tính năng che dấu linh khí mới có thể qua mắt thần thức các tu sĩ Nguyên Anh cấp.","congNang":["Ẩn thân che dấu hình thể, cần vật hỗ trợ che linh khí để qua mắt Nguyên Anh @c0703"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0703","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0703","loai":"thi triển","importance":"normal","giaiDoan":"Sử dụng lấy hộp ngọc Cổ Bảo","text":"Ngân Nguyệt dùng độn thuật Lang Tộc ẩn thân lấy ba hộp ngọc ở Cổ Bảo tầng hai, kết hợp tính năng che linh khí của hộp ngọc để qua mắt thần thức tu sĩ Nguyên Anh.","anchor":"Ngân Nguyệt Lang Tộc độn thuật mặc dù thần diệu, nhưng chính yếu là do hộp ngọc này có thể che dấu linh khí"}]},"nguon":["@c0703"]},{"id":"vong-nguyet-quyet","name":"Vọng Nguyệt quyết","cn":"望月诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Thương Khôn Thượng Nhân"],"blurb":"Công pháp thần thông của Thương Khôn Thượng Nhân ghi trong ngọc giản. Hàn Lập không thể tu luyện nhưng có vài bí thuật và kinh nghiệm tu luyện đáng tham khảo.","detail":"Ghi chép trong ngọc giản của Thương Khôn Thượng Nhân, bao gồm công pháp chính cùng một số bí thuật và kinh nghiệm tu luyện phụ trợ. Hàn Lập không phù hợp tu luyện công pháp chính nhưng đánh giá bí thuật kèm theo có giá trị tham khảo.","nguonGoc":"Thương Khôn Thượng Nhân sáng tạo hoặc truyền thừa","trangThai":"ton-tai","nguoiTu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"@c0704","tangDatToi":"","trangThai":"da-mat"}],"tabs":{"tienTrinh":[{"chuong":"@c0704","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập phát hiện trong ngọc giản","text":"Hàn Lập xem ngọc giản chiến lợi phẩm, phát hiện chứa công pháp Vọng Nguyệt quyết của Thương Khôn Thượng Nhân. Không tu luyện được nhưng tham khảo bí thuật và kinh nghiệm.","anchor":"công pháp Vọng Nguyệt quyết trong đó ta không có cách nào tu luyện được"}]},"nguon":["@c0704"]},{"id":"cau-linh-thuat","name":"Câu Linh thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Pháp sĩ","soHuu":["Pháp sĩ họ Đàm"],"blurb":"Linh thuật pháp sĩ, dùng đạn hoàn bắn xuống đất triệu hoán Câu Linh Thổ Long bằng thổ thạch, linh khí đến từ đạn hoàn trên trán thổ long.","detail":"Pháp sĩ bắn đạn hoàn vàng xuống mặt đất, hô khẩu quyết, triệu hoán hai con cầu long màu vàng dài vài chục trượng từ dưới đất bay ra. Thổ long hoàn toàn do thổ thạch hình thành nhưng sống động như vật sống, linh khí đến từ đạn hoàn nằm trên trán. Bị Hàn Lập dùng Kiềm Lam Băng Diễm đông cứng rồi kiếm khí kích nát dễ dàng.","congNang":["Triệu hoán thổ long từ đất đá, cần đạn hoàn làm linh hạch"],"nguoiTu":[{"ten":"Pháp sĩ họ Đàm","tuChuong":"@c0705","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0705","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Pháp sĩ họ Đàm triệu hoán hai con Câu Linh Thổ Long bằng đạn hoàn vàng, bị Hàn Lập phá hủy dễ dàng bằng Kiềm Lam Băng Diễm và kiếm khí.","anchor":"hai con cầu long màu vàng dài vài chục trượng chui từ dưới mặt đất bay ra"}]},"nguon":["@c0705"]},{"id":"mong-dan-thuat","name":"Mộng Dẫn thuật","cn":"梦引术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kỹ thuật moi ký ức/thông tin từ người bị khống chế, phối hợp cùng huyễn thuật để tăng hiệu quả.","detail":"Hàn Lập dùng Mộng Dẫn thuật phối hợp cùng huyễn thuật của Ngân Nguyệt để moi hết thông tin ký ức từ ba đệ tử Yểm Nguyệt Tông đã bị đánh ngất. Có thể khai thác được ký ức chi tiết về nội bộ tông môn.","congNang":["Moi ký ức/thông tin từ người bị khống chế, phối hợp huyễn thuật tăng hiệu quả"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0709","tangDatToi":"","trangThai":"thành thục"}],"tabs":{"tienTrinh":[{"chuong":"@c0709","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Hàn Lập phối hợp Mộng Dẫn thuật cùng huyễn thuật của Ngân Nguyệt moi hết thông tin ký ức ba đệ tử Yểm Nguyệt Tông.","anchor":"phối hợp cùng với Mộng Dẫn thuật của ta để moi hết ra những thông tin đi"}]},"nguon":["@c0709"]},{"id":"khon-tam-thuat","name":"Khốn Tâm Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Yểm Nguyệt Tông","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"blurb":"Khốn Tâm Thuật là pháp thuật cấm chế do đại trưởng lão Yểm Nguyệt Tông sử dụng máu huyết bản thân để hạ chú, mấu chốt nằm ở một khối lệnh bài. Trong phạm vi trăm dặm, người hạ chú có thể khống chế đối tượng bị trúng thuật, mức độ khống chế phụ thuộc vào chênh lệch tu vi giữa hai bên.","detail":"Khốn Tâm Thuật được tiết lộ qua lời Nam Cung Uyển tại @c0712, khi nàng cho biết mình bị đại trưởng lão sư tỷ hạ thuật này bằng máu huyết. Pháp thuật vận hành dựa trên một khối lệnh bài làm mấu chốt; chừng nào lệnh bài chưa bị phá hủy, người hạ chú có thể khống chế nạn nhân trong phạm vi trăm dặm. Khi chênh lệch tu vi giữa người hạ chú và nạn nhân không lớn, thuật chỉ khống chế được động tác đơn giản, không thể sử dụng pháp lực của nạn nhân. Thuật này dự kiến được dùng trong đại điển nhằm ép buộc đối tượng.","congNang":["Khống chế đối tượng bị hạ chú trong phạm vi trăm dặm, mức độ tùy chênh lệch tu vi giữa người hạ chú và nạn nhân @c0712","Khi chênh lệch tu vi không lớn, chỉ khống chế được động tác đơn giản, không thể sử dụng pháp lực của nạn nhân @c0712"],"nguoiTu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0712","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0712","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Nam Cung Uyển tiết lộ bị đại trưởng lão sư tỷ hạ Khốn Tâm Thuật bằng máu huyết, mấu chốt ở lệnh bài, khống chế trong trăm dặm. Hàn Lập nhận lời đi lấy lệnh bài.","anchor":"Khốn Tâm Thuật mà vị sư tỷ kia hạ là thật sự khó phá giải"}]},"nguon":["@c0712"],"dacDiem":"Sử dụng máu huyết của chính người hạ chú để thi triển, mấu chốt cốt lõi nằm ở một khối lệnh bài; nếu lệnh bài chưa bị phá hủy thì thuật vẫn còn hiệu lực."},{"id":"thai-am-bo-duong-thuat","name":"Thuật Thái Âm Bổ Dương","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật / Tà thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Ngụy Ly Thần"],"blurb":"Tà thuật mà Ngụy Ly Thần lén tu luyện, ám chỉ ý đồ xấu khi cầu hôn Nam Cung Uyển.","detail":"Ngụy Ly Thần lén lút tu luyện thuật Thái Âm Bổ Dương, thể hiện bản chất ngụy quân tử và ý đồ không trong sáng khi theo đuổi Nam Cung Uyển.","nguon":["@c0712"]},{"id":"tran-ky-tran-ban","name":"Trận kỳ trận bàn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Kết Đan cấp","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bộ trận kỳ trận bàn Hàn Lập luyện từ thời Kết Đan Kỳ, có thể tập trung uy lực trong phạm vi hẹp và ngụy trang bí mật, nhưng uy lực không đủ đối phó tu sĩ Nguyên Anh Kỳ, chỉ có tác dụng phụ trợ.","detail":"Hàn Lập lấy trận kỳ trận bàn bố trí khắp đại sảnh động phủ Nam Cung Uyển, khống chế uy lực trong phạm vi hẹp và ngụy trang phi thường bí mật, khó phát hiện nếu không dùng thần thức tìm kỹ. Tự nhận thức đây là trận pháp luyện từ thời Kết Đan, uy lực chỉ đủ phụ trợ chứ không đủ đối phó Nguyên Anh Kỳ.","congNang":["Tập trung uy lực trận pháp trong phạm vi hẹp","Ngụy trang bí mật, khó phát hiện"],"tabs":{"tienTrinh":[{"chuong":"@c0713","loai":"dùng","importance":"normal","giaiDoan":"Bố trí phục kích sư tỷ Yểm Nguyệt Tông","text":"Hàn Lập bố trí trận kỳ trận bàn khắp đại sảnh để phục kích sư tỷ Nguyên Anh trung kỳ, tập trung uy lực trong phạm vi hẹp và ngụy trang bí mật.","anchor":"Trận kỳ trận bàn này đều là khi Hàn Lập đang có tu vi Kết Đan Kỳ luyện thành"}]},"nguon":["@c0713"]},{"id":"phap-tran-cam-che-dai-sanh","name":"Pháp trận cấm chế đại sảnh","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp cấm chế do Hàn Lập bố trí sẵn trong đại sảnh thính đường động phủ Nam Cung Uyển, kích hoạt bằng hai đạo pháp quyết xanh đỏ đánh vào hai cột trụ để khốn đại trưởng lão.","detail":"Hàn Lập đã chuẩn bị trước pháp trận cấm chế trong đại sảnh. Khi đại trưởng lão niệm chú cố phát động cấm chế lệnh bài, Hàn Lập bắn hai đạo pháp quyết một xanh một đỏ vào hai cột trụ gần đó, kích hoạt trận pháp phối hợp với Kinh Long chung tạo thế bao vây.","congNang":["Khốn/cấm chế đối phương trong phạm vi đại sảnh"],"tabs":{"tienTrinh":[{"chuong":"@c0714","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu kích hoạt","text":"Hàn Lập bắn hai đạo pháp quyết xanh đỏ vào hai cột trụ, kích hoạt pháp trận cấm chế đã bố trí sẵn trong đại sảnh để khốn đại trưởng lão Yểm Nguyệt Tông.","anchor":"Hai đạo pháp quyết một xanh một đỏ phân biệt đánh vào hai cột trụ ở gần đó"}]},"nguon":["@c0714"]},{"id":"luan-hoi-than-quang","name":"Luân Hồi Thần Quang","cn":"轮回神光","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấp cao","hePhai":"","soHuu":["Nam Cung Uyển"],"blurb":"Luân Hồi Thần Quang là thần thông cấp cao của Nam Cung Uyển, khi thi triển hiện vầng sáng đỏ đậm lớn trên đỉnh đầu như phật quang lưu chuyển, uy lực đủ khiến tu sĩ Nguyên Anh kỳ kiêng dè nhưng đi kèm đại giá cho chính người vận dụng.","detail":"Nam Cung Uyển niệm chú thi triển Luân Hồi Thần Quang, trên đỉnh đầu hiện ra vầng sáng đỏ đậm lớn lưu chuyển. Sư tỷ của nàng — Đại trưởng lão Yểm Nguyệt Tông — chứng kiến liền biến sắc kinh hãi, gọi đây là hành động liều mạng, cho thấy thần thông này tuy uy lực cấp cao song đòi hỏi đại giá hoặc tiềm ẩn nguy hiểm nghiêm trọng đối với chính người thi triển. @c0715","nguoiTu":[{"ten":"Nam Cung Uyển","tuChuong":"@c0715","tangDatToi":"","trangThai":"thi triển"}],"congNang":["Khi thi triển, hiện vầng sáng đỏ đậm lớn trên đỉnh đầu như phật quang lưu chuyển @c0715","Uy lực cấp cao, đủ khiến tu sĩ Nguyên Anh kỳ kiêng dè @c0715"],"dacDiem":"Có đại giá cho người dùng, bị coi là hành động liều mạng khi vận dụng; cần niệm chú để thi triển.","tabs":{"tienTrinh":[{"chuong":"@c0715","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Nam Cung Uyển niệm chú thi triển Luân Hồi Thần Quang, hiện vầng sáng đỏ đậm trên đỉnh đầu khiến sư tỷ biến sắc kinh hãi.","anchor":"Luân Hồi Thần Quang! Nam Cung sư muội, ngươi thật muốn liều mạng sao? Dám vận dụng thần thông này?"}]},"nguon":["@c0715"],"uyLuc":"Uy lực đủ khiến tu sĩ Nguyên Anh kỳ phải kiêng dè, sư tỷ cảnh giới cao biến sắc khi chứng kiến."},{"id":"hoa-kiem-vi-ti","name":"Hóa kiếm vi ti","cn":"化劍為絲","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"Kiếm tu","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"blurb":"Kiếm thuật biến phi kiếm thành hàng ngàn sợi tơ bạc bén nhọn tấn công diện rộng, đủ sức chém rơi Phệ Kim Trùng nhiều lần.","detail":"Băng lãnh nữ tử phun ra tiểu kiếm bạc rồi bắt quyết, kiếm hóa thành ngàn đạo hào quang nhỏ như tơ bén nhọn liên tục chém đối thủ. Hàn Lập nhận ra đây là kỹ thuật đặc trưng của kiếm tu.","congNang":["Biến phi kiếm thành ngàn sợi tơ bạc bén nhọn tấn công diện rộng"],"nguoiTu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0716","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0716","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Băng lãnh nữ tử phun ra tiểu kiếm bạc, thi triển Hóa kiếm vi ti hóa thành ngàn sợi tơ bạc bén nhọn chém rơi Phệ Kim Trùng nhiều lần. Hàn Lập nhận ra đây là kỹ thuật kiếm tu.","anchor":"Hóa kiếm vi ti! Hàn Lập nhướng mày lẩm bẩm"}]},"nguon":["@c0716"]},{"id":"an-bi-cam-che-trong-phu","name":"Ẩn bí cấm chế trong phủ","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế / Trận pháp","phamCap":"Không rõ","hePhai":"Yểm Nguyệt Tông","soHuu":["Nam Cung Uyển"],"blurb":"Cấm chế ẩn bí được bố trí sẵn trong đại sảnh động phủ Nam Cung Uyển, kích hoạt bằng chú ngữ, tạo hồng quang mạc phong tỏa toàn sảnh.","detail":"Nam Cung Uyển dùng chú ngữ kích hoạt, hồng quang mạc xuất hiện trên tường, đỉnh và nền đại sảnh. Quang mạc có tính khắc chế hoàng quang, hút và bao vây đối phương. Bị hắc bạch kiếm khí phá vỡ nhưng đã tạm chặn được tu sĩ Nguyên Anh trung kỳ.","congNang":["Hồng quang mạc phong tỏa toàn sảnh, khắc chế hoàng quang, bao vây đối phương"],"nguon":["@c0717"]},{"id":"bac-cuc-nguyen-quang","name":"Bắc Cực nguyên quang","cn":"北極元光","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Năng lực phòng ngự kết hợp với Lưỡng Nghi hoàn, có thể che chở tối đa ba người xuyên qua khe nứt không gian Trụy Ma Cốc.","detail":"Tuyền Ki Tử giải thích uy lực Lưỡng Nghi hoàn kết hợp Bắc Cực nguyên quang chỉ có thể che chở tối đa ba người, thêm một cũng không được.","congNang":["Kết hợp Lưỡng Nghi hoàn che chở tối đa 3 người vào Trụy Ma Cốc"],"tabs":{"tienTrinh":[{"chuong":"@c0724","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hé lộ giới hạn uy lực","text":"Tuyền Ki Tử giải thích Lưỡng Nghi hoàn kết hợp Bắc Cực nguyên quang chỉ che chở tối đa ba người, thêm một cũng không được.","anchor":"uy lực của nó nhiều lắm cũng chỉ có thể che chở ba người mà thôi"}]},"nguon":["@c0724"]},{"id":"lam-sac-han-diem","name":"Lam sắc hàn diễm","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Băng thuộc tính","soHuu":["Hàn Lập"],"blurb":"Hàn diễm màu lam của Hàn Lập, có thể ngưng kết pháp thể tu sĩ Nguyên Anh kỳ trong nháy mắt, được kỳ vọng khắc chế Thiên Lân Yêu Hỏa của Hỏa Thiềm cổ thú.","detail":"Nam Lũng Hầu nhắc lại ấn tượng lam sắc hàn diễm có thể ngưng kết pháp thể tu sĩ Nguyên Anh kỳ, cho rằng có thể khắc chế Hỏa Thiềm cổ thú sở hữu Thiên Lân Yêu Hỏa.","congNang":["Ngưng kết pháp thể tu sĩ Nguyên Anh kỳ trong nháy mắt","Có thể khắc chế hỏa thuộc tính (Thiên Lân Yêu Hỏa)"],"tabs":{"tienTrinh":[{"chuong":"@c0724","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc như lý do cần Hàn Lập","text":"Nam Lũng Hầu cho rằng lam sắc hàn diễm có thể khắc chế Hỏa Thiềm cổ thú sở hữu Thiên Lân Yêu Hỏa trong Trụy Ma Cốc.","anchor":"thi triển ra lam sắc hàn diễm, có thể trong nháy mắt ngưng kết pháp thể tu sĩ Nguyên Anh kỳ"}]},"nguon":["@c0724"]},{"id":"thien-lan-yeu-hoa","name":"Thiên Lân Yêu Hỏa","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hỏa thuộc tính","soHuu":["Hỏa Thiềm cổ thú"],"blurb":"Yêu hỏa bẩm sinh của Hỏa Thiềm cổ thú trong Trụy Ma Cốc, mạnh hơn anh hỏa của tu sĩ Nguyên Anh kỳ.","detail":"Yêu hỏa bẩm sinh của loài Hỏa Thiềm cổ thú sống vạn năm trong Trụy Ma Cốc. So với anh hỏa của tu sĩ Nguyên Anh kỳ thì lợi hại hơn nhiều. Thương Khôn Thượng Nhân từng giao thủ sơ đã thua và bị hỏa độc suýt chết.","congNang":["Hỏa lực mạnh hơn anh hỏa tu sĩ Nguyên Anh kỳ","Hỏa độc nguy hiểm, khiến Thương Khôn Thượng Nhân suýt chết"],"tabs":{"tienTrinh":[{"chuong":"@c0724","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lần đầu hé lộ thông tin","text":"Nam Lũng Hầu và Tuyền Ki Tử tiết lộ Hỏa Thiềm cổ thú sở hữu Thiên Lân Yêu Hỏa mạnh hơn anh hỏa Nguyên Anh, Thương Khôn Thượng Nhân từng giao thủ đã thua.","anchor":"yêu hỏa của nó so với anh hỏa của tu sĩ Nguyên Anh chúng ta thì lợi hại hơn nhiều"}]},"nguon":["@c0724"]},{"id":"cam-che-dai-tran-bien-gioi","name":"Cấm chế đại trận","loai":"khac","loaiLabel":"Trận pháp phòng thủ","soHuu":["Cửu Quốc Minh"],"blurb":"Trận pháp phòng thủ do Cửu Quốc Minh bố trí tại hơn mười nơi trọng yếu dọc biên giới, dùng để trì hoãn thế công đại quân pháp sĩ Mộ Lan.","detail":"Dựa vào địa lợi, tổn hao vô số tâm huyết bố trí. Pháp sĩ Mộ Lan phải thanh trừ sạch các nơi có cấm chế đại trận mới coi như chiếm giữ được. Mỗi nơi cần tu sĩ Nguyên Anh tọa trấn.","congNang":["Phòng thủ trì hoãn thế công đại quân"],"tabs":{"tienTrinh":[{"chuong":"@c0725","loai":"xuất hiện","importance":"normal","giaiDoan":"Đang vận hành tại biên giới","text":"Cửu Quốc Minh bố trí cấm chế đại trận tại hơn mười nơi trọng yếu dọc biên giới, dựa vào địa lợi trì hoãn thế công pháp sĩ Mộ Lan. Hàn Lập cùng hai tu sĩ Nguyên Anh được phái tới trấn thủ một trong các nơi đó.","anchor":"dựa vào địa lợi, tổn hao vô số tâm huyết bố trí đại trận cấm chế, trì hoãn thế công của đại quân pháp sĩ một chút"}]},"nguon":["@c0725"]},{"id":"thien-phong-huyen-ba-tran","name":"Thiên phong huyền ba trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Bặc Đà Tử"],"blurb":"Thiên phong huyền ba trận là trận pháp phòng thủ quy mô lớn được Bặc Đà Tử vận hành nhằm ngăn chặn đội pháp sĩ Mộ Lan xâm nhập. Trận pháp này đã bị phá vỡ, khiến Bặc Đà Tử bị thương nặng.","detail":"Thiên phong huyền ba trận xuất hiện trong trận chiến giữa phe Bặc Đà Tử và đội pháp sĩ Mộ Lan. Bặc Đà Tử dùng trận pháp này làm tuyến phòng ngự chính để chặn đường xâm nhập của đối phương. Tuy nhiên, trận pháp cuối cùng bị phá vỡ, bản thân Bặc Đà Tử cũng chịu thương tổn nặng nề trong quá trình vận hành trận.","congNang":["Ngăn chặn đội pháp sĩ xâm nhập, dùng làm trận pháp phòng thủ quy mô lớn @c0726"],"tabs":{"tienTrinh":[{"chuong":"@c0726","loai":"xuất hiện","importance":"major","giaiDoan":"Bị phá","text":"Bặc Đà Tử dùng trận này chặn pháp sĩ Mộ Lan nhưng trận bị phá, bản thân bị thương nặng.","anchor":"Thiên phong huyền ba trận chẳng lẽ đã bị phá?"}]},"trangThai":"da-pha","capNhatToi":"@c0726","nguon":["@c0726"]},{"id":"dai-tran-luc-sac-vu-hai","name":"Đại trận lục sắc vụ hải Hoàng Long Sơn","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế đại trận","phamCap":"","hePhai":"","soHuu":["Đại hán họ Lục"],"blurb":"Cấm chế đại trận phòng thủ bao phủ hơn mười dặm quanh Hoàng Long Sơn, biểu hiện là lục sắc vụ hải quỷ dị dày đặc.","detail":"Trận pháp phòng thủ quy mô lớn tại Hoàng Long Sơn, kích hoạt bằng chuông xanh. Tạo ra lục sắc vụ hải bao trùm phạm vi hơn mười dặm, có thể mở thông đạo cho người ra vào. Ba Nguyên Anh viện quân đánh giá trận này trước khi vào.","congNang":["Phòng thủ đại bản doanh, tạo lục sắc vụ hải dày đặc bao trùm hơn mười dặm","Có thể mở thông đạo cho người ra vào"],"tabs":{"tienTrinh":[{"chuong":"@c0726","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt","text":"Đại hán họ Lục gõ chuông xanh kích hoạt đại trận, lục sắc vụ hải bao phủ hơn mười dặm quanh Hoàng Long Sơn.","anchor":"bốn phía Hoàng Long Sơn tràn ngập nồng đậm lục sắc quái vụ, đem phương viên trong phạm vi hơn mười dặm hóa thành quỷ dị bích lục vụ hải"}]},"trangThai":"dang-hoat-dong","capNhatToi":"@c0726","nguon":["@c0726"]},{"id":"tu-la-cuc-hoa","name":"Tử La cực hỏa","cn":"","aliases":["Tử La thiên hỏa"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hỏa hệ / Hàn hệ","soHuu":["Hàn Lập"],"blurb":"Tử La cực hỏa là ma diễm tím do Hàn Lập luyện hóa từ Kiềm Lam Băng Diễm kết hợp hàn khí của Lục Dực Sương Công, uy lực hơn Kiềm Lam Băng Diễm một bậc. Đây là đòn sát thủ lớn nhất hiện tại của Hàn Lập, tuy nhiên số lượng còn rất ít, chưa đủ để đối đầu chính diện tu sĩ Nguyên Anh Hậu Kỳ.","detail":"Hàn Lập mỗi lần luyện hóa một tia Kiềm Lam Băng Diễm thì lập tức chuyển hóa thành ma diễm tím cỡ quả trứng gà, được đặt tên Tử La cực hỏa để phân biệt với Tu La Thánh Hỏa. Uy lực của Tử La cực hỏa đã mạnh gấp ba so với ban đầu theo nhận xét của Ngân Nguyệt, và còn nhiều tiềm lực khai thác. Dù Nguyên Anh Hậu Kỳ tu sĩ bị dính cũng không tiêu thụ nổi, nhưng do số lượng hiện rất ít nên chưa đủ sức đối đầu chính diện đối thủ cảnh giới này.","thuocTinh":"Hỏa hệ ma diễm (phái sinh từ hàn khí + dị hỏa)","nguonGoc":"Luyện từ Kiềm Lam Băng Diễm kết hợp Lục Dực Sương Công hàn khí","uyLuc":"Hơn Kiềm Lam Băng Diễm một bậc, uy lực đã mạnh gấp ba so với ban đầu; Nguyên Anh Hậu Kỳ tu sĩ bị dính cũng không tiêu thụ nổi.","dacDiem":"Ngọn lửa tím cỡ quả trứng gà, số lượng rất ít, được luyện hóa từ Kiềm Lam Băng Diễm kết hợp hàn khí của Lục Dực Sương Công.","congNang":["Ma diễm có thể khiến tu sĩ Nguyên Anh Hậu Kỳ bị dính không tiêu thụ nổi @c0728"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0728","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0728","loai":"xuat-hien","importance":"major","giaiDoan":"Luyện thành lần đầu","text":"Hàn Lập dùng Kiềm Lam Băng Diễm kết hợp Lục Dực Sương Công phun hàn khí luyện hóa thành ma diễm tím, đặt tên Tử La cực hỏa. Uy lực hơn Kiềm Lam Băng Diễm một bậc, là đòn sát thủ lớn nhất hiện tại. Ngân Nguyệt nhận xét uy lực đã mạnh gấp ba so với lúc mới gặp.","anchor":"Hàn Lập dùng Kiềm Lam Băng Diễm cùng Lục Dực Sương Công phun ra hàn khí mà tu luyện thành ma diễm"}]},"capNhatToi":"@c0728","nguon":["@c0728"]},{"id":"hao-nhien-chinh-khi-quyet","name":"Hạo Nhiên Chính Khí quyết","cn":"浩然正气诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Hạo Nhiên Các","soHuu":["Lão giả họ Mã"],"blurb":"Công pháp chính truyền Hạo Nhiên Các, thủy hỏa bất xâm, có tác dụng khắc tà ích quỷ, không bị ma hỏa công tâm.","detail":"Thi triển khi bạch quang nhu hòa hộ thể. Tác dụng thủy hỏa bất xâm, khắc tà ích quỷ. Ưu điểm đặc biệt là không bị ma hỏa công tâm. Tuy nhiên không khắc chế được thiên địa linh hỏa tam vị chân đế.","thuocTinh":"Chính khí","uyLuc":"Thủy hỏa bất xâm, khắc tà ích quỷ, không bị ma hỏa công tâm, nhưng không khắc chế linh hỏa tam vị chân đế","dacDiem":"Bạch quang nhu hòa hộ thể","congNang":["Thủy hỏa bất xâm","Khắc tà ích quỷ","Không bị ma hỏa công tâm"],"nguoiTu":[{"ten":"Lão giả họ Mã","tuChuong":"@c0729","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"thi triển","importance":"normal","giaiDoan":"Trận đấu Mã lão giả vs Quật Diệu","text":"Lão giả họ Mã dùng bạch quang nhu hòa hộ thể khi đối đầu Quật Diệu. Cốc Song Bồ phân tích: thủy hỏa bất xâm, khắc tà ích quỷ, không bị ma hỏa công tâm nhưng không khắc chế được thiên địa linh hỏa tam vị chân đế.","anchor":"Hạo Nhiên Chính Khí quyết tựa hồ như thủy hỏa bất xâm, có tác dụng khắc tà ích quỷ"}]},"nguon":["@c0729"]},{"id":"hoa-linh-bien-hoa","name":"Hỏa linh biến hóa","cn":"火灵变化","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thiên địa linh hỏa tam vị chân đế","hePhai":"Bái Hỏa Bộ","soHuu":["Quật Diệu"],"blurb":"Hỏa linh biến hóa là thần thông hỏa thuộc tính đặc thù, luyện hóa Thiên Địa Hỏa Linh ngưng kết thành hỏa mãng, có khả năng biến hóa thành hỏa giao hồng lân phun xích diễm uy lực kinh khủng. Đây không phải năng lực mà Nguyên Anh pháp sĩ phổ thông có thể thi triển.","detail":"Hỏa linh biến hóa là công pháp hỏa thuộc tính đạt cảnh giới chí cao, cốt lõi nằm ở việc luyện hóa Thiên Địa Hỏa Linh — loại linh lực trời đất cực kỳ khó nắm bắt — ngưng hóa sinh thành hỏa mãng. Hỏa mãng sau đó biến hóa thành hỏa giao hồng lân, mọc sừng, mọc lợi trảo, giương nanh múa vuốt, hình thái uy mãnh. Tại mốc @c0729, Quật Diệu tiết lộ bản chất hỏa mãng chính là Thiên Địa Hỏa Linh ngưng hóa sinh thành, đồng thời hỏa mãng biến hóa thành hỏa giao thi triển uy lực. Hỏa giao phun xích diễm cuồn cuộn, đủ sức bao phủ cả đối thủ cấp Nguyên Anh lẫn pháp bảo trong biển lửa, cho thấy đẳng cấp vượt xa tầm Nguyên Anh pháp sĩ thông thường.","thuocTinh":"Hỏa","nguonGoc":"Thiên Địa Hỏa Linh ngưng hóa","uyLuc":"Hỏa giao phun xích diễm cuồn cuộn, bao phủ cả đối thủ Nguyên Anh lẫn pháp bảo trong biển lửa; không phải Nguyên Anh pháp sĩ phổ thông có thể làm được.","dacDiem":"Hỏa mãng do Thiên Địa Hỏa Linh ngưng hóa sinh thành, biến hóa thành hỏa giao hồng lân — mọc sừng, mọc lợi trảo, hình thái giương nanh múa vuốt.","congNang":["Luyện hóa Thiên Địa Hỏa Linh ngưng kết thành hỏa mãng @c0729","Hỏa mãng biến hóa thành hỏa giao hồng lân — mọc sừng, mọc lợi trảo, giương nanh múa vuốt @c0729","Hỏa giao phun xích diễm cuồn cuộn bao phủ đối thủ cấp Nguyên Anh cùng pháp bảo trong biển lửa @c0729"],"nguoiTu":[{"ten":"Quật Diệu","tuChuong":"@c0729","tangDatToi":"Thiên địa linh hỏa tam vị chân đế","trangThai":"dai-thanh"}],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"thi triển","importance":"major","giaiDoan":"Trận đấu với lão giả họ Mã","text":"Quật Diệu tiết lộ hỏa mãng chính là Thiên Địa Hỏa Linh ngưng hóa sinh thành. Hỏa mãng biến hóa thành hỏa giao hồng lân — mọc sừng, mọc lợi trảo. Hỏa giao phun xích diễm cuồn cuộn bao phủ cả lão giả họ Mã và bát quái đồ trong biển lửa.","anchor":"hỏa mãng hồng quang trên người đại phóng rồi đột nhiên phi vũ thượng thiên, trên đầu sinh ra một cái sừng, vuốt mọc thêm lợi trảo rồi hóa thân thành một con hỏa giao hồng lân"}]},"nguon":["@c0729"]},{"id":"thien-sat-chan-ma-cong","name":"Thiên Sát Chân Ma Công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Ma đạo","soHuu":["Hắc bào nhân"],"blurb":"Thiên Sát Chân Ma Công là ma đạo công pháp do một trưởng lão truyền công bí ẩn truyền cho hắc bào nhân, cho phép ma hoá thân thể cao hai trượng mọc sừng phun nanh, dùng quỷ trảo ẩn hình và đôi lợi trảo tấn công. Công pháp này tự xưng cực mạnh ở cùng cấp, song có nhược điểm chí mạng là tối kiêng kị kim sắc điện hồ, và bộ dáng ma hoá giống hệt huyễn ảnh của Lục Cực Chân Ma Công.","detail":"Thiên Sát Chân Ma Công là một bộ ma đạo công pháp được một trưởng lão truyền công bí ẩn truyền thụ cho hắc bào nhân; ngay từ khi truyền công, trưởng lão đã dặn dò rõ rằng tối kiêng kị của công pháp này chính là kim sắc điện hồ. Khi thi triển toàn lực, người tu luyện ma hoá thân thể cao hai trượng, đầu mọc hai sừng, miệng phun răng nanh, toàn thân toát ra hắc khí kèm theo tiếng quỷ khóc. Bộ dáng ma hoá này giống hệt huyễn ảnh xuất hiện trong Lục Cực Chân Ma Công, gợi ra mối liên hệ giữa hai bộ ma đạo công pháp. Trong trận đấu với Hàn Lập tại chương @c0731, hắc bào nhân thi triển toàn lực Thiên Sát Chân Ma Công nhưng bị kim sắc điện hồ khắc chế. Công pháp tự xưng ở cùng cấp bậc hiếm khi gặp đối thủ, song nhược điểm chí mạng trước kim sắc điện hồ khiến uy thế bị triệt tiêu.","thuocTinh":"Ma đạo","nguonGoc":"Do một trưởng lão truyền công bí ẩn truyền cho hắc bào nhân","uyLuc":"Tự xưng ở cùng cấp bậc tu vi hiếm khi gặp đối thủ, thi triển toàn lực ma hoá thân thể cao hai trượng toát hắc khí kèm tiếng quỷ khóc, dùng quỷ trảo ẩn hình và đôi lợi trảo tấn công; tuy nhiên bị kim sắc điện hồ khắc chế hoàn toàn @c0731.","dacDiem":"Tối kiêng kị kim sắc điện hồ — nhược điểm được trưởng lão truyền công dặn dò từ đầu. Bộ dáng ma hoá giống hệt huyễn ảnh trong Lục Cực Chân Ma Công, gợi mối liên hệ giữa hai bộ ma đạo công pháp.","congNang":["Ma hoá thân thể cao hai trượng, đầu mọc hai sừng, miệng phun răng nanh, toàn thân toát hắc khí kèm tiếng quỷ khóc @c0731","Quỷ trảo xanh lục ẩn hình tấn công đối thủ @c0731","Đôi lợi trảo bao vây đối thủ @c0731","Có thể thu nhỏ thân hình hoặc hoá thành mảnh tơ đen để tháo chạy @c0731"],"nguoiTu":[{"ten":"Hắc bào nhân","tuChuong":"@c0731","tangDatToi":"Toàn lực","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0731","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Hắc bào nhân thi triển toàn lực Thiên Sát Chân Ma Công đấu Hàn Lập, ma hoá thân thể nhưng bị kim sắc điện hồ áp chế, buộc phải hoá thân tháo chạy. Lộ ra tối kiêng kị là kim sắc điện hồ do trưởng lão truyền công dặn dò.","anchor":"Dưới mười phần uy lực của Thiên Sát Chân Ma Công hôm nay của ta"}]},"nguon":["@c0731"]},{"id":"thien-am-huyen-hoa-tran","name":"Thiên Âm Huyễn Hóa Trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Đại trận phòng thủ tại Hoàng Long Sơn, được đánh giá rất vững chắc, pháp sĩ Mộ Lan phải tăng gấp rưỡi binh lực mới có thể phá nổi.","detail":"Trận pháp phòng thủ đặt tại Hoàng Long Sơn, tạo vụ hải sương mù bao phủ. Đại hán trọc mi (chỉ huy phòng thủ) đánh giá trận pháp vững chắc, pháp sĩ Mộ Lan không tăng gấp rưỡi thì không thể phá. Có thông đạo mở xuyên vụ hải để ra vào.","congNang":["Tạo vụ hải sương mù phòng thủ bao phủ Hoàng Long Sơn","Pháp sĩ cần tăng gấp rưỡi binh lực mới phá nổi"],"tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"nhắc tới","importance":"normal","giaiDoan":"Đánh giá phòng thủ","text":"Đại hán trọc mi nhận định trận pháp rất vững chắc, pháp sĩ Mộ Lan không tăng gấp rưỡi thì không phá nổi.","anchor":"Thiên Âm Huyễn Hóa Trận tại Hoàng Long Sơn chúng ta cũng không dễ phá như vậy"}]},"nguon":["@c0732"]},{"id":"truyen-am-mat-thuat","name":"Truyền âm mật thuật","cn":null,"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":null,"hePhai":"Mộ Lan","soHuu":["Cốc Song Bồ","Nhạc thượng sư"],"blurb":"Kỹ thuật truyền âm đặc biệt bảo mật cao hơn truyền âm bình thường, chỉ thần thức cấp Nguyên Anh hậu kỳ mới có thể nghe trộm được.","detail":"Phương thức truyền âm mà Cốc Song Bồ sử dụng để liên lạc bí mật với Nhạc thượng sư (pháp sĩ Mộ Lan ẩn giấu). Khác với truyền âm thông thường, mật thuật này có độ bảo mật cực cao — theo Cốc Song Bồ phán đoán, ngoại trừ thần thức cường đại ngang tu sĩ Nguyên Anh hậu kỳ ra thì không có cách nào nghe trộm được. Hàn Lập đã nghe trộm thành công nhờ thần thức vượt trội so với tu sĩ cùng cấp, qua đó nắm được thông tin tình báo quan trọng về tình hình Mộ Lan.","nguon":["@c0733"]},{"id":"nhu-phong-quyet","name":"Nhu phong quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Nhạc Thượng Sư"],"blurb":"Công pháp tốc độ cực cao mà Nhạc Thượng Sư tu luyện, tự nhận không dưới Lôi Độn Thuật.","detail":"Nhạc Thượng Sư tu luyện công pháp này, tốc độ cực nhanh, tự tin rằng về tốc độ không thua Lôi Độn Thuật của Hàn Lập. Dùng ưu thế tốc độ để giữ khoảng cách, tránh cho đối phương cận chiến.","congNang":["Tốc độ cực cao, không dưới Lôi Độn Thuật"],"nguoiTu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0736","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0736","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu được nhắc tới","text":"Nhạc Thượng Sư tự tin dùng Nhu phong quyết đối phó Hàn Lập, tuyên bố tốc độ không dưới Lôi Độn Thuật.","anchor":"Ta tu luyện “Nhu phong quyết”, nói về tốc độ quyết sẽ không dưới lôi độn thuật của đối phương"}]},"nguon":["@c0736"]},{"id":"hoa-linh-tinh-nguyen","name":"Hỏa linh tinh nguyên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hỏa","soHuu":["Quật Diệu"],"blurb":"Thủ đoạn hỏa hệ uy lực lớn của Quật Diệu, dùng để phá đại trận.","detail":"Quật Diệu sở hữu hỏa linh tinh nguyên, uy lực phá trận cực lớn. Nhạc Thượng Sư dặn tiết kiệm, chờ thời điểm mấu chốt mới phóng thích.","congNang":["Hỏa hệ cường công phá trận, uy lực cực lớn"],"nguoiTu":[{"ten":"Quật Diệu","tuChuong":"@c0736","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0736","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu được nhắc tới","text":"Quật Diệu xin phóng thích hỏa linh tinh nguyên phá đại trận Hoàng Long Sơn, được Nhạc Thượng Sư dặn tiết kiệm cho thời điểm mấu chốt.","anchor":"Ta sẽ phóng thích hỏa linh tinh nguyên, một hơi phá đại trận này"}]},"nguon":["@c0736"]},{"id":"linh-thuat-dai-tran","name":"Linh thuật đại trận","cn":"灵术大阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Mộ Lan pháp sĩ","soHuu":["Quật Diệu"],"blurb":"Linh thuật đại trận là trận pháp đặc trưng của pháp sĩ Mộ Lan, dùng nhiều tiểu đội pháp sĩ thay thế trận kỳ trận bàn để nhanh chóng bố thành pháp trận uy lực cực đại, do một cao giai pháp sĩ chủ trì điều khiển. Tại Hỏa Long Sơn, Quật Diệu từng chủ trì bản hỏa thuộc tính, hơn mười tiểu đội pháp sĩ ngưng thành hỏa cầu khổng lồ nhắm phá cấm chế.","detail":"Linh thuật đại trận là pháp trận linh thuật đặc hữu của Mộ Lan nhân. Khác với pháp trận thông thường cần bố trí trận kỳ, trận bàn, trận pháp này lấy bản thân các pháp sĩ làm nút trận, nhiều tiểu đội pháp sĩ hợp lực tụ tập linh khí rồi ngưng tụ thành nguyên tố cầu khổng lồ tương ứng thuộc tính của trận. Toàn trận cần một cao giai pháp sĩ đứng ra chủ trì, thống nhất điều khiển linh lực các tiểu đội. Trong trận chiến tại Hỏa Long Sơn, Quật Diệu chủ trì linh thuật đại trận bản hỏa thuộc tính, hơn mười tiểu đội pháp sĩ Mộ Lan đồng loạt ngưng tụ thành hơn mười hỏa cầu khổng lồ lao vào phá vỡ cấm chế vụ hải.","congNang":["Dùng nhiều tiểu đội pháp sĩ thay thế trận kỳ trận bàn để nhanh chóng bố thành pháp trận @c0737","Tụ tập linh khí ngưng thành hỏa cầu khổng lồ tấn công phá cấm chế @c0737"],"nguoiTu":[{"ten":"Quật Diệu","tuChuong":"@c0737","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0737","loai":"thi triển","importance":"major","giaiDoan":"Phá cấm chế Hỏa Long Sơn","text":"Quật Diệu chủ trì linh thuật đại trận hỏa thuộc tính, hơn mười tiểu đội pháp sĩ Mộ Lan ngưng tụ hỏa cầu khổng lồ, sáu lục diện hồng cự phiên bắn quang trụ dẫn hỏa cầu lao vào phá tan cấm chế vụ hải Hỏa Long Sơn.","anchor":"Có thể do sử dụng nhiều pháp sĩ thay thế cho trận kỳ trận bàn, rất nhanh tạo thành pháp trận linh thuật"}]},"nguon":["@c0737"],"uyLuc":"Hơn mười tiểu đội pháp sĩ Mộ Lan đồng thời ngưng tụ hơn mười hỏa cầu khổng lồ, lao thẳng vào phá cấm chế vụ hải tại Hỏa Long Sơn.","dacDiem":"Lấy bản thân pháp sĩ làm nút trận thay cho trận kỳ trận bàn, cần cao giai pháp sĩ chủ trì điều khiển toàn trận, có thể triển khai theo thuộc tính nguyên tố khác nhau."},{"id":"bach-lien-bi-thuat","name":"Bạch Liên bí thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Mộ Lan pháp sĩ","soHuu":["Nhạc Thượng Sư"],"blurb":"Bạch Liên bí thuật là thần thông thượng cổ, người thi triển đọc chú ngữ tối nghĩa kết ấn hoa sen tạo đóa Bạch Liên trên đầu, triển khai bạch sắc quang mạc bao phủ phương viên hơn trăm trượng hình thành bình chướng vô hình ngăn pháp bảo xâm nhập. Bí thuật này cần thời gian dài niệm chú mới có thể hoàn thành thi triển.","detail":"Bạch Liên bí thuật là một loại thần thông có nguồn gốc thượng cổ. Khi thi triển, người dùng đọc thượng cổ chú ngữ tối nghĩa, mười ngón tay kết ấn hoa sen, ngưng tụ thành một đóa Bạch Liên phiêu đãng trên đỉnh đầu, phát ra bạch sắc linh quang chói mắt. Đóa Bạch Liên triển khai bạch sắc quang mạc bao phủ phương viên hơn trăm trượng, hình thành bình chướng vô hình phong tỏa khu vực. Trong truyện, nữ tử áo xanh sử dụng bí thuật này chặn đứng kiếm khí của Thanh Trúc Phong Vân Kiếm khiến kiếm khí không thể tới gần. Bí thuật đòi hỏi thời gian niệm chú kéo dài mới hoàn thành, đây là nhược điểm rõ rệt trong thực chiến. @c0739","congNang":["Tạo đóa Bạch Liên phiêu đãng trên đầu phát ra bạch sắc linh quang, triển khai quang mạc bao phủ phương viên hơn trăm trượng @c0739","Hình thành bình chướng vô hình phong tỏa khu vực, ngăn pháp bảo và kiếm khí xâm nhập — đã chặn đứng kiếm khí Thanh Trúc Phong Vân Kiếm @c0739"],"nguoiTu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0739","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0739","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Nữ tử áo xanh đọc thượng cổ chú ngữ, kết ấn hoa sen, tạo đóa Bạch Liên trên đầu triển khai quang mạc trăm trượng, chặn đứng Thanh Trúc Phong Vân Kiếm của Hàn Lập.","anchor":"mười ngón tay tách ra tạo bình như hoa sen, bên trên có một đoàn bạch quang chớp động không thôi"}]},"nguon":["@c0739"],"uyLuc":"Bạch sắc quang mạc phong tỏa phương viên hơn trăm trượng, chặn đứng hoàn toàn kiếm khí Thanh Trúc Phong Vân Kiếm không thể tới gần.","dacDiem":"Sử dụng thượng cổ chú ngữ tối nghĩa kết hợp kết ấn hoa sen, cần thời gian dài niệm chú mới hoàn thành thi triển; biểu hiện dưới dạng đóa Bạch Liên bạch sắc phiêu đãng trên đỉnh đầu người dùng."},{"id":"phong-don-thuat","name":"Phong Độn Thuật","cn":"风遁术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Nhạc Thượng Sư","Nữ tử họ Nhạc"],"blurb":"Độn thuật dùng phong nguyên tố dịch chuyển tức thì, tốc độ quỷ dị không kém Lôi Độn Thuật.","detail":"Nữ tử áo xanh kết hợp Bạch Liên và hoàng sắc tiểu đỉnh hóa thành thanh phong biến mất, xuất hiện ở ngoài hơn hai mươi trượng. Hàn Lập nhận định tốc độ không kém Lôi Độn.","nguon":["@c0740","@c0778"],"congNang":["Dịch chuyển tức thì bằng phong nguyên tố, tốc độ ngang Lôi Độn Thuật","Hóa gió di chuyển tốc độ cao"],"nguoiTu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0740","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0740","loai":"thi triển","importance":"normal","giaiDoan":"Nữ tử áo xanh thi triển lần đầu trước mặt Hàn Lập","text":"Nữ tử kết hợp Bạch Liên và tiểu đỉnh hóa thanh phong biến mất, hiện ra ở xa hơn hai mươi trượng, tốc độ khiến Hàn Lập âm thầm kêu khổ.","anchor":"Hàn Lập trên mặt không có chút vui mừng nào, ngược lại sau khi thì thào một tiếng thì trong lòng âm thầm kêu khổ"},{"chuong":"@c0778","loai":"thi triển","importance":"normal","giaiDoan":"Nữ tử họ Nhạc dùng truy đuổi Hàn Lập","text":"Nữ tử họ Nhạc hóa thanh phong truy đuổi Hàn Lập sau khi bị đoạt cổ đăng, nhưng bị lôi châu nổ phá giải và tam sắc phi trùng ngăn cản thi triển lại.","anchor":"Nữ nhân này quanh thân hiện lên thanh quang, hóa thành một cổ thanh phong, truy theo"}]}},{"id":"bach-lien-nhap-the","name":"Bạch Liên nhập thể","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Phật môn","soHuu":["Nhạc Thượng Sư"],"blurb":"Bí thuật phật môn nhập Bạch Liên vào thiên linh cái, từ trán phóng cánh hoa sen trắng vừa phòng ngự vừa phản kích cận chiến cực mạnh.","detail":"Nữ tử nhập Bạch Liên vào đỉnh đầu (thiên linh cái), từ trán phóng cánh hoa sen trắng đánh bật Hàn Lập khạc máu, bắn bay hai ba mươi trượng, đồng thời đánh bay Thanh Trúc Phong Vân Kiếm. Hàn Lập đánh giá là phật môn bí thuật, động tác chậm nhưng đối phương vô pháp tránh né.","nguon":["@c0740"],"congNang":["Phòng ngự cận chiến cực mạnh","Phản kích phóng cánh hoa sen trắng","Động tác chậm nhưng đối phương vô pháp tránh"],"nguoiTu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0740","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0740","loai":"thi triển","importance":"normal","giaiDoan":"Nữ tử nhập thể đánh bật Hàn Lập","text":"Nữ tử nhập Bạch Liên vào thiên linh cái phóng cánh hoa sen trắng đánh trúng ngực Hàn Lập, khiến hắn khạc máu bắn bay hai ba mươi trượng.","anchor":"đối phương thi triển phật môn bí thuật thì cũng tuyệt không có dũng khí đón đỡ"}]}},{"id":"ngoc-duong-chan-hoa","name":"Ngọc Dương Chân Hỏa","cn":"","loai":"than-thong","loaiLabel":"Dị hỏa","phamCap":"","hePhai":"","soHuu":["Ngân Nguyệt"],"blurb":"Dị hỏa thanh bạch nhị sắc, triển khai qua Tử Vân Đấu hóa hỏa xà tấn công.","detail":"Ngân Nguyệt triển khai qua Tử Vân Đấu, hiện dạng thanh bạch nhị sắc dị hỏa trải khắp tử võng cùng hỏa xà tấn công Bạch Liên của nữ tử áo lục.","congNang":["Dị hỏa thanh bạch nhị sắc, truyền dẫn qua lưới tử võng Tử Vân Đấu bao phủ đốt cháy mục tiêu"],"tabs":{"tienTrinh":[{"chuong":"@c0741","loai":"thi triển","importance":"normal","giaiDoan":"Triển khai trong Tử Vân Đấu","text":"Ngân Nguyệt triển khai Ngọc Dương Chân Hỏa thanh bạch nhị sắc trải khắp tử võng Tử Vân Đấu, hóa hỏa xà tấn công Bạch Liên của nữ tử áo lục.","anchor":"thanh bạch nhị sắc dị hỏa, trải rộng khắp tử võng"}]},"nguon":["@c0741"]},{"id":"phan-hong-sac-huong-vu","name":"Phấn hồng sắc hương vụ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngân Nguyệt","soHuu":["Ngân Nguyệt"],"blurb":"Mị thuật huyễn hóa của Ngân Nguyệt, phun phấn hồng sắc hương vụ từ miệng tạo huyễn ảnh tuấn nam mỹ nữ ôm nhau quấy rối tinh thần đối phương.","detail":"Ngân Nguyệt phun ra từ miệng, dị hương lan tỏa huyễn hóa vô số tuấn nam mỹ nữ ôm nhau làm cử động thân thiết, khiến đối phương ngẩn người mất tập trung, tạo cơ hội cho đồng minh hành động.","congNang":["Quấy rối tinh thần đối phương bằng huyễn ảnh dâm mị"],"nguon":["@c0742"],"tabs":{"tienTrinh":[{"chuong":"@c0742","loai":"thi triển","importance":"normal","giaiDoan":"Trận chiến Hoàng Long Sơn","text":"Ngân Nguyệt phun phấn hồng sắc hương vụ tạo huyễn ảnh tuấn nam mỹ nữ khiến nữ tử họ Nhạc ngẩn người mặt đỏ, tạo cơ hội cho Hàn Lập thu hồi cự kiếm.","anchor":"dị hương đại khởi huyễn hóa ra vô số tuấn nam mỹ nữ, mỗi người ôm ôm nhau, làm ra những cử động cực kỳ thân thiết"}]}},{"id":"phan-than-thuat-trong-than-su","name":"Phân thân thuật của Trọng Thần Sư","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Mộ Lan tộc","soHuu":["Trọng Thần Sư"],"blurb":"Thần thông phân thân thành ba của Trọng Thần Sư, tạo bản thể cùng hai hóa thân có tu vi khí tức hoàn toàn giống nhau, thần thức không phân biệt nổi. Được thi triển trong cuộc truy đuổi Hàn Lập sau khi hắn dùng Lôi Độn Thuật thoát thân.","detail":"Trọng Thần Sư thi triển phân thân thuật, phân thân thành ba (bản thể cùng hai hóa thân đồng đẳng) để truy đuổi Hàn Lập sau khi hắn sử dụng Lôi Độn Thuật thoát khỏi giao chiến. Tu vi và khí tức của ba thân hoàn toàn đồng nhất, ngay cả thần thức của Hàn Lập — vượt trên Nguyên Anh Trung Kỳ — cũng không thể phân biệt đâu là bản thể, đâu là hóa thân.","congNang":["Tạo hai hóa thân đồng đẳng bản thể, tu vi khí tức giống hệt, thần thức không phân biệt nổi @c0743"],"nguoiTu":[{"ten":"Trọng Thần Sư","tuChuong":"@c0743","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0743","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Trọng Thần Sư phân thân thành ba để truy đuổi Hàn Lập sau khi hắn dùng Lôi Độn Thuật thoát thân.","anchor":"thân hình sau một trận mơ hồ thì ngân quang chợt lóe rồi hiện ra hai gã nho sinh giống nhau như đúc"}]},"nguon":["@c0743"]},{"id":"tu-la-thien-hoa","name":"Tử La Thiên Hỏa","cn":"紫罗天火","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Chân hỏa mạnh mẽ của Hàn Lập, có thể áp chế và luyện hóa dị hỏa từ bảo vật khác.","detail":"Hàn Lập dùng Tử La Thiên Hỏa để áp chế thanh sắc đăng diễm từ đồng đăng Mộ Lan dính trên Thanh Trúc Phong Vân Kiếm. Ngân Nguyệt nhận định Tử La Thiên Hỏa có thể luyện hóa được thanh sắc đăng diễm nếu có đủ thời gian.","congNang":["Áp chế và luyện hóa dị hỏa từ bảo vật khác"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0744","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0744","loai":"thi triển","importance":"normal","giaiDoan":"Áp chế thanh sắc đăng diễm","text":"Hàn Lập dùng Tử La Thiên Hỏa áp chế thanh sắc đăng diễm dính trên Thanh Trúc Phong Vân Kiếm nhưng chưa trừ hết hậu hoạn, Ngân Nguyệt tin rằng có thể luyện hóa được.","anchor":"Tử La Thiên Hỏa của chủ nhân cũng không phải là thần thông tầm thường"}]},"nguon":["@c0744","@c0792"]},{"id":"me-hon-huyen-thuat","name":"Mê hồn huyễn thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Ngân Nguyệt"],"blurb":"Thần thông của Ngân Nguyệt, phối hợp Mộng Dẫn thuật của Hàn Lập để tra hỏi tù binh.","detail":"Ngân Nguyệt sử dụng Mê hồn huyễn thuật phối hợp cùng Mộng Dẫn thuật của Hàn Lập, hai thuật kết hợp giúp khai thác tình báo từ tù binh pháp sĩ Mộ Lan nhanh chóng.","congNang":["Mê hoặc, hỗ trợ tra hỏi tù binh phối hợp cùng Mộng Dẫn thuật"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0745","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0745","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Ngân Nguyệt phối hợp Mộng Dẫn thuật của Hàn Lập tra hỏi tù binh Phụng Thác, khai thác tình báo biên giới.","anchor":"Mộng Dẫn thuật của Hàn Lập với Mê hồn huyễn thuật của Ngân Nguyệt"}]},"nguon":["@c0745"]},{"id":"kien-tho-cong","name":"Kiền Thổ Công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Nghê Hàng Trai","soHuu":["Tu sĩ họ Huống"],"blurb":"Công pháp nổi danh của tu sĩ họ Huống (Nghê Hàng Trai), uy chấn Thiên Nam mấy trăm năm.","detail":"Công pháp sở trường của tu sĩ họ Huống, trưởng lão Nghê Hàng Trai. Uy chấn khắp Thiên Nam suốt mấy trăm năm, khiến hắn trở thành nhân vật chỉ dưới phu phụ Long Hàm trong hàng ngũ Thiên Đạo Minh.","nguoiTu":[{"ten":"Tu sĩ họ Huống","tuChuong":"@c0747","tangDatToi":"","trangThai":"dang-tu"}],"congNang":["Uy chấn Thiên Nam mấy trăm năm"],"tabs":{"tienTrinh":[{"chuong":"@c0747","loai":"nhắc tới","importance":"normal","giaiDoan":"Được giới thiệu","text":"Lữ Lạc giới thiệu tu sĩ họ Huống của Nghê Hàng Trai với Kiền Thổ Công uy chấn Thiên Nam mấy trăm năm.","anchor":"Một thân Kiền Thổ Công uy chấn Thiên Nam mấy trăm năm rồi"}]},"nguon":["@c0747"]},{"id":"thanh-sac-dang-diem","name":"Thanh sắc đăng diễm","cn":"青色灯焰","aliases":["Thanh diễm"],"loai":"khac","loaiLabel":"Ma diễm","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Thanh Sắc Đăng Diễm là loại hỏa diễm quái dị màu xanh tím bám trên Thanh Trúc Phong Vân Kiếm sau trận chiến tại Hoàng Long Sơn, sở hữu uy lực ngang Tử La Cực Hỏa và đặc tính bất tử bất diệt.","detail":"Thanh Sắc Đăng Diễm là một loại ma diễm có màu xanh tím, xuất hiện bám trên Thanh Trúc Phong Vân Kiếm từ trận chiến Hoàng Long Sơn. Ngọn lửa này thiêu đốt không ngừng nghỉ và có uy lực ngang hàng với Tử La Cực Hỏa. Hàn Lập từng dùng Tử La Cực Hỏa để áp chế, lấy số lượng dồn ép Thanh Sắc Đăng Diễm đến mũi kiếm, thu nhỏ chỉ còn bằng hạt đậu, nhưng vẫn không thể diệt trừ hoàn toàn — ngọn diễm vẫn tự khôi phục. Sự hiện diện của nó khiến cả Thanh Trúc Phong Vân Kiếm, Kiềm Lam Băng Diễm và Tử La Cực Hỏa đều bị phong tỏa, không thể thi triển tấn công.","congNang":["Thiêu đốt không ngừng tại vị trí bám, không thể dập tắt @c0751","Bất tử bất diệt: bị dồn ép đến kích thước hạt đậu vẫn tự khôi phục @c0751","Phong tỏa pháp bảo bị bám, khiến Thanh Trúc Phong Vân Kiếm không thể sử dụng tấn công @c0751","Uy lực ngang Tử La Cực Hỏa, Tử La Cực Hỏa chỉ có thể áp chế bằng số lượng chứ không thể tiêu diệt @c0751","Khiến Kiềm Lam Băng Diễm và Tử La Cực Hỏa đều không thể thi triển tấn công @c0751"],"tabs":{"tienTrinh":[{"chuong":"@c0751","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện khi Hàn Lập xử lý hậu hoạn trận Hoàng Long Sơn","text":"Bám trên Thanh Trúc Phong Vân Kiếm thiêu đốt không ngừng, uy lực ngang Tử La Cực Hỏa. Hàn Lập dùng Tử La Cực Hỏa dồn ép xuống mũi kiếm nhỏ bằng hạt đậu nhưng thanh diễm bất tử bất diệt tự khôi phục. Cuối cùng Hàn Lập bọc tử diễm lên tay trần bóp chặt thanh diễm, kết quả chưa rõ.","anchor":"Thanh sắc đăng diễm này không biết là loại ma diễm gì, uy lực kinh người không dưới Tử La Cực Hỏa của Hàn Lập"}]},"nguon":["@c0751"],"uyLuc":"Uy lực ngang hàng Tử La Cực Hỏa, bị Tử La Cực Hỏa lấy số lượng dồn ép đến mũi kiếm nhỏ bằng hạt đậu vẫn bất tử bất diệt, tự khôi phục và phong tỏa hoàn toàn pháp bảo cùng hỏa diễm của đối phương.","dacDiem":"Ma diễm màu xanh tím, bất tử bất diệt, thiêu đốt vĩnh cửu tại vị trí bám, không thể bị tiêu diệt mà chỉ có thể bị áp chế tạm thời."},{"id":"am-hoa-loi","name":"Âm Hỏa Lôi","cn":"陰火雷","loai":"bi-thuat","loaiLabel":"Bí thuật luyện chế","phamCap":"Cực phẩm (uy lực trên cả Thiên Đô Thi Hỏa)","hePhai":"Huyền Âm Kinh","soHuu":["Hàn Lập"],"blurb":"Âm Hỏa Lôi là phương pháp luyện chế lôi châu được ghi chép trong Huyền Âm Kinh, áp chế lượng lớn âm hỏa tinh thuần thành một đoàn trộn cùng lôi điện và tài liệu khác để tạo ra lôi châu có uy lực phá hoại trên cả Thiên Đô Thi Hỏa. Hàn Lập sau khi tra cứu đã quyết định cải biến phương pháp gốc, dùng thanh sắc đăng diễm thay thế âm hỏa kết hợp Ích Tà Thần Lôi để luyện chế loại lôi châu biến thể.","detail":"Âm Hỏa Lôi là phương pháp luyện chế lôi châu ghi trong Huyền Âm Kinh. Nguyên lý cốt lõi là dùng âm hỏa tinh thuần của Huyền Âm Đại Pháp áp chế thành một đoàn, trộn lôi điện chi lực cùng các tài liệu khác, rồi gia cố bằng thủ đoạn đặc thù để tạo thành lôi châu. Phương pháp này có nhược điểm rõ ràng: lôi châu chỉ dùng được một lần rồi mất, quy trình luyện chế vô cùng phức tạp với tỉ lệ thành công thấp, đồng thời chỉ tu sĩ có khả năng thao túng lôi điện mới có thể thực hiện. Chính vì những hạn chế này mà ngay cả Cực Âm lão tổ và Huyền Cốt Thượng Nhân — những nhân vật từng tu luyện Huyền Âm Kinh — đều chưa từng luyện chế thành công. Hàn Lập khi tra Huyền Âm Kinh tìm thấy phương pháp này đã quyết định cải biến, dùng thanh sắc đăng diễm thay thế âm hỏa, kết hợp Ích Tà Thần Lôi để luyện chế một l","thuocTinh":"Âm hỏa + Lôi điện","nguonGoc":"Huyền Âm Kinh","yeuCau":"Thao túng được lôi điện, có âm hỏa tinh thuần (hoặc dị hỏa thay thế)","uyLuc":"Uy lực phá hoại trên cả Thiên Đô Thi Hỏa.","dacDiem":"Dùng một lần là mất, luyện chế phức tạp với tỉ lệ thành công thấp, chỉ tu sĩ thao túng được lôi điện mới có thể thực hiện. Cực Âm lão tổ và Huyền Cốt Thượng Nhân đều chưa từng luyện chế thành công.","congNang":["Ném ra kích nổ trọng thương đối thủ, hoạt động theo nguyên lý lôi châu dùng một lần @c0752"],"trangThai":"Hàn Lập đang luyện chế biến thể bằng thanh diễm","capNhatToi":"@c0752","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0752","tangDatToi":"Đang luyện chế biến thể","trangThai":"dang-luyen"}],"tabs":{"tienTrinh":[{"chuong":"@c0752","loai":"xuat-hien","importance":"major","giaiDoan":"Lộ nguyên lý và bắt đầu luyện chế biến thể","text":"Hàn Lập tra Huyền Âm Kinh tìm thấy phương pháp Âm Hỏa Lôi, quyết định cải biến dùng thanh sắc đăng diễm thay âm hỏa kết hợp Ích Tà Thần Lôi bắt đầu luyện chế Lôi châu biến thể.","anchor":"Chỉ tính lực phá hoại mà nói thì thậm chí còn trên cả Thiên Đô Thi Hỏa"}]},"nguon":["@c0752"]},{"id":"ma-dao-cong-phap-hop-hoan-tong","name":"Ma đạo công pháp tối đỉnh Hợp Hoan Tông","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Tối đỉnh Hợp Hoan Tông","hePhai":"Ma đạo","soHuu":["Vân Lộ lão ma"],"blurb":"Công pháp ma đạo tối đỉnh của Hợp Hoan Tông, liên quan đến thải bổ chi đạo, yêu cầu thể chất âm dương đồng thể mới tu luyện được.","detail":"Công pháp này được Vân Lộ lão ma tu luyện, am hiểu thải bổ chi đạo, thường xuyên đuổi bắt tuấn nam mỹ nữ để thải bổ. Yêu cầu thể chất trời sinh âm dương đồng thể.","thuocTinh":"Âm dương đồng thể, thải bổ","nguonGoc":"Hợp Hoan Tông","yeuCau":"Trời sinh âm dương đồng thể","nguoiTu":[{"ten":"Vân Lộ lão ma","tuChuong":"@c0753","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0753","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến khi Vân Lộ lão ma xuất hiện","text":"Vân Lộ lão ma tu luyện ma đạo công pháp tối đỉnh Hợp Hoan Tông, am hiểu thải bổ chi đạo, thường xuyên đuổi bắt tuấn nam mỹ nữ.","anchor":"tu luyện ma đạo công pháp tối đỉnh của Hợp Hoan Tông, am hiểu thải bổ chi đạo"}]},"nguon":["@c0753"]},{"id":"cuu-hon-bi-cong","name":"Cửu Hồn bí công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Toái Hồn Chân Nhân"],"blurb":"Công pháp do Toái Hồn Chân Nhân tu luyện, đã đạt cảnh giới chí cao.","detail":"Bí công Toái Hồn Chân Nhân tu luyện, được nhắc tại tụ hội lão quái Nguyên Anh Thiên Nam rằng đã đạt cảnh giới chí cao.","nguoiTu":[{"ten":"Toái Hồn Chân Nhân","tuChuong":"@c0754","tangDatToi":"cảnh giới chí cao","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0754","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Được nhắc đến tại tụ hội","text":"Được nhắc tại tụ hội lão quái rằng Toái Hồn Chân Nhân đã tu luyện Cửu Hồn bí công đến cảnh giới chí cao.","anchor":"Nghe nói Cửu Hồn bí công của đạo hữu đã tu luyện đến cảnh giới chí cao"}]},"nguon":["@c0754"]},{"id":"tinh-tam-quyet","name":"Tĩnh Tâm quyết","cn":"静心诀","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thái Chân môn","soHuu":["Chí Dương thượng nhân"],"blurb":"Công pháp trấn tĩnh tâm thần, thanh âm truyền vào tai người nghe như gió xuân, lập tức khiến tâm bình khí hòa, dẹp dao động.","detail":"Chí Dương thượng nhân dùng Tĩnh Tâm quyết tại hội nghị Thiên Nam, thanh âm truyền vào tai mọi người khiến lập tức tâm bình khí hòa. Có tu sĩ nhận xét Tĩnh Tâm quyết của Thái Chân môn quả nhiên có chút môn đạo.","congNang":["Trấn tĩnh tâm thần người nghe qua thanh âm, dẹp dao động tâm trạng"],"nguoiTu":[{"ten":"Chí Dương thượng nhân","tuChuong":"@c0755","tangDatToi":"đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0755","loai":"thi triển","importance":"normal","giaiDoan":"Hội nghị Thiên Nam","text":"Chí Dương thượng nhân thi triển Tĩnh Tâm quyết trấn tĩnh toàn bộ tu sĩ trong đại điện.","anchor":"Tĩnh Tâm quyết của Thái Chân môn quả nhiên là có chút môn đạo"}]},"nguon":["@c0755"]},{"id":"van-tuyet-quyet","name":"Vân Tuyết quyết","cn":"云雪诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Băng/Tuyết","soHuu":["Bạch phu nhân"],"blurb":"Thần thông của Bạch phu nhân, được Chí Dương thượng nhân nhắc tới khi đánh giá bà đủ sức đối phó một pháp sĩ Mộ Lan trong đổ chiến.","detail":"Chí Dương thượng nhân nhận xét với thần thông Vân Tuyết quyết, Bạch phu nhân chắc chắn thắng khi đối đầu một pháp sĩ Mộ Lan. Đặc tính liên quan băng tuyết, chi tiết công năng cụ thể chưa được hé lộ.","nguoiTu":[{"ten":"Bạch phu nhân","tuChuong":"@c0757","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0757","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Chí Dương thượng nhân nhắc tới","text":"Chí Dương thượng nhân đánh giá Bạch phu nhân với Vân Tuyết quyết đủ sức đối phó một pháp sĩ Mộ Lan.","anchor":"với thần thông Vân Tuyết quyết của Bạch đạo hữu thì đối phó với một tên pháp sĩ, chắc chắn sẽ thắng"}]},"nguon":["@c0757"]},{"id":"dai-tran-cam-che-bien-gioi","name":"Đại trận cấm chế biên giới","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Hệ thống cấm chế phòng thủ quy mô lớn được cả hai phía Thiên Nam và Mộ Lan thiết lập tại biên giới Ngu Quốc – Bắc Lương Quốc, bao phủ đại doanh bằng quang mạc ngũ sắc dày đặc, cần nghiệm chứng thân phận mới mở thông đạo.","detail":"Cả phía Thiên Nam lẫn Mộ Lan bố trí cấm chế lớn nhỏ hai bên biên giới trong sáu ngày, đến ngày thứ sáu gần hoàn chỉnh. Đại doanh Thiên Nam được bao phủ bởi quang mạc ngũ sắc dày đặc chói mắt.","dacDiem":"Quang mạc ngũ sắc bao phủ toàn bộ đại doanh, cần nghiệm chứng thân phận mới cho phép thông hành","nguon":["@c0761"]},{"id":"dai-tran-linh-thuat-cai-tien","name":"Đại trận linh thuật cải tiến","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Mộ Lan tộc","soHuu":["Trọng Thần Sư"],"blurb":"Trọng thần sư bỏ trăm năm nghiên cứu cải tiến nhiều loại pháp trận linh thuật, truyền cho pháp sĩ Mộ Lan để đối phó trận pháp Thiên Nam.","detail":"Nhiều loại đại trận linh thuật được Trọng thần sư tự nghiên cứu cải tiến suốt trăm năm, có tác dụng áp chế công kích pháp khí tu sĩ Thiên Nam. Đã truyền cho pháp sĩ Mộ Lan chuẩn bị cho đại chiến.","congNang":["Áp chế công kích pháp khí tu sĩ Thiên Nam"],"nguoiTu":[{"ten":"Trọng Thần Sư","tuChuong":"@c0762","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0762","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Trước đại chiến Thiên Nam","text":"Trọng thần sư tiết lộ trong hội nghị đã bỏ trăm năm nghiên cứu cải tiến nhiều loại pháp trận linh thuật, truyền cho pháp sĩ để sử dụng trong đại chiến ngày mai.","anchor":"ta bỏ ra trăm năm nghiên cứu pháp trận linh thuật đâu phải là để chơi"}]},"nguon":["@c0762"]},{"id":"am-duong-song-ma-giai-cam","name":"Âm dương song ma giải cấm","loai":"bi-thuat","loaiLabel":"Bí thuật","hePhai":"Hợp Hoan Tông","soHuu":["Hợp Hoan Tông"],"blurb":"Sát chiêu Hợp Hoan Tông chuẩn bị cho đại chiến Thiên Nam.","detail":"Bí thuật được Hợp Hoan Tông chuẩn bị sẵn sàng dùng trong đại chiến với pháp sĩ Mộ Lan.","nguon":["@c0763"]},{"id":"van-hon-dai-tran","name":"Vạn hồn đại trận","loai":"bi-thuat","loaiLabel":"Trận pháp","hePhai":"Quỷ Linh Tông","soHuu":["Quỷ Linh Tông"],"blurb":"Đại trận của Quỷ Linh Tông, tùy lúc có thể sử dụng trong đại chiến.","detail":"Trận pháp uy lực lớn do Quỷ Linh Tông chuẩn bị, sẵn sàng triển khai bất cứ lúc nào trong cuộc đại chiến với pháp sĩ Mộ Lan.","nguon":["@c0763"]},{"id":"muoi-toa-tieu-hinh-phap-tran","name":"Mười tòa tiểu hình pháp trận","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thiên Nam – Mộ Lan hợp tác","soHuu":[],"blurb":"Mười tòa pháp trận phiếm bạch quang do tu sĩ và pháp sĩ hai phe hợp lực bố trí tại biên giới, mỗi tòa bao trùm 70-80 trượng, dùng làm không gian đấu cách ly cho mười trận đánh cuộc Nguyên Anh.","detail":"Do tu sĩ và pháp sĩ tinh thông trận pháp từ phe Thiên Nam và Mộ Lan hợp lực bố trí trong gần một khắc. Sử dụng trận kỳ hiệp trợ và trân quý tài liệu. Mỗi tòa có một Kết Đan Kỳ tu sĩ cùng một pháp sĩ giám sát vận hành. Tường bạch quang ngăn cách chiến trường với bên ngoài.","congNang":["Tạo không gian đấu cách ly, giám sát công bằng cho đánh cuộc Nguyên Anh"],"tabs":{"tienTrinh":[{"chuong":"@c0765","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí hoàn thành","text":"Tu sĩ và pháp sĩ hai phe hợp lực bố trí mười tòa pháp trận phiếm bạch quang trong gần một khắc, mỗi tòa 70-80 trượng, có Kết Đan Kỳ tu sĩ và pháp sĩ giám sát.","anchor":"mười tòa ẩn phiếm bạch quang tiểu hình pháp trận đã thành hình"}]},"nguon":["@c0765"]},{"id":"huyet-la-quang-trao","name":"Huyết La Quang Tráo","cn":"血罗光罩","aliases":["Huyết quang tráo","Huyết tráo"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ (một trong sáu đại bí thuật tông phái)","hePhai":"Ma đạo","soHuu":["Phòng tông chủ"],"blurb":"Huyết La Quang Tráo là một trong sáu đại bí thuật tông phái của Phòng tông chủ, dùng mười huyết thi bồi dưỡng trăm năm cùng ma linh đan làm vật liệu, thông qua phân thức khống chế huyết thi tự bạo để tạo thành huyết tráo vây khốn đối thủ. Ngay cả tu sĩ Nguyên Anh Hậu Kỳ cũng khó phá giải trong thời gian ngắn.","detail":"Huyết La Quang Tráo thuộc sáu đại bí thuật tông phái mà Phòng tông chủ nắm giữ, đòi hỏi hy sinh mười huyết thi đã bồi dưỡng hàng trăm năm cùng ma linh đan mới có thể thi triển. Khi khai động, mười huyết thi giả dạng pháp sĩ (ma tu) tham gia vào đổ chiến, lọt vào bên trong lồng hào quang cùng đối thủ, rồi đồng loạt tự bạo thân thể dưới sự khống chế của phân thức. Huyết nhục từ huyết thi bám lên vách quang tráo, hóa thành huyết vụ nhuộm đỏ toàn bộ lồng, biến quang tráo thành huyết tráo. Tại chiến trường biên giới Thiên Nam, mười huyết thi được tung ra đồng loạt, vây khốn cùng lúc cả mười vị Nguyên Anh tu sĩ phe Thiên Nam. Đặc tính của huyết tráo là chỉ thuần vây khốn mà không gây thương tổn trực tiếp cho người bị nhốt; huyết vụ bên trong dù bị đánh tán vẫn lập tức khôi phục, khiến đối phương","thuocTinh":"Ma đạo / Huyết","nguonGoc":"Một trong sáu đại bí thuật tông phái Phòng tông chủ","yeuCau":"Mười huyết thi bồi dưỡng trăm năm, ma linh đan, phân thức khống chế","uyLuc":"Ngay cả tu sĩ Nguyên Anh Hậu Kỳ cũng phải tiêu tốn lượng lớn pháp lực và thời gian mới có thể phá vỡ huyết tráo.","dacDiem":"Chỉ có công năng vây khốn thuần túy, không gây thương tổn trực tiếp cho đối phương; huyết vụ cấu thành huyết tráo dù bị tán vẫn lập tức khôi phục, cần hy sinh mười huyết thi bồi dưỡng trăm năm cùng ma linh đan để thi triển, thông qua phân thức khống chế huyết thi tự bạo làm vật liệu.","congNang":["Vây khốn tu sĩ Nguyên Anh bên trong huyết tráo, dự kiến duy trì khoảng nửa ngày @c0766","Mười huyết thi đồng loạt thi triển, có thể vây khốn cùng lúc mười Nguyên Anh tu sĩ @c0766","Huyết vụ bị tán lập tức tự khôi phục, buộc đối phương tiêu hao lượng lớn pháp lực mới có thể phá giải @c0766"],"trangThai":"Đã thi triển tại chiến trường biên giới","capNhatToi":"@c0766","nguoiTu":[{"ten":"Phòng tông chủ","tuChuong":"@c0766","tangDatToi":"","trangThai":"Đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0766","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển tại chiến trường biên giới","text":"Mười huyết thi giả dạng ma tu đồng loạt tự bạo trong lồng hào quang đổ chiến, huyết nhục hóa huyết vụ nhuộm đỏ toàn bộ quang tráo, vây khốn cả mười Nguyên Anh tu sĩ Thiên Nam. Phòng tông chủ tiết lộ đây là một trong sáu đại bí thuật tông phái, cần hy sinh mười huyết thi trăm năm cùng ma linh đan.","anchor":"Huyết la quang tráo là một trong sáu đại bí thuật của tông phái"}]},"nguon":["@c0766"]},{"id":"linh-thuat-phap-tran","name":"Linh thuật pháp trận","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Mộ Lan pháp sĩ","soHuu":["Mộ Lan pháp sĩ"],"blurb":"Chiến thuật liên hợp của pháp sĩ Mộ Lan: non nửa số pháp sĩ đồng thời thi triển linh thuật tạo thành pháp trận công kích quy mô lớn, bao gồm hỏa cầu đường kính hơn trượng và băng thương.","detail":"Non nửa số pháp sĩ đồng thời thi triển linh thuật (hỏa cầu đường kính hơn trượng, hơn ngàn băng thương) tạo thành pháp trận công kích diện rộng bao trùm bầu trời phía đối phương. Long Hàm nhận ra đây là Linh thuật pháp trận của pháp sĩ Mộ Lan.","congNang":["Nhiều pháp sĩ liên hợp thi triển linh thuật công kích diện rộng (hỏa cầu, băng thương)"],"nguoiTu":[{"ten":"Mộ Lan pháp sĩ","tuChuong":"@c0767","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0767","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển trong đại chiến biên giới","text":"Non nửa số pháp sĩ đồng thời thi triển linh thuật tạo mấy trăm hỏa cầu lớn và hơn ngàn băng thương bao trùm bầu trời phe tu sĩ.","anchor":"Long Hàm thì thào tự nói một câu"}]},"nguon":["@c0767"]},{"id":"ngu-sac-thai-mac","name":"Ngũ sắc thái mạc","cn":"五色彩幕","aliases":["Ngũ sắc quang mạc","Trận kỳ ngũ sắc quang mạc"],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Cửu Quốc Minh","soHuu":["Tu sĩ Cửu Quốc Minh"],"blurb":"Pháp trận do tu sĩ Cửu Quốc Minh bố trí, chuyên khắc chế linh thuật cấm chế của pháp sĩ Mộ Lan.","detail":"Pháp trận phòng thủ dạng thái mạc ngũ sắc, chịu được đợt công kích đầu tiên của đại quân pháp sĩ mà không hề hấn gì. Chuyên môn khắc chế linh thuật cấm chế, được Ngụy Vô Nhai giới thiệu bố trí trước trận chiến biên giới.","congNang":["Khắc chế linh thuật cấm chế của pháp sĩ Mộ Lan"],"thuocTinh":"Phòng thủ diện rộng","tabs":{"tienTrinh":[{"chuong":"@c0768","loai":"thi triển","importance":"normal","giaiDoan":"Trận chiến biên giới Thiên Nam","text":"Tu sĩ Cửu Quốc triển khai ngũ sắc thái mạc chặn đứng đợt công kích đầu tiên của pháp sĩ Mộ Lan, thái mạc không hề hấn gì.","anchor":"chuyên môn khắc chế linh thuật cấm chế, nhìn sau khi trận công kích kinh người đi qua, thải mạc lại vẫn không hề hấn gì"}]},"nguon":["@c0768"]},{"id":"than-thong-an-nac-tu-dong-linh-ho","name":"Thần thông ẩn nặc Tứ Đồng Linh Hồ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Yêu khu","soHuu":["Ngân Nguyệt"],"blurb":"Thần thông ẩn nặc của yêu khu Tứ Đồng Linh Hồ, cho phép chủ nhân tiếp cận tu sĩ Nguyên Anh kỳ mà không bị phát giác.","detail":"Yêu khu Tứ Đồng Linh Hồ của Ngân Nguyệt sở hữu thần thông ẩn nặc bẩm sinh, vừa đột phá thêm một tầng, giúp nàng lén tiếp cận Hoàng sam lão giả (Nguyên Anh kỳ) mà không bị phát hiện để tập kích.","congNang":["Ẩn thân tiếp cận tu sĩ cao giai mà không bị thần thức phát giác"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0770","tangDatToi":"Vừa đột phá thêm 1 tầng","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0770","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Đột phá thêm một tầng","text":"Ngân Nguyệt tiết lộ yêu khu Tứ Đồng Linh Hồ có thần thông ẩn nặc vừa đột phá thêm một tầng, nhờ đó tiếp cận Nguyên Anh tu sĩ mà không bị phát giác.","anchor":"khối Tứ Đồng Linh Hồ này yêu khu có thần thông ẩn nặc"}]},"nguon":["@c0770"]},{"id":"thuan-di-thien-ho-thu","name":"Thuấn di","cn":"瞬移","loai":"bi-thuat","loaiLabel":"Năng lực thiên phú","phamCap":"","hePhai":"","soHuu":["Thiên Hổ Thú"],"blurb":"Năng lực thiên phú của Thiên Hổ Thú — dịch chuyển tức thời, khiến đối thủ không thể truy kích hay phòng thủ kịp.","detail":"Hai con Thiên Hổ Thú Kết Đan Hậu Kỳ của Điền Chung sử dụng thuấn di tập kích hai sườn Hàn Lập, bị đẩy lùi bằng kiếm quang nhưng lập tức thuấn di thoát, Hàn Lập không thể truy kịp.","nguon":["@c0771"]},{"id":"khon-ma-dai-tran","name":"Khốn ma đại trận","cn":"困魔大阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Chính đạo Thiên Nam","soHuu":["Hôi bào lão giả","Trường mi lão giả","Lão giả thân hình to lớn"],"blurb":"Trận pháp liên thủ do bảy lão giả Thiên Nam dùng bảy kiện Thái Chân Thất Bảo hợp lực tạo thành, hình thành bảy lồng bảy sắc vây khốn đối thủ.","detail":"Bảy tu sĩ cùng tế xuất bảy kiện cổ bảo (cổ kính, hồng xích, hoàng qua, lệnh bài, tiểu đỉnh, ngọc phiến, như ý) hợp thành bảy lồng bảy sắc bao quanh mục tiêu. Được sử dụng để vây khốn phân thân Thánh cầm nhưng vẫn ở thế hạ phong.","thuocTinh":"Phong ấn, vây khốn","nguonGoc":"Thiên Nam chính đạo","dacDiem":"Cần đúng bảy kiện Thái Chân Thất Bảo và bảy tu sĩ đồng thời thi triển","congNang":["Hợp lực bảy cổ bảo tạo bảy lồng bảy sắc vây khốn đối thủ"],"nguoiTu":[{"ten":"Hôi bào lão giả","tuChuong":"@c0772","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Trường mi lão giả","tuChuong":"@c0772","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Lão giả thân hình to lớn","tuChuong":"@c0772","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0772","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển trên chiến trường","text":"Bảy lão giả Thiên Nam tế xuất bảy kiện Thái Chân Thất Bảo, hợp lực tạo Khốn ma đại trận vây khốn phân thân Thánh cầm. Tuy vây được nhưng vẫn ở thế hạ phong, lệnh bài suýt bị đánh nát.","anchor":"Hãy mau thi triển 'khốn ma đại trận', rồi vây khốn yêu cầm này lại"}]},"capNhatToi":"@c0772","nguon":["@c0772"]},{"id":"nghi-thuc-trieu-hoi-thanh-cam","name":"Nghi thức triệu hồi Thánh cầm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật Mộ Lan","phamCap":"Không rõ","hePhai":"Mộ Lan tộc","soHuu":["Nhạc thượng sư"],"blurb":"Bí thuật triệu hồi phân thân Mộ Lan Thánh cầm — linh thú cảnh giới Hóa Thần, truyền thừa mấy vạn năm trong Mộ Lan tộc. Nghi thức đòi hỏi cổ đăng, tiên huyết và viên châu phấn hồng làm tế vật, người thi triển phải duy trì cổ đăng không tắt và không thể tham chiến trong suốt quá trình.","detail":"Nghi thức triệu hồi Thánh cầm là bí thuật truyền thừa mấy vạn năm của Mộ Lan tộc, dùng để triệu hồi phân thân linh thú Mộ Lan Thánh cầm ở cảnh giới Hóa Thần. Khi thi triển, Nhạc thượng sư dùng cổ đăng bắt quyết hoa sen, đọc chú ngữ hoang dã thượng cổ rồi phun tiên huyết để kích hoạt. Cổ đăng phân thành chín cái xếp theo hình chữ Phẩm, chín đóa hoa đăng hợp nhất thành đầu lâu lửa xanh. Sau đó dâng viên châu phấn hồng cho Thánh cầm nuốt, kích hoạt biến hình thành Hỏa Điểu. Nghi thức mang ràng buộc nghiêm ngặt: cổ đăng phải được duy trì liên tục — nếu đèn tắt hoặc bị hủy, phân thân Thánh cầm lập tức biến mất; đồng thời người triệu hồi không thể tham chiến trong suốt thời gian duy trì nghi thức.","thuocTinh":"Hỏa","nguonGoc":"Mộ Lan tộc, truyền thừa mấy vạn năm","dacDiem":"Phải duy trì cổ đăng không tắt trong suốt nghi thức; người triệu hồi không thể tham chiến; cần ba loại tế vật gồm cổ đăng, tiên huyết và viên châu phấn hồng; chín cổ đăng xếp hình chữ Phẩm hợp nhất thành đầu lâu lửa xanh; đèn tắt hoặc bị hủy thì Thánh cầm biến mất.","congNang":["Triệu hồi phân thân linh thú Mộ Lan Thánh cầm ở cảnh giới Hóa Thần @c0772","Phân thân hấp thu toàn bộ địa hỏa linh khí trong phạm vi mười dặm","Phân thân Thánh cầm nuốt viên châu phấn hồng để biến hình thành Hỏa Điểu @c0772"],"nguoiTu":[{"ten":"Nhạc thượng sư","tuChuong":"@c0772","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0772","loai":"thi triển","importance":"major","giaiDoan":"Triệu hồi thành công trên chiến trường","text":"Nhạc thượng sư thi triển nghi thức triệu hồi phân thân Thánh cầm bằng cổ đăng, tiên huyết và viên châu phấn hồng. Thánh cầm xuất hiện dưới dạng khổng tước xanh, nuốt châu biến thành Hỏa Điểu khổng lồ, hấp thu toàn bộ hỏa linh khí trong mười dặm.","anchor":"cô ta còn phải lo cho cây đèn không được hết dầu hay là bị tắt đi"}]},"capNhatToi":"@c0772","nguon":["@c0772"]},{"id":"thuong-co-bi-thuat-luyen-ma-thi","name":"Thượng cổ bí thuật luyện ma thi","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Hợp Hoan Tông","soHuu":["Hợp Hoan Tông"],"blurb":"Bí thuật thượng cổ do Hợp Hoan Tông nắm giữ, cho phép xóa thần trí tu sĩ còn sống rồi luyện chế thành ma thi có thần thông cao hơn lúc sống ba phần. Được dùng để luyện đôi song tu trưởng lão phản bội thành Âm Dương Ma Thi.","detail":"Thượng cổ bí thuật luyện ma thi là một bí pháp cổ xưa được Hợp Hoan Tông sử dụng. Quy trình luyện chế đòi hỏi đối tượng là tu sĩ còn sống; thần trí của nạn nhân bị xóa hoàn toàn, sau đó thân xác được luyện chế thành ma thi. Ma thi thành phẩm giữ lại thần thông vốn có lúc sinh tiền nhưng uy lực tăng thêm ba phần so với khi còn sống. Trong truyện, Hợp Hoan Tông đã áp dụng bí thuật này lên đôi trưởng lão song tu phản bội chuyển sang quỷ tu, luyện thành Âm Dương Ma Thi.","congNang":["Xóa hoàn toàn thần trí của tu sĩ còn sống, luyện chế thân xác thành ma thi giữ lại thần thông gốc nhưng mạnh hơn lúc sống ba phần @c0774"],"nguoiTu":[{"ten":"Hợp Hoan Tông","tuChuong":"@c0774","tangDatToi":"","trangThai":"sử dụng thành công"}],"tabs":{"tienTrinh":[{"chuong":"@c0774","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lần đầu hé lộ","text":"Hợp Hoan Tông dùng thượng cổ bí thuật xóa thần trí đôi song tu trưởng lão phản bội, luyện thành Âm Dương Ma Thi có thần thông cao hơn lúc sống ba phần.","anchor":"dùng thượng cổ bí thuật xoá đi thần trí của họ rồi luyện chế thành Âm Dương Ma Thi"}]},"nguon":["@c0774"],"uyLuc":"Ma thi thành phẩm sở hữu thần thông cao hơn ba phần so với khi nạn nhân còn sống, như đã thể hiện qua Âm Dương Ma Thi được luyện từ đôi trưởng lão song tu.","dacDiem":"Đối tượng luyện chế bắt buộc phải là tu sĩ còn sống; sau khi bị xóa thần trí và luyện thành ma thi, thần thông gốc không mất đi mà được khuếch đại."},{"id":"phuong-phap-quy-tu","name":"Phương pháp quỷ tu","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Tà đạo","soHuu":[],"blurb":"Phương pháp tu luyện tà đạo, có thể chuyển đổi từ chính đạo sang, áp dụng lên cả người còn sống, giúp tu vi tăng tiến.","detail":"Phương pháp tu luyện mà đôi song tu trưởng lão Hợp Hoan Tông đã chuyển đổi sang sau khi phản bội tông môn. Có thể áp dụng lên người còn sống, tu vi tăng tiến nhanh nhưng đi kèm sát nghiệp.","congNang":["Chuyển đổi tu luyện từ chính đạo sang quỷ tu, tăng tu vi"],"tabs":{"tienTrinh":[{"chuong":"@c0774","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc trong lai lịch Song Ma","text":"Đôi song tu trưởng lão Hợp Hoan Tông phản bội chuyển sang phương pháp quỷ tu, tu vi tăng tiến, giết hơn trăm đệ tử trước khi bị bắt.","anchor":"có thể chuyển đổi phương pháp quỷ tu, có thể áp dụng lên cả người còn sống"}]},"nguon":["@c0774"]},{"id":"cu-vien-hit-thi-khi","name":"Cự viên hít thi khí","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Cự viên cổ quái"],"blurb":"Thần thông thiên phú của cự viên cổ quái, hít sạch thi khí của hàng ngàn đồng giáp thi bằng mũi rồi phun ánh sáng vàng cuốn sạch thi khí trên thân luyện thi khiến chúng hóa tro bụi. Năng lực này được thi triển giữa chiến trường Thiên Nam. @c0775","detail":"Đây là năng lực thiên phú của cự viên cổ quái, xuất hiện giữa chiến trường Thiên Nam. Cự viên dùng chiếc mũi to lớn hít nhẹ một cái đã hấp thu toàn bộ hắc vụ thi khí của hàng ngàn đồng giáp thi, sau đó phun ra ánh sáng vàng cuốn sạch thi khí còn sót lại trên thân luyện thi, khiến hàng trăm con hóa tro trong chốc lát. Thần thông này thể hiện khả năng khắc chế thi khí cực kỳ mạnh mẽ của cự viên, vừa có thể thu hút vừa có thể tịnh hóa thi khí trên quy mô lớn. @c0775","congNang":["Hấp thu thi khí bằng cách hít mũi — hít sạch toàn bộ hắc vụ thi khí của hàng ngàn đồng giáp thi chỉ trong một hơi @c0775","Phun ánh sáng vàng cuốn sạch thi khí trên thân luyện thi, khiến chúng hóa tro bụi @c0775"],"tabs":{"tienTrinh":[{"chuong":"@c0775","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển trên chiến trường","text":"Cự viên xuất hiện giữa chiến trường Thiên Nam, hít sạch thi khí hàng ngàn đồng giáp thi rồi phun ánh sáng vàng quét sạch hàng trăm luyện thi hóa tro bụi, đảo ngược cục diện.","anchor":"cái mũi to lớn hít nhẹ một cái"}]},"nguon":["@c0775"],"uyLuc":"Một hơi hít sạch thi khí của hàng ngàn đồng giáp thi, sau đó phun ánh sáng vàng khiến hàng trăm luyện thi hóa tro trong chốc lát. @c0775","dacDiem":"Thần thông thiên phú của cự viên, sử dụng chiếc mũi to lớn làm trung tâm thi triển, có hai giai đoạn: hít thu thi khí rồi phun quang cuốn sạch tàn dư."},{"id":"thanh-minh-linh-nhan","name":"Thanh Minh Linh Nhãn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông cho phép nhìn xuyên ảo thuật và ẩn nặc, phát hiện chân thân kẻ địch qua phân thân ảo ảnh.","detail":"Hàn Lập thi triển Thanh Minh Linh Nhãn để nhìn thấu ảo ảnh phân thân của hắc bào nữ tử, phát hiện chân thân đang lẩn phía sau lưng hắn định đánh lén.","tabs":{"tienTrinh":[{"chuong":"@c0776","loai":"thi triển","importance":"normal","giaiDoan":"Dùng nhìn thấu phân thân ảo ảnh","text":"Hàn Lập thi triển Thanh Minh Linh Nhãn nhìn xuyên bảy tám phân thân ảo ảnh của hắc bào nữ tử, phát hiện chân thân ẩn phía sau lưng hắn.","anchor":"thi triển ra thần thông minh thanh linh nhãn"}]},"nguon":["@c0776"]},{"id":"than-thong-an-nac-tang-hinh","name":"Thần thông ẩn nặc tàng hình","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Yêu tộc","soHuu":["Hàn Lập"],"blurb":"Thần thông ẩn thân từ pháp quyết luyện khí vô danh của yêu tộc, thu liễm linh khí và khí tức thân thể để tàng hình tiếp cận mục tiêu.","detail":"Hàn Lập tu luyện từ pháp quyết luyện khí vô danh của yêu tộc. Thu liễm linh khí toàn thân lẫn khí tức thân thể, đạt hiệu quả tàng hình. Tuy không bằng thiên phú độn thuật của Ngân Nguyệt nhưng về phương diện liễm khí thì không thua kém.","thuocTinh":"Ẩn nặc","nguonGoc":"Pháp quyết luyện khí vô danh của yêu tộc","congNang":["Thu liễm linh khí và khí tức thân thể để tàng hình"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0777","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0777","loai":"thi triển","importance":"normal","giaiDoan":"Sử dụng lần đầu trên chiến trường","text":"Hàn Lập sử dụng thần thông ẩn nặc tàng hình bí mật tiếp cận nữ tử họ Nhạc nhằm phá hủy cổ đăng, nhưng bị phát hiện.","anchor":"Hàn Lập từ pháp quyết luyện khí vô danh của yêu tộc mà tu luyện thần thông ẩn nặc tàng hình"}]},"nguon":["@c0777"]},{"id":"hoa-dieu-huyen-hoa","name":"Hỏa Điểu huyễn hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Mộ Lan thánh cầm","soHuu":["Mộ Lan thánh cầm"],"blurb":"Thần thông của Mộ Lan thánh cầm (cự điểu khổng tước), rung lông hóa thành mấy trăm Hỏa Điểu thanh sắc bay đi tấn công hỗ trợ.","detail":"Cự điểu rung lông, từng mảng thanh vũ rời ra rồi quang mang chợt lóe hóa thành mấy trăm thanh sắc Hỏa Điểu dài cỡ một xích, tự động bay đi tương trợ chiến đấu.","congNang":["Phân thân hỏa điểu thanh sắc tấn công hỗ trợ đồng minh"],"tabs":{"tienTrinh":[{"chuong":"@c0777","loai":"thi triển","importance":"normal","giaiDoan":"Thánh cầm hỗ trợ đám lão giả Mộ Lan","text":"Cự điểu giương cánh rung lông hóa mấy trăm Hỏa Điểu thanh sắc bay đến tương trợ đám lão giả phe Mộ Lan đang bị cuốn vào chiến đấu.","anchor":"Từng mảng lớn thanh vũ từ trên người nó rời ra, sau đó quang mang chợt lóe hóa thành đám thanh sắc Hỏa Điểu dài cỡ một xích"}]},"nguon":["@c0777"]},{"id":"thuat-ngung-tu-thach-nhan","name":"Thuật ngưng tụ thạch nhân khổng lồ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Mộ Lan pháp sĩ","soHuu":["Mộ Lan Đại Thượng Sư"],"blurb":"Mấy Đại Thượng Sư Mộ Lan hợp lực ngưng tụ ra thạch nhân khổng lồ cao gần trăm trượng, giống Khôi Lỗi, dùng để vây công đối thủ.","detail":"Mấy tên Mộ Lan Đại Thượng Sư hợp lực thi triển thần thông ngưng tụ ra hư linh thú thạch nhân khổng lồ cao cơ hồ trăm trượng, hình dáng giống Khôi Lỗi, dùng để chiến đấu vây công tu sĩ Thiên Nam.","congNang":["Tạo hư linh thú thạch nhân khổng lồ chiến đấu"],"nguoiTu":[{"ten":"Mộ Lan Đại Thượng Sư","tuChuong":"@c0777","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0777","loai":"thi triển","importance":"normal","giaiDoan":"Ngưng tụ thạch nhân vây công","text":"Mấy Đại Thượng Sư hợp lực ngưng tụ thạch nhân khổng lồ cao gần trăm trượng vây công quỷ vụ và tu sĩ Thiên Nam.","anchor":"mấy tên Mộ Lan Đại Thượng Sư hợp lực ngưng tụ ra hư linh thú, kình thiên cự đại thạch nhân"}]},"nguon":["@c0777"]},{"id":"am-hoa-dai-thu","name":"Bàn tay hắc hồng (âm hỏa đại thủ)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Phóng bàn tay lớn màu hắc hồng mang âm hỏa, dùng để bắt giữ vật và tiêu diệt đăng diễm.","detail":"Hàn Lập phóng ra bàn tay lớn màu hắc hồng có âm hỏa, túm lấy chủ đăng trong cửu trản cổ đăng và dùng âm hỏa tiêu diệt đăng diễm trên đó.","congNang":["Bắt giữ mục tiêu","Dùng âm hỏa tiêu diệt đăng diễm"],"nguon":["@c0778"],"tabs":{"tienTrinh":[{"chuong":"@c0778","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập dùng đoạt chủ đăng","text":"Hàn Lập phóng bàn tay lớn hắc hồng túm lấy chủ đăng, dùng âm hỏa tiêu diệt đăng diễm trên đó khiến tám trản còn lại đồng loạt tắt.","anchor":"bị đại thủ túm lấy, theo đó đăng diễm bị hắc sắc âm hỏa trên đại thủ mạnh mẽ tiêu diệt"}]}},{"id":"phong-hon-chu","name":"Phong Hồn Chú","cn":"封魂咒","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Ma đạo cấm chế bí thuật (đã thất truyền tại Thiên Nam)","hePhai":"Ma đạo","soHuu":["Hắc bào nam tử","Âm La Tông"],"blurb":"Phong Hồn Chú là một trong năm loại ma đạo cấm chế bí thuật đã thất truyền tại Thiên Nam, có tác dụng phong ấn ba hồn bảy phách của nạn nhân khiến hồn phách dần tiêu tán, cuối cùng chỉ còn lại nhục thân. Giải chú pháp quyết thuộc bí thuật cấp tông chủ hoặc đại trưởng lão Âm La Tông.","detail":"Phong Hồn Chú là thủ đoạn đặc biệt của ma đạo, thuộc một trong năm loại cấm chế bí thuật đã thất truyền tại Thiên Nam. Người thi triển điểm ngón tay lên trán nạn nhân, khiến ba hồn bảy phách chậm rãi bị phong ấn, sau đó tùy theo tu vi của người bị trúng chú mà hồn phách dần dần tiêu tán, cuối cùng chỉ còn nhục thân vô dụng. Nam Cung Uyển bị hắc bào nam tử điểm Phong Hồn Chú tại tiểu sơn gần động phủ Lạc Vân Tông sơn môn (@c0781). Hắc bào thanh niên tuyên bố nắm giữ phương pháp giải chú nhưng đưa ngọc giản giả (@c0784). Hàn Lập sau đó xác nhận giải chú pháp quyết thực chất là bí thuật cấp tông chủ hoặc đại trưởng lão Âm La Tông, và có thể mượn ngoại vật để giải (@c0789).","congNang":["Phong ấn ba hồn bảy phách nạn nhân, khiến hồn phách dần tiêu tán chỉ còn nhục thân (@c0781)"],"tabs":{"tienTrinh":[{"chuong":"@c0781","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện, thi triển lên Nam Cung Uyển","text":"Hắc bào nam tử điểm Phong Hồn Chú lên trán Nam Cung Uyển tại tiểu sơn gần động phủ Lạc Vân Tông, khiến ba hồn bảy phách nàng dần bị phong ấn.","anchor":"ba hồn bảy phách sẽ chậm rãi bị phong ấn. Sau đó tùy theo tu vi của người bị phong ấn, hồn phách sẽ dần dần tiêu tán"},{"chuong":"@c0784","loai":"nhắc tới","importance":"normal","giaiDoan":"Phương pháp giải trở thành mục tiêu đàm phán","text":"Hắc bào thanh niên tuyên bố nắm phương pháp giải, đưa ngọc giản giả. Hàn Lập tuyên bố sẽ sưu hồn đối phương để tìm cách giải.","anchor":"Phương pháp giải từ Phong hồn chú trong ngọc giản này"},{"chuong":"@c0789","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ bí mật giải chú","text":"Hàn Lập xác nhận giải chú pháp quyết là bí thuật cấp tông chủ/đại trưởng lão Âm La Tông. Có thể mượn ngoại vật phá ấn với 50% khả năng.","anchor":"pháp quyết giải trừ phong hồn chú này chỉ có Âm La Tông tông chủ cùng tông nội Đại trưởng lão mới biết được"}]},"nguon":["@c0781","@c0783","@c0784","@c0789"],"uyLuc":"Khiến ba hồn bảy phách người trúng chú dần bị phong ấn rồi tiêu tán, cuối cùng chỉ còn nhục thân vô dụng, thuộc hàng cấm chế bí thuật ma đạo đã thất truyền.","dacDiem":"Thi triển bằng cách điểm ngón tay lên trán nạn nhân; pháp quyết giải chú thuộc bí thuật cấp tông chủ hoặc đại trưởng lão Âm La Tông, có thể mượn ngoại vật để giải; là một trong năm loại ma đạo cấm chế bí thuật đã thất truyền tại Thiên Nam."},{"id":"that-long-thung","name":"Thất long thung","cn":"七龙桶","loai":"bi-thuat","loaiLabel":"Trận pháp / Cấm chế","phamCap":"Không rõ (khiến khí linh cổ bảo hoảng sợ)","hePhai":"","soHuu":["Hắc bào thanh niên"],"blurb":"Thất long thung là cấm chế uy lực cực lớn do hắc bào thanh niên bày sẵn tại tiểu đảo, khi kích hoạt triệu ra bảy đạo bạch sắc quang trụ cùng bảy giao long ngân bạch sắc. Khí linh Ngân Nguyệt của cổ bảo Bạch lân thuẫn cực kỳ sợ hãi khi nhận ra cấm chế này, cho thấy uy lực vượt xa cấp độ thông thường.","detail":"Thất long thung là một cấm chế được hắc bào thanh niên bày đặt sẵn tại tiểu đảo nhằm phục kích. Khi kích hoạt bằng pháp quyết, bảy đạo bạch sắc quang trụ phóng thẳng lên cao, trên mỗi cột quang trụ hiện ra một con giao long ngân bạch sắc ngửa đầu tê hống. Ngân Nguyệt — khí linh của cổ bảo Bạch lân thuẫn đang theo Hàn Lập — nhận ra cấm chế này và phản ứng hoảng sợ tột độ, thúc giục Hàn Lập mau tránh xa, qua đó cho thấy đây là cấm chế đáng gờm có uy lực vượt xa tầm thường.","congNang":["Triệu bảy giao long ngân bạch sắc từ bảy đạo bạch sắc quang trụ để khống chế khu vực chiến đấu @c0784"],"tabs":{"tienTrinh":[{"chuong":"@c0784","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu kích hoạt","text":"Hắc bào thanh niên kích hoạt cấm chế bày sẵn, bảy bạch sắc quang trụ phóng lên hiện bảy giao long bạc. Ngân Nguyệt hoảng sợ cảnh báo Hàn Lập.","anchor":"Không tốt, là Thất long thung! chủ nhân mau tránh ra"}]},"nguon":["@c0784"],"uyLuc":"Khiến khí linh Ngân Nguyệt của cổ bảo Bạch lân thuẫn cực kỳ sợ hãi khi nhận ra, cho thấy uy lực đáng gờm vượt xa cấp độ thông thường.","dacDiem":"Cấm chế dạng bày sẵn, kích hoạt bằng pháp quyết, biểu hiện đặc trưng là bảy đạo bạch sắc quang trụ cùng bảy giao long ngân bạch sắc ngửa đầu tê hống."},{"id":"xa-nu-thien-nguyet-quyet","name":"Xá Nữ Thiên Nguyệt Quyết","cn":"舍女天月诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Luân Hồi Công","soHuu":["Nam Cung Uyển"],"blurb":"Xá Nữ Thiên Nguyệt Quyết là một công pháp cực kỳ nguy hiểm thuộc bộ Luân Hồi Công, vận hành theo nguyên lý tử rồi mới sinh. Nam Cung Uyển đã liều mạng tu luyện công pháp này trong lúc bị Phong Hồn Chú phong ấn, nương vào sinh tử một đường cơ hội.","detail":"Xá Nữ Thiên Nguyệt Quyết là bí thuật nằm trong bộ Luân Hồi Công, thuộc dạng công pháp tử rồi sau đó mới sinh — người tu luyện phải đặt mình vào cảnh tử địa trước rồi mới có thể đắc sinh cơ. Công pháp này được biết đến là cực kỳ nguy hiểm, nương vào sinh tử một đường. Nam Cung Uyển trong lúc bị Phong Hồn Chú phong ấn hồn phách đã bất chấp hiểm nguy, liều mạng tu luyện công pháp này. Sự kiện được Hàn Lập phát hiện tại thời điểm ghi nhận @c0789.","congNang":["Thuộc loại bí thuật tử rồi mới sinh — người tu phải trải qua trạng thái cận tử để đạt được chuyển cơ @c0789"],"dacDiem":"Cực kỳ nguy hiểm, nương vào sinh tử một đường; người tu luyện phải đặt mình vào tử địa rồi mới có thể hồi sinh đắc được sinh cơ.","nguoiTu":[{"ten":"Nam Cung Uyển","tuChuong":"@c0789","tangDatToi":"Không rõ","trangThai":"đang tu luyện"}],"nguon":["@c0789"],"tabs":{"tienTrinh":[{"chuong":"@c0789","loai":"xuất hiện","importance":"major","giaiDoan":"Nam Cung Uyển liều tu luyện","text":"Hàn Lập phát hiện Nam Cung Uyển đã liều mạng tu luyện Xá Nữ Thiên Nguyệt Quyết — công pháp tử rồi mới sinh trong Luân Hồi Công — khi đang bị Phong Hồn Chú phong ấn trong băng bích.","anchor":"dĩ nhiên dám nương vào sanh tử một đường cơ hội để tu luyện công pháp tối nguy hiểm Xá Nữ Thiên Nguyệt quyết trong Luân Hồi Công này"}]}},{"id":"huyen-mau-hoa-anh-thuat","name":"Huyền mẫu hóa anh thuật","cn":"玄母化婴术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Huyền mẫu hóa anh thuật là một đại thần thông cho phép tu sĩ luyện đệ nhị nguyên anh bằng cách xâm chiếm một linh anh ngoại lai, rót thần thức vào rồi đồng hóa trong cơ thể. Hàn Lập đã chính thức thi triển bí thuật này lên Mộc Linh Anh sau khi nguyên anh ngưng cố.","detail":"Hàn Lập nghiên cứu Huyền mẫu hóa anh thuật từ ngọc giản và bắt đầu tu luyện sau khi nguyên anh ngưng cố. Đây là một đại thần thông vượt xa bí thuật thông thường, cho phép tu sĩ sở hữu đệ nhị nguyên anh thông qua việc xâm chiếm linh anh của sinh vật khác. Quy trình thi triển gồm nhiều bước: trước hết dùng hồn thuật suy yếu thần thức của mục tiêu, sau đó nguyên anh xuất khiếu cưỡng hành xóa sạch linh thức bên trong linh anh, rồi rót một bộ phận thần thức của bản thân vào, cuối cùng thu linh anh đã bị chiếm hữu vào cơ thể để tiến hành đồng hóa. Quá trình đồng hóa kéo dài rất lâu, có thể từ ba đến năm năm, bảy đến tám năm, thậm chí hơn mười năm. Tại @c0790, Hàn Lập chính thức thi triển thuật này lên Mộc Linh Anh, xâm chiếm thần thức, rót thần thức mình vào và thu linh anh vào cơ thể bắt đầu đồ","congNang":["Luyện đệ nhị nguyên anh bằng cách xâm chiếm linh anh ngoại lai, rót thần thức vào rồi đồng hóa trong cơ thể @c0790","Dùng hồn thuật suy yếu thần thức mục tiêu trước khi xâm chiếm @c0790","Nguyên anh xuất khiếu cưỡng hành xóa sạch linh thức bên trong linh anh mục tiêu @c0790"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0790","tangDatToi":"bắt đầu tu luyện, đang đồng hóa","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0790","loai":"thi triển","importance":"major","giaiDoan":"Hàn Lập chính thức thực hành bước đầu","text":"Hàn Lập xâm chiếm thần thức Mộc Linh Anh, rót thần thức mình vào, thu linh anh vào cơ thể bắt đầu đồng hóa tạo đệ nhị nguyên anh.","anchor":"Bí thuật bình thường thật sự không có cách nào có thể so sánh được với loại đại thần thông này"}]},"capNhatToi":"@c0790","nguon":["@c0790"],"dacDiem":"Đại thần thông vượt xa bí thuật thông thường; quá trình đồng hóa linh anh ngoại lai kéo dài từ ba đến năm năm, bảy đến tám năm, thậm chí hơn mười năm."},{"id":"thuan-di-thuat","name":"Thuấn di thuật","cn":"瞬移术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông nguyên anh","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông của nguyên anh cho phép dịch chuyển tức thời, nhưng tiêu hao nguyên khí lớn.","detail":"Nguyên anh Hàn Lập thi triển trong mật thất: biến mất tại một góc, sau một khắc tái hiện trên đỉnh đầu Hàn Lập, nhưng tiêu hao nguyên khí khiến sắc mặt trắng bệch.","congNang":["Dịch chuyển tức thời (tiêu hao nguyên khí lớn)"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0790","tangDatToi":"sơ dụng","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0790","loai":"thi triển","importance":"normal","giaiDoan":"Nguyên anh Hàn Lập sơ dụng","text":"Nguyên anh Hàn Lập thi triển thuấn di thuật trong mật thất, biến mất rồi tái hiện trên đỉnh đầu, nhưng tiêu hao nguyên khí khiến sắc mặt trắng bệch.","anchor":"Đây chính là thần thông của nguyên anh, thuấn di thuật"}]},"capNhatToi":"@c0790","nguon":["@c0790"]},{"id":"thien-tuyet-ma-thi","name":"Thiên Tuyệt Ma Thi","cn":"天绝魔尸","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Đỉnh cao luyện thi","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Thiên Tuyệt Ma Thi là phương pháp luyện thi đỉnh cao ghi chép trong ngọc giản thu được từ hắc bào thanh niên Âm La Tông. Kỹ thuật này yêu cầu thân thể sở hữu thần thông lợi hại, xóa sạch thần thức rồi dùng bí thuật luyện chế, tạo ra ma thi giữ nguyên toàn bộ thần thông và tu vi nguyên bản của thân thể gốc.","detail":"Thiên Tuyệt Ma Thi được Hàn Lập phát hiện trong ngọc giản luyện thi thuật sưu tầm của hắc bào thanh niên Âm La Tông. Đây là phương pháp luyện thi thuật bậc cao, đòi hỏi nguyên liệu là thân thể có sẵn các loại thần thông lợi hại; sau khi xóa sạch thần thức trong thân thể, tu sĩ sử dụng bí thuật chuyên biệt để luyện chế thành ma thi. Thành phẩm ma thi có thể thi triển tất cả thần thông cùng tu vi nguyên bản mà thân thể gốc sở hữu. Thi Tiêu được đánh giá là nguyên liệu tốt nhất cho phương pháp này, tuy nhiên dù dùng nguyên liệu thượng hạng cùng thiên địa linh thi để luyện chế thì tỉ lệ thành công cũng chỉ nắm chắc ba phần, bởi quá trình luyện chế hung ác thập phần. Sau khi nghiên cứu, Hàn Lập quyết định luyện Thi Tiêu theo phương pháp Thiên Tuyệt Ma Thi sau khi xóa nguyên thần của Thi Tiêu.","thuocTinh":"Ma đạo, luyện thi","nguonGoc":"Ngọc giản sưu tầm của hắc bào thanh niên Âm La Tông","yeuCau":"Thân thể có thần thông lợi hại, thiên địa linh thi, xóa thần thức","uyLuc":"Ma thi thành phẩm giữ nguyên toàn bộ thần thông và tu vi nguyên bản của thân thể gốc, có thể thi triển tất cả thần thông mà thân thể sở hữu lúc sinh tiền.","dacDiem":"Tỉ lệ thành công chỉ ba phần dù có nguyên liệu tốt nhất, quá trình luyện chế hung ác thập phần; yêu cầu thân thể phải sở hữu thần thông lợi hại và cần xóa sạch thần thức trước khi luyện chế.","congNang":["Luyện thi thể thành ma thi giữ nguyên toàn bộ thần thông và tu vi nguyên bản của thân thể gốc @c0791"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0791","tangDatToi":"Đang chuẩn bị luyện","trangThai":"dang-hoc"}],"tabs":{"tienTrinh":[{"chuong":"@c0791","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập phát hiện phương pháp trong ngọc giản","text":"Hàn Lập đọc ngọc giản luyện thi thuật thu từ hắc bào thanh niên Âm La Tông, phát hiện phương pháp Thiên Tuyệt Ma Thi và quyết định luyện Thi Tiêu thành Thiên Tuyệt Ma Thi.","anchor":"có khả năng tạo thành Thiên Tuyệt Ma Thi. Loại Ma thi này chắc chắn là rất là lợi hại bởi lẽ nó có thể thi triển tất cả các loại thần thông của nó cùng với nguyên bổn tu vi trước đây"}]},"capNhatToi":"@c0791","nguon":["@c0791"]},{"id":"phuong-phap-luyen-thi-tong-hop","name":"Hơn mười loại phương pháp luyện thi","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Tập hợp hơn mười phương pháp luyện thi do hắc bào thanh niên Âm La Tông sưu tầm, phục chế và cải tiến, ghi trong ngọc giản.","detail":"Hắc bào thanh niên Âm La Tông minh tranh ám đoạt rồi phục chế hơn mười phương pháp luyện thi, kèm chú giải cải tiến có thể tăng uy lực luyện thi thêm ba phần. Ngọc giản chứa các phương pháp này được Hàn Lập thu từ thần thức của hắc bào thanh niên.","nguon":["@c0791"]}]};
